      /**
       * key: challengeId → the CURRENT USER's enrollment for that challenge.
       * Only contains enrollments where memberId === currentUser.
       * Used by the Me tab card to instantly check enrolment status without
       * scanning the full globalChallengeEnrollmentsDB array.
       * @type {Map<string, ChallengeEnrollmentRecord>}
       */
      let myEnrollmentsMap = new Map();

      /**
       * Silently syncs BOOK_COUNT and PAGE_COUNT challenge progress in the
       * background after a page or shelf write succeeds.
       *
       * Called with setTimeout(..., 0) so the main UI update (shelf re-render,
       * feed refresh, toast) completes first — this runs after the browser
       * has painted and the user is already looking at their updated state.
       *
       * For each active BOOK_COUNT / PAGE_COUNT enrollment belonging to the
       * current member: calls syncAndFetchEnrollment(), patches myEnrollmentsMap
       * with the fresh data, then re-renders the challenges card if the Me tab
       * is visible.
       */
      function backgroundSyncChallengeProgress() {
        // Collect only the challenge types that auto-sync from source data.
        // Other types (HABIT_STREAK, BINGO_GRID etc.) are updated explicitly
        // by the member — no background sync needed.
        const syncableTypes = new Set(['BOOK_COUNT', 'PAGE_COUNT']);

        const enrollmentsToSync = Array.from(myEnrollmentsMap.values()).filter(function(e) {
          const challenge = challengesMap.get(e.challengeId);
          return challenge &&
                 syncableTypes.has(challenge.challengeType) &&
                 e.enrollmentStatus === 'Active';
        });

        if (enrollmentsToSync.length === 0) return;

        enrollmentsToSync.forEach(function(enrollment) {
          google.script.run
            .withSuccessHandler(function(res) {
              if (!res || res.status !== 'success' || !res.enrollment) return;

              // Patch local map with fresh server values
              myEnrollmentsMap.set(res.enrollment.challengeId, res.enrollment);

              // Re-render challenges card only if Me tab is currently visible
              if (document.getElementById('meView') &&
                  document.getElementById('meView').style.display === 'block') {
                renderMyChallengesCard();
              }
            })
            .withFailureHandler(function(err) {
              // Fully silent — background sync failure is not user-visible
              console.warn('backgroundSyncChallengeProgress failed for',
                           enrollment.challengeId, ':', err);
            })
            .syncAndFetchEnrollment(enrollment.challengeId);
        });
      }
