      /**
       * Opens the Help Center from the More drawer.
       * navPush snapshots the origin root tab so the back button restores it
       * rather than always falling through to Home.
       */
      function openHelpCenter() {
        // Snapshot origin view + scroll BEFORE switchTab() overwrites currentActiveView
        navPush({});
        toggleDrawer(false);
        switchTab('help');
        resetHelpCenter();
      }

      function resetHelpCenter() {
        document.getElementById('helpSearchInput').value = "";
        document.getElementById('helpCategoryGrid').style.display = "grid";
        document.getElementById('helpResultsArea').style.display = "none";
      }

      function openHelpCategory(categoryName) {
        document.getElementById('helpSearchInput').value = ""; // Clear search
        const results = helpArticlesDB.filter(article => article.category === categoryName);
        renderHelpResults(results, `${categoryName} Guides`, true);
      }

      function handleHelpSearch() {
        const query = document.getElementById('helpSearchInput').value;
        
        // If search is empty, go back to the default grid
        if (query.trim() === "") {
          resetHelpCenter();
          return;
        }

        // Lazy-load the Fuse engine only when they actually type something
        if (!helpFuseIndex) {
          // Strip HTML tags from content before indexing so Fuse matches
          // real text only — not class names, div attributes, or emoji markup.
          const cleanedArticles = helpArticlesDB.map(a => ({
            ...a,
            content: a.content.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim()
          }));
          helpFuseIndex = new Fuse(cleanedArticles, {
            keys: ['title', 'tags', 'content'], // Searches title, tags, and clean text
            threshold: 0.3, // 0.0 = perfect match, 1.0 = matches anything. 0.3 handles typos.
            ignoreLocation: true
          });
        }

        const rawResults = helpFuseIndex.search(query);
        // Fuse returns items inside an 'item' wrapper, extract them:
        const formattedResults = rawResults.map(r => r.item);
        
        renderHelpResults(formattedResults, "Search Results");
      }

      /**
       * Renders a list of help articles into the results area.
       *
       * @param {Array}   articlesArray  - Articles to display (pre-sorted by caller for category views).
       * @param {string}  titleText      - Heading shown above the list.
       * @param {boolean} isCategoryView - When true, applies featured-first and sequence-badge
       *                                   rendering. When false (search results), plain list only.
       */
      function renderHelpResults(articlesArray, titleText, isCategoryView = false) {
        document.getElementById('helpCategoryGrid').style.display = "none";
        document.getElementById('helpResultsArea').style.display = "block";
        document.getElementById('helpResultsTitle').innerText = titleText;

        const listContainer = document.getElementById('helpResultsList');
        listContainer.innerHTML = "";

        if (articlesArray.length === 0) {
          listContainer.innerHTML = `<p style="color: var(--text-muted); font-style: italic;">No articles found. Try different keywords.</p>`;
          return;
        }

        articlesArray.forEach((article, idx) => {
          // ── Featured card: first article in a category view that has order:1 ──
          if (isCategoryView && idx === 0 && article.order === 1) {
            listContainer.innerHTML += `
              <div class="help-featured-card" role="button" tabindex="0" data-action onclick="openHelpArticle('${article.id}')">
                <div style="flex-grow:1;">
                  <div class="help-featured-badge-pill">✨ Start Here</div>
                  <div class="help-featured-title">${article.title}</div>
                  <div class="help-featured-snippet">${article.snippet}</div>
                </div>
                <i class="fa-solid fa-chevron-right" style="color:var(--arka-accent);margin-top:4px;flex-shrink:0;"></i>
              </div>`;
            return;
          }

          // ── Sequence badge: numbered articles in a category view ─────────────
          const seqBadge = (isCategoryView && article.order != null)
            ? `<div class="help-seq-badge">${article.order}</div>`
            : `<i class="fa-solid fa-chevron-right" style="color:var(--text-faint);margin-left:10px;"></i>`;

          const seqChevron = (isCategoryView && article.order != null)
            ? `<i class="fa-solid fa-chevron-right" style="color:var(--text-faint);margin-left:10px;"></i>`
            : '';

          listContainer.innerHTML += `
            <div class="help-result-card" role="button" tabindex="0" data-action onclick="openHelpArticle('${article.id}')">
              <div style="flex-grow:1;">
                <div style="font-size:0.75rem;color:var(--arka-accent);font-weight:bold;text-transform:uppercase;margin-bottom:2px;">${article.category}</div>
                <div style="font-weight:bold;color:var(--text-strong);font-size:1.05rem;margin-bottom:4px;">${article.title}</div>
                <div style="font-size:0.85rem;color:var(--text-muted);line-height:1.3;">${article.snippet}</div>
              </div>
              <i class="fa-solid fa-chevron-right" style="color:var(--text-faint);margin-left:10px;"></i>
            </div>`;
        });
      }

