      // ============================================================================
      // BADGE SYSTEM FRONTEND HELPERS
      // ============================================================================

      /**
       * Resolves a free-text genre string to matched canonical genre names.
       * Mirrors MasterEngine resolveCanonicalGenres_() logic exactly.
       *
       * @param  {string} genreString - Raw comma-separated genre string from a book record.
       * @returns {string[]} Matched canonical genre names (may be empty).
       */
      function resolveCanonicalGenres_(genreString) {
        if (!genreString) return [];
        const matched = new Set();
        genreString.split(',').forEach(function(rawTag) {
          const tag = rawTag.trim().toLowerCase();
          if (!tag) return;
          for (const canonical in GENRE_ALIAS_MAP_FRONTEND) {
            if (GENRE_ALIAS_MAP_FRONTEND[canonical].includes(tag)) matched.add(canonical);
          }
        });
        return Array.from(matched);
      }

      /**
       * Normalises a single free-text genre tag for Genre Collector counting.
       * Mirrors MasterEngine resolveGenreForCollector_() exactly.
       *
       * If the tag matches any alias in GENRE_ALIAS_MAP_FRONTEND it is collapsed
       * to the canonical name. Otherwise the raw tag is kept (lowercased, trimmed)
       * so unrecognised genres like "historical fiction" count as their own slot
       * independently of "fiction".
       *
       * @param  {string} rawTag - A single trimmed genre tag.
       * @returns {string} Normalised genre string.
       */
      function resolveGenreForCollector_(rawTag) {
        const lower = rawTag.toLowerCase();
        for (const canonical in GENRE_ALIAS_MAP_FRONTEND) {
          if (GENRE_ALIAS_MAP_FRONTEND[canonical].includes(lower)) return canonical;
        }
        return lower; // no alias match — treat as its own unique genre
      }

      /**
       * Returns ISO 8601 week string "YYYY-Www" for a given Date.
       * Canonical frontend version — mirrors MasterEngine getISOWeekString_().
       * Uses local date methods (not UTC) so week boundaries match the member's
       * timezone, consistent with getISOWeekNumber() used in the heatmap.
       *
       * @param  {Date} date
       * @returns {string} e.g. "2024-W05"
       */
      function getISOWeekString_(date) {
        const d = new Date(date);
        d.setHours(0, 0, 0, 0);
        d.setDate(d.getDate() + 3 - (d.getDay() + 6) % 7);
        const yearStart = new Date(d.getFullYear(), 0, 4);
        const weekNum   = 1 + Math.round(
          ((d - yearStart) / 86400000 - 3 + (yearStart.getDay() + 6) % 7) / 7
        );
        return d.getFullYear() + '-W' + String(weekNum).padStart(2, '0');
      }

      /**
       * Converts an ISO week string to an integer epoch-week count.
       * Two ISO weeks are consecutive iff their values differ by exactly 1.
       *
       * @param  {string} isoWeekStr - e.g. "2024-W05"
       * @returns {number}
       */
      function isoWeekToEpochWeeks_(isoWeekStr) {
        const parts = isoWeekStr.split('-W');
        if (parts.length !== 2) return -1;
        const year    = parseInt(parts[0], 10);
        const weekNum = parseInt(parts[1], 10);
        const jan4      = new Date(year, 0, 4);
        const dayOfWeek = jan4.getDay() || 7;
        const week1Mon  = new Date(jan4.getTime() - (dayOfWeek - 1) * 86400000);
        const targetMon = new Date(week1Mon.getTime() + (weekNum - 1) * 7 * 86400000);
        return Math.floor(targetMon.getTime() / (7 * 86400000));
      }

      /**
       * Computes the all-time best consecutive ISO-week reading streak from page logs.
       * Canonical frontend version — mirrors MasterEngine computeAllTimeBestStreak_().
       * Uses parseGoogleDate() for Arka Z-Format compatibility.
       *
       * @param  {Array<{timestamp: string, pagesDelta: number}>} pageLogs
       * @returns {number} Best streak in weeks (0 if no valid logs).
       */
      function computeAllTimeBestStreak_(pageLogs) {
        const weekSet = {};
        pageLogs.forEach(function(log) {
          if ((Number(log.pagesDelta) || 0) > 0) {
            const d = parseGoogleDate(log.timestamp);
            if (!isNaN(d.getTime())) weekSet[getISOWeekString_(d)] = true;
          }
        });
        const weeks = Object.keys(weekSet).sort(function(a, b) {
          return isoWeekToEpochWeeks_(a) - isoWeekToEpochWeeks_(b);
        });
        if (!weeks.length) return 0;
        let best = 1, cur = 1;
        for (let i = 1; i < weeks.length; i++) {
          const diff = isoWeekToEpochWeeks_(weeks[i]) - isoWeekToEpochWeeks_(weeks[i - 1]);
          cur = diff === 1 ? cur + 1 : 1;
          if (cur > best) best = cur;
        }
        return best;
      }

      /**
       * Computes total unique ISO weeks with at least one positive page log.
       * Canonical frontend version — mirrors MasterEngine computeUniqueWeeksLogged_().
       * Uses parseGoogleDate() for Arka Z-Format compatibility.
       *
       * @param  {Array<{timestamp: string, pagesDelta: number}>} pageLogs
       * @returns {number}
       */
      function computeUniqueWeeksLogged_(pageLogs) {
        const weekSet = {};
        pageLogs.forEach(function(log) {
          if ((Number(log.pagesDelta) || 0) > 0) {
            const d = parseGoogleDate(log.timestamp);
            if (!isNaN(d.getTime())) weekSet[getISOWeekString_(d)] = true;
          }
        });
        return Object.keys(weekSet).length;
      }

      /**
       * Computes the member's current active reading streak in ISO weeks.
       * Canonical frontend companion to computeAllTimeBestStreak_().
       *
       * Algorithm: collect all ISO weeks with at least one positive page log,
       * sort them, then walk backwards from the most recent to count the
       * longest unbroken consecutive tail.
       *
       * Grace period: if the most recent logged week is exactly one week
       * behind the current calendar week, the streak is still considered live
       * (the member may simply not have logged yet this week). A gap of two
       * or more weeks always breaks the streak.
       *
       * @param  {Array<{timestamp: string, pagesDelta: number}>} pageLogs
       * @returns {number} Current streak in weeks (0 if none active).
       */
      function computeCurrentStreak_(pageLogs) {
        const weekSet = {};
        pageLogs.forEach(function(log) {
          if ((Number(log.pagesDelta) || 0) > 0) {
            const d = parseGoogleDate(log.timestamp);
            if (!isNaN(d.getTime())) weekSet[getISOWeekString_(d)] = true;
          }
        });

        const weeks = Object.keys(weekSet).sort(function(a, b) {
          return isoWeekToEpochWeeks_(a) - isoWeekToEpochWeeks_(b);
        });
        if (!weeks.length) return 0;

        // Grace period: streak is live if the last logged week is this week
        // OR last week (member may be mid-week and not yet logged).
        const currentWeekEpoch    = isoWeekToEpochWeeks_(getISOWeekString_(new Date()));
        const lastLoggedWeekEpoch = isoWeekToEpochWeeks_(weeks[weeks.length - 1]);
        if (currentWeekEpoch - lastLoggedWeekEpoch > 1) return 0;

        // Walk backwards from the most recent logged week, counting consecutive weeks.
        let streak = 1;
        for (let i = weeks.length - 2; i >= 0; i--) {
          const gapWeeks = isoWeekToEpochWeeks_(weeks[i + 1]) - isoWeekToEpochWeeks_(weeks[i]);
          if (gapWeeks === 1) {
            streak++;
          } else {
            break;
          }
        }
        return streak;
      }

      /**
       * Computes all badge progress metrics for the current user from in-memory data.
       * Called once per renderBadgeGallery() invocation; results drive progress bars.
       *
       * @returns {{
       *   pageCount: number, bookCount: number, reviewCount: number,
       *   eventsCount: number, libraryCount: number, fatReadMax: number,
       *   genreCounts: Object<string,number>, uniqueGenreCount: number,
       *   bestStreak: number, currentStreak: number, totalWeeks: number, yearsAsMember: number
       * }}
       */
      function computeMyBadgeProgress_() {
        const me      = membersMap.get(currentUser);
        const myLogs  = globalMyPageLogDB.filter(l => l.memberId === currentUser);
        const myShelf = globalShelvesDB.filter(
          s => s.memberId === currentUser && s.status === 'Finished'
        );

        // Pages and books maintained by MasterEngine in MemberDB Cols P and Q.
        // Frontend member object uses fields `pages` (Col P) and `books` (Col Q)
        // as set by buildMembersList_() — not totalPages/totalBooks.
        const pageCount = me ? (Number(me.pages) || 0) : 0;
        const bookCount = me ? (Number(me.books) || 0) : 0;

        // Reviews: count shelf records with non-empty review text.
        // Source of truth is MemberShelfDB Col F (review field). Deleted rows are
        // already excluded from globalShelvesDB by Wave 3 filtering. No status
        // restriction — Finished and DNF reviews both count, matching Rankings logic.
        const reviewCount = globalShelvesDB.filter(function(s) {
          return s.memberId === currentUser && (s.review || '').trim() !== '';
        }).length;

        // Events attended: ActivityLogDB remains the source (no equivalent shelf field).
        let eventsCount = 0;
        globalActivityLogDB.forEach(function(a) {
          if (a.activityMemberID !== currentUser) return;
          if (a.activityTypeID === 'ARKA_ACTTYP_EVENTATTENDED') eventsCount++;
        });

        // Library additions: books where this member is the original adder (Col F in LibraryDB)
        const libraryCount = globalBooksDB.filter(b => b.addedByRaw === currentUser).length;

        // Fat Read: largest page count of any single finished book for this member
        let fatReadMax = 0;
        myShelf.forEach(function(s) {
          const book = booksMap.get(s.bookId);
          if (book && (Number(book.pages) || 0) > fatReadMax) fatReadMax = Number(book.pages);
        });

        // Genre Explorer counts — canonical genres only, used for Explorer progress bars
        const genreCounts = {};

        // Genre Collector set — all normalised genre strings (synonym-collapsed,
        // but historically distinct genres like "historical fiction" kept separate)
        const collectorGenreSet = {};

        myShelf.forEach(function(s) {
          const book = booksMap.get(s.bookId);
          if (!book || !book.genre) return;

          // Explorer: canonical matches only
          resolveCanonicalGenres_(book.genre).forEach(function(g) {
            genreCounts[g] = (genreCounts[g] || 0) + 1;
          });

          // Collector: every raw tag, case-insensitive dedup (no synonym collapsing)
          book.genre.split(',').forEach(function(rawTag) {
            const trimmed = rawTag.trim().toLowerCase();
            if (!trimmed) return;
            collectorGenreSet[trimmed] = true;
          });
        });

        const uniqueGenreCount = Object.keys(collectorGenreSet).length;

        // Streak metrics: computed from page log timestamps via ISO week logic.
        // bestStreak   → all-time best consecutive weeks; drives badge tier awards.
        // currentStreak → live active streak; drives progress bar display so it
        //                 resets to zero when a streak is broken (see buildReplacingSeriesHtml_).
        const bestStreak    = computeAllTimeBestStreak_(myLogs);
        const currentStreak = computeCurrentStreak_(myLogs);
        const totalWeeks    = computeUniqueWeeksLogged_(myLogs);

        // Anniversary: years elapsed since JoinDate (Col E in MemberDB, dd-MMM-yyyy format)
        const joinDate      = me && me.joinDate ? parseGoogleDate(me.joinDate) : null;
        const yearsAsMember = joinDate && !isNaN(joinDate.getTime())
          ? (Date.now() - joinDate.getTime()) / (1000 * 60 * 60 * 24 * 365.25)
          : 0;

        return {
          pageCount, bookCount, reviewCount, eventsCount, libraryCount,
          fatReadMax, genreCounts, uniqueGenreCount, bestStreak, currentStreak, totalWeeks, yearsAsMember
        };
      }

      /**
       * Normalises a GENRE_EXPLORER badge meta string (the genre name in BadgeDB)
       * to its canonical form from CANONICAL_GENRE_LIST, case-insensitively.
       * Ensures 'romance', 'Romance', 'lgbtq+', and 'LGBTQ+' all map to the
       * same canonical key used as keys in genreCounts and CANONICAL_GENRE_LIST.
       * Falls back to rawMeta unchanged if no canonical match is found.
       *
       * Mirrors normaliseGenreMeta_() in MasterEngine — both must stay in sync.
       *
       * @param  {string} rawMeta - Raw badgeMeta value from BadgeDB
       * @returns {string} Canonical genre name, or rawMeta unchanged
       */
      function normaliseGenreMeta_(rawMeta) {
        const lower = (rawMeta || '').trim().toLowerCase();
        return CANONICAL_GENRE_LIST.find(function(g) {
          return g.toLowerCase() === lower;
        }) || rawMeta;
      }

      /**
       * Groups globalBadgesDB into a nested structure for gallery rendering.
       * Non-GENRE_EXPLORER: { [category]: [badge...] } sorted by badgeTier asc.
       * GENRE_EXPLORER:     { GENRE_EXPLORER: { [genre]: [badge...] } } sorted by badgeTier asc.
       *
       * @returns {Object}
       */
      function buildBadgesByCategory_() {
        const map = {};
        globalBadgesDB.forEach(function(badge) {
          const cat  = badge.badgeCategory || 'SPECIAL';
          const meta = badge.badgeMeta     || '';
          if (cat === 'GENRE_EXPLORER') {
            // Normalise the genre key case-insensitively so 'romance' and 'Romance'
            // both produce the same bucket, matching CANONICAL_GENRE_LIST keys.
            const normMeta = normaliseGenreMeta_(meta);
            if (!map['GENRE_EXPLORER'])              map['GENRE_EXPLORER'] = {};
            if (!map['GENRE_EXPLORER'][normMeta])    map['GENRE_EXPLORER'][normMeta] = [];
            map['GENRE_EXPLORER'][normMeta].push(badge);
          } else {
            if (!map[cat]) map[cat] = [];
            map[cat].push(badge);
          }
        });
        // Sort every array by tier ascending
        Object.keys(map).forEach(function(cat) {
          if (cat === 'GENRE_EXPLORER') {
            Object.keys(map['GENRE_EXPLORER']).forEach(function(genre) {
              map['GENRE_EXPLORER'][genre].sort((a, b) => (a.badgeTier || 0) - (b.badgeTier || 0));
            });
          } else {
            map[cat].sort((a, b) => (a.badgeTier || 0) - (b.badgeTier || 0));
          }
        });
        return map;
      }

      /**
       * Returns a filtered, ordered badge list for compact strip display.
       *
       * Replacing categories: only the highest tier earned per group is included.
       * GENRE_EXPLORER groups by genre (one badge per genre max).
       * Non-replacing (YEARLY, SPECIAL): all earned badges included.
       * Results are ordered by BADGE_CATEGORY_DISPLAY sequence, highest tier first.
       *
       * @param   {string} memberId
       * @returns {Array<{badge: Object, award: Object}>}
       */
      function getEffectiveStripBadges_(memberId) {
        const awards           = memberBadgeIndex.get(memberId) || [];
        const highestByGroup   = {}; // { groupKey: { tier, badge, award } }
        const nonReplacingItems = [];

        awards.forEach(function(award) {
          const badge = badgesMap.get(award.badgeId);
          if (!badge) return;
          const cat = badge.badgeCategory || 'SPECIAL';
          if (BADGE_REPLACING_CATEGORIES.has(cat)) {
            // GENRE_EXPLORER: one slot per genre; all others: one slot per category
            // Normalise so 'romance' and 'Romance' deduplicate to the same strip slot.
            const groupKey = cat === 'GENRE_EXPLORER'
              ? 'GENRE_EXPLORER_' + normaliseGenreMeta_(badge.badgeMeta || '')
              : cat;
            const tier = badge.badgeTier || 0;
            if (!highestByGroup[groupKey] || tier > highestByGroup[groupKey].tier) {
              highestByGroup[groupKey] = { tier, badge, award };
            }
          } else {
            nonReplacingItems.push({ badge, award });
          }
        });

        const result = nonReplacingItems.concat(
          Object.values(highestByGroup).map(e => ({ badge: e.badge, award: e.award }))
        );

        // Sort by display category order, then by tier descending (best tier first per category)
        const catOrder = BADGE_CATEGORY_DISPLAY.map(c => c.category);
        result.sort(function(a, b) {
          const oA = catOrder.indexOf(a.badge.badgeCategory || 'SPECIAL');
          const oB = catOrder.indexOf(b.badge.badgeCategory || 'SPECIAL');
          if (oA !== oB) return oA - oB;
          return (b.badge.badgeTier || 0) - (a.badge.badgeTier || 0);
        });
        return result;
      }

      /**
       * Collapses or expands a gallery section body div.
       * Called by onclick on every section header.
       *
       * @param {string} sectionId - The element ID of the section body div
       */
      function toggleGallerySectionBody_(sectionId) {
        const body  = document.getElementById(sectionId);
        const arrow = document.getElementById(sectionId + '-arrow');
        if (!body) return;
        const isOpen = body.style.display !== 'none';
        body.style.display = isOpen ? 'none' : 'block';
        if (arrow) arrow.textContent = isOpen ? '▶' : '▼';
      }

      /**
       * Builds a filled progress bar and current/next counter display.
       *
       * @param {number} current     - Current metric value
       * @param {number} next        - Target threshold value
       * @param {string} accentColor - CSS colour for the progress fill
       * @returns {string} HTML
       */
      function buildProgressBarHtml_(current, next, accentColor) {
        const pct     = next > 0 ? Math.min(100, Math.round((current / next) * 100)) : 0;
        const dispCur = (current % 1 !== 0)
          ? current.toFixed(1)
          : Math.floor(current).toLocaleString();
        const dispNext = Number(next).toLocaleString();
        return `
          <div style="margin-top:5px;">
            <div style="background:var(--border-soft);border-radius:4px;height:5px;overflow:hidden;">
              <div style="width:${pct}%;background:var(--color-gamification);height:100%;border-radius:4px;
                          transition:width 0.4s ease;"></div>
            </div>
            <div style="font-size:0.66rem;color:var(--text-faint);margin-top:2px;">
              ${dispCur} / ${dispNext}
            </div>
          </div>`;
      }

      /**
       * Builds an inline badge image element (circle) for gallery use.
       * Always attaches openBadgeDetailSheet onclick — on both the img tag
       * and the emoji fallback div shown when no image URL exists or image fails.
       *
       * @param {Object}  badge    - Badge object from badgesMap
       * @param {boolean} isLocked - True = dim + dashed border (not yet earned)
       * @param {number}  sizePx   - Diameter in pixels
       * @param {string}  accent   - Border colour when earned
       * @returns {string} HTML
       */
      function buildGalleryBadgeImgHtml_(badge, isLocked, sizePx, accent) {
        const border   = isLocked ? '2px dashed var(--neutral-mid)' : `3px solid ${accent}`;
        const opacity  = isLocked ? '0.38' : '1';
        const imgSrc   = badge.imgUrl ? badge.imgUrl.replace('sz=w400', 'sz=w120') : '';
        const clickAttr = `onclick="openBadgeDetailSheet('${badge.id}')"`;
        const baseStyle = `width:${sizePx}px;height:${sizePx}px;border-radius:50%;
            border:${border};opacity:${opacity};cursor:pointer;flex-shrink:0;`;

        // Fallback emoji circle — always has onclick so tapping works even when image absent
        const fallback = `<div style="${baseStyle}background:#f0e8f5;
            display:none;align-items:center;justify-content:center;
            font-size:${Math.floor(sizePx * 0.4)}px;"
            ${clickAttr}>🏅</div>`;

        if (!imgSrc) {
          // No image URL at all — show emoji circle immediately with onclick
          return `<div style="${baseStyle}background:#f0e8f5;display:flex;
              align-items:center;justify-content:center;
              font-size:${Math.floor(sizePx * 0.4)}px;"
              ${clickAttr}>🏅</div>`;
        }

        // Image URL present — try to load it; fall back to emoji on error
        return `<img src="${imgSrc}"
            style="${baseStyle}background:#f0e8f5;object-fit:cover;display:block;"
            ${clickAttr}
            onerror="this.style.display='none';this.nextElementSibling.style.display='flex';">
          ${fallback}`;
      }

      /**
       * Builds a full badge collection card for a standard replacing series.
       *
       * Returns a complete self-contained card div containing:
       *   - Left accent border using the category colour
       *   - Badge image (72 px, tappable → openBadgeDetailSheet)
       *   - Tier label · caption pill · category name · earned date
       *   - Progress bar (unified Arka amber — all categories use one bar colour)
       *   - "Next: X AP 🔓" label on the right of the bar
       *   - Dot-trail journey band on the right edge (journey-supported categories only)
       *
       * Category accent colours appear only on: left border, tier pill background,
       * and band dots/button — never on the progress bar itself.
       *
       * Called only when catEarned > 0 (renderBadgeGallery handles the 0-earned
       * case via buildUnstartedHint_ + compact row).
       *
       * @param {string}   category       - Badge category key (e.g. 'PAGE_MILESTONE')
       * @param {Object[]} badgesInSeries - All badges in this series, sorted by tier asc
       * @param {Set}      earnedBadgeIds - Set of badge IDs currently held (Active)
       * @param {Object}   progress       - Output of computeMyBadgeProgress_()
       * @param {string}   accentColor    - Category accent colour
       * @returns {string} HTML string — a complete card div
       */
      function buildReplacingSeriesHtml_(category, badgesInSeries, earnedBadgeIds, progress, accentColor) {
        if (!badgesInSeries || !badgesInSeries.length) {
          return `<p style="font-size:0.83rem;color:var(--text-faint);font-style:italic;
                    margin-bottom:10px;">No badges defined for this category yet.</p>`;
        }

        // Per-category band colours drawn from the design-system ramps.
        // bg = band background (50-level tint), dot = trail dots (200-level),
        // bdr = separator border (100-level), btn = circle arrow fill (600-level).
        const BAND_PALETTE = {
          PAGE_MILESTONE   : { bg: '#EEEDFE', dot: '#AFA9EC', bdr: '#CECBF6', btn: 'var(--color-challenge)' },
          BOOK_MILESTONE   : { bg: '#E1F5EE', dot: '#5DCAA5', bdr: '#9FE1CB', btn: '#0F6E56' },
          STREAK_MILESTONE : { bg: '#FAEEDA', dot: '#FAC775', bdr: '#FAC775', btn: '#BA7517' },
          PLOGGER          : { bg: '#EEEDFE', dot: '#AFA9EC', bdr: '#CECBF6', btn: 'var(--color-challenge)' },
          REVIEW_MILESTONE : { bg: '#FAECE7', dot: '#F0997B', bdr: '#F5C4B3', btn: '#993C1D' },
          FAT_READ         : { bg: '#F1EFE8', dot: '#B4B2A9', bdr: '#D3D1C7', btn: '#5F5E5A' },
          GENRE_COLLECTOR  : { bg: '#EEEDFE', dot: '#AFA9EC', bdr: '#CECBF6', btn: 'var(--color-challenge)' },
          ANNIVERSARY      : { bg: '#FAEEDA', dot: '#FAC775', bdr: '#FAC775', btn: '#BA7517' },
          SOCIAL_BUTTERFLY : { bg: '#E1F5EE', dot: '#5DCAA5', bdr: '#9FE1CB', btn: '#0F6E56' },
          LIBRARIAN        : { bg: '#EEEDFE', dot: '#AFA9EC', bdr: '#CECBF6', btn: 'var(--color-challenge)' },
        };

        const JOURNEY_SUPPORTED = ['PAGE_MILESTONE','BOOK_MILESTONE','STREAK_MILESTONE',
          'PLOGGER','REVIEW_MILESTONE','FAT_READ','GENRE_COLLECTOR',
          'ANNIVERSARY','SOCIAL_BUTTERFLY','LIBRARIAN'];

        const band            = BAND_PALETTE[category] || BAND_PALETTE['PAGE_MILESTONE'];
        const showJourneyBand = JOURNEY_SUPPORTED.includes(category);

        // Find highest earned tier and next tier in the replacing series
        let currentBadge = null, nextBadge = null;
        for (let i = badgesInSeries.length - 1; i >= 0; i--) {
          if (earnedBadgeIds.has(badgesInSeries[i].id)) {
            currentBadge = badgesInSeries[i];
            nextBadge    = badgesInSeries[i + 1] || null;
            break;
          }
        }
        if (!currentBadge) nextBadge = badgesInSeries[0]; // fallback: not yet started

        const thresholds = BADGE_THRESHOLDS_FRONTEND[category] || [];
        const conf       = BADGE_CATEGORY_DISPLAY.find(function(c) { return c.category === category; }) || {};
        const metricKey  = conf.metricKey;
        const rawMetric  = metricKey ? (progress[metricKey] || 0) : 0;
        // STREAK_MILESTONE uses currentStreak so the bar resets when the streak breaks
        const barMetric  = (category === 'STREAK_MILESTONE')
          ? (progress.currentStreak || 0)
          : rawMetric;

        // ── Dot-trail journey band ───────────────────────────────────────────
        const journeyBandHtml = showJourneyBand ? `
          <div style="width:34px;background:${band.bg};display:flex;flex-direction:column;
                      align-items:center;justify-content:center;cursor:pointer;flex-shrink:0;
                      border-left:0.5px solid ${band.bdr};gap:3px;"
               onclick="openBadgeJourneyView_('${category}')">
            <div style="width:4px;height:4px;border-radius:50%;background:${band.dot};"></div>
            <div style="width:4px;height:4px;border-radius:50%;background:${band.dot};"></div>
            <div style="width:4px;height:4px;border-radius:50%;background:${band.dot};"></div>
            <div style="margin:3px 0;width:22px;height:22px;border-radius:50%;
                        background:${band.btn};display:flex;align-items:center;
                        justify-content:center;">
              <i class="fa-solid fa-chevron-right" style="font-size:9px;color:white;"
                aria-hidden="true"></i>
            </div>
            <div style="width:4px;height:4px;border-radius:50%;background:${band.dot};"></div>
            <div style="width:4px;height:4px;border-radius:50%;background:${band.dot};"></div>
            <div style="width:4px;height:4px;border-radius:50%;background:${band.dot};"></div>
          </div>` : '';

        // ── Info column content ──────────────────────────────────────────────
        let contentHtml = '';

        if (currentBadge) {
          // User holds at least one tier in this series
          const earnedAward = (memberBadgeIndex.get(currentUser) || [])
            .find(function(a) { return a.badgeId === currentBadge.id; });
          const earnedDate = earnedAward ? earnedAward.awardedDate : '';
          const tierLabel  = currentBadge.badgeTier ? 'Tier ' + currentBadge.badgeTier : '';

          contentHtml = `
            <div style="display:flex;align-items:center;gap:5px;margin-bottom:2px;">
              <span style="font-size:0.58rem;font-weight:700;color:${accentColor};
                           text-transform:uppercase;letter-spacing:0.3px;">
                ${tierLabel} &middot; Now
              </span>
              <span style="font-size:0.56rem;background:${band.bg};color:${band.btn};
                           border-radius:10px;padding:1px 6px;font-weight:700;">
                ${escapeHtml(currentBadge.caption)}
              </span>
            </div>
            <div style="font-size:0.87rem;font-weight:700;color:var(--text-strong);
                        margin-bottom:1px;cursor:pointer;"
                 onclick="openBadgeDetailSheet('${currentBadge.id}')">
              ${escapeHtml(conf.label || category)}
            </div>
            <div style="font-size:0.61rem;color:var(--text-muted);margin-bottom:6px;">
              ${earnedDate ? 'Earned ' + earnedDate : '&nbsp;'}
            </div>`;

          if (nextBadge) {
            const nextTierIdx   = (nextBadge.badgeTier || 1) - 1;
            const nextThreshold = thresholds[nextTierIdx] || 0;
            const cappedMetric  = Math.min(barMetric, nextThreshold);
            const pct           = nextThreshold > 0
              ? Math.min(100, Math.round((cappedMetric / nextThreshold) * 100)) : 0;
            const apOnUnlock    = nextBadge.badgePoints || 0;
            const metricUnit    = conf.unit ? ' ' + conf.unit : '';

            contentHtml += `
              <div>
                <div style="margin-bottom:3px;">
                  <div style="font-size:0.59rem;color:var(--text-muted);margin-bottom:1px;">
                    Next: ${escapeHtml(nextBadge.caption)}
                  </div>
                  <div style="font-size:0.59rem;color:#BA7517;font-weight:700;">
                    ${cappedMetric.toLocaleString()} / ${nextThreshold.toLocaleString()}${metricUnit}
                    ${apOnUnlock
                      ? ' &middot; ' + apOnUnlock.toLocaleString()
                        + ' AP <i class="ti ti-lock-open" style="font-size:9px;" aria-hidden="true"></i>'
                      : ''}
                  </div>
                </div>
                <div style="height:6px;background:var(--border-soft);border-radius:3px;
                            overflow:hidden;">
                  <div style="width:${pct}%;height:100%;background:var(--color-gamification);border-radius:3px;
                              transition:width 0.4s ease;"></div>
                </div>
              </div>`;
          } else {
            // Maximum tier reached in this series
            contentHtml += `
              <div style="font-size:0.68rem;color:#27ae60;font-weight:600;">
                &#127942; Maximum tier reached!
              </div>`;
          }

        } else if (nextBadge) {
          // Not yet started — show greyed Tier 1 with progress toward it
          const firstThreshold = thresholds[0] || 0;
          const cappedMetric   = Math.min(barMetric, firstThreshold);
          const pct            = firstThreshold > 0
            ? Math.min(100, Math.round((cappedMetric / firstThreshold) * 100)) : 0;
          const apOnUnlock     = nextBadge.badgePoints || 0;
          const metricUnit     = conf.unit ? ' ' + conf.unit : '';

          contentHtml = `
            <div style="font-size:0.6rem;font-weight:700;color:var(--text-faint);
                        text-transform:uppercase;letter-spacing:0.3px;margin-bottom:2px;">
              Not yet started
            </div>
            <div style="font-size:0.87rem;font-weight:700;color:var(--text-faint);
                        margin-bottom:2px;">
              ${escapeHtml(conf.label || category)}
            </div>
            <div style="font-size:0.78rem;color:var(--text-faint);margin-bottom:6px;
                        line-height:1.35;">
              ${escapeHtml(nextBadge.description || '')}
            </div>
            ${firstThreshold ? `
              <div>
                <div style="margin-bottom:3px;">
                  <div style="font-size:0.59rem;color:var(--text-faint);margin-bottom:1px;">
                    First badge: ${escapeHtml(nextBadge.caption)}
                  </div>
                  <div style="font-size:0.59rem;color:#BA7517;font-weight:700;">
                    ${cappedMetric.toLocaleString()} / ${firstThreshold.toLocaleString()}${metricUnit}
                    ${apOnUnlock
                      ? ' &middot; ' + apOnUnlock.toLocaleString()
                        + ' AP <i class="ti ti-lock-open" style="font-size:9px;" aria-hidden="true"></i>'
                      : ''}
                  </div>
                </div>
                <div style="height:6px;background:var(--border-soft);border-radius:3px;
                            overflow:hidden;">
                  <div style="width:${pct}%;height:100%;background:var(--color-gamification);border-radius:3px;
                              transition:width 0.4s ease;"></div>
                </div>
              </div>` : ''}`;
        }

        // Badge image (72 px) — greyed when not yet earned
        const displayBadge = currentBadge || nextBadge;
        const badgeImgHtml = displayBadge
          ? buildGalleryBadgeImgHtml_(displayBadge, !currentBadge, 72, accentColor)
          : '';

        // ── Assemble full card ───────────────────────────────────────────────
        return `
          <div style="border:1px solid var(--border-soft);border-radius:10px;
                      margin-bottom:9px;overflow:hidden;display:flex;background:white;">
            <div style="border-left:3px solid ${accentColor};flex:1;display:flex;
                        align-items:center;gap:10px;padding:11px 8px 11px 11px;">
              <div style="flex-shrink:0;">${badgeImgHtml}</div>
              <div style="flex:1;min-width:0;">${contentHtml}</div>
            </div>
            ${journeyBandHtml}
          </div>`;
      }

      /**
       * Builds a card wrapper for the YEARLY and SPECIAL badge sections.
       * These categories have their own section-body builders (buildYearlySectionHtml_,
       * buildSpecialSectionHtml_) and don't use the replacing-series layout or
       * journey band — they just need a consistent card shell.
       *
       * @param {string} label    - Display label (e.g. 'Annual Awards')
       * @param {string} icon     - Emoji icon character
       * @param {string} accent   - Category accent colour for the left border
       * @param {string} bodyHtml - Pre-built inner HTML from the section builder
       * @returns {string} HTML
       */
      function buildNamedSectionCardHtml_(label, icon, accent, bodyHtml) {
        return `
          <div style="border:1px solid var(--border-soft);border-radius:10px;
                      margin-bottom:9px;overflow:hidden;background:white;">
            <div style="border-left:3px solid ${accent};padding:12px 14px;">
              <div style="display:flex;align-items:center;gap:6px;margin-bottom:10px;">
                <span style="font-size:1rem;">${icon}</span>
                <span style="font-size:0.88rem;font-weight:700;color:var(--text-strong);">
                  ${label}
                </span>
              </div>
              ${bodyHtml}
            </div>
          </div>`;
      }

      /**
       * Builds a card for the Genre Explorer category.
       * Wraps the existing buildGenreExplorerSectionHtml_() rows with a header
       * showing the earned badge count pill.
       *
       * @param {Object} geByGenre    - { [genre]: [badge...] } from buildBadgesByCategory_()
       * @param {Set}    earnedBadgeIds
       * @param {Object} genreCounts  - { [genre]: finishedBookCount }
       * @param {number} catEarned    - Total earned badge count for earned pill
       * @returns {string} HTML
       */
      function buildGenreExplorerCardHtml_(geByGenre, earnedBadgeIds, genreCounts, catEarned) {
        const accent   = '#00897b';
        const bodyHtml = buildGenreExplorerSectionHtml_(geByGenre, earnedBadgeIds, genreCounts);
        return `
          <div style="border:1px solid var(--border-soft);border-radius:10px;
                      margin-bottom:9px;overflow:hidden;background:white;">
            <div style="border-left:3px solid ${accent};padding:12px 14px;">
              <div style="display:flex;align-items:center;gap:6px;margin-bottom:10px;">
                <span style="font-size:1rem;">🗺️</span>
                <span style="font-size:0.88rem;font-weight:700;color:var(--text-strong);">
                  Genre Explorer
                </span>
                <span style="font-size:0.6rem;font-weight:700;color:white;
                             background:${accent};border-radius:10px;padding:2px 7px;">
                  ${catEarned}
                </span>
              </div>
              ${bodyHtml}
            </div>
          </div>`;
      }

      /**
       * Returns the unlock-hint string for an unstarted badge category.
       * Shown as a subtitle in the compact "Not yet started" rows.
       *
       * @param  {string} category - Badge category key
       * @returns {string} Human-readable hint, or empty string if none defined
       */
      function buildUnstartedHint_(category) {
        const HINTS = {
          PAGE_MILESTONE   : 'Read 1,000 pages to begin',
          BOOK_MILESTONE   : 'Finish 10 books to begin',
          STREAK_MILESTONE : 'Log 10 consecutive weeks to begin',
          PLOGGER          : 'Log reading for 10 weeks to begin',
          REVIEW_MILESTONE : 'Write 10 reviews to begin',
          FAT_READ         : 'Finish a 400+ page book to begin',
          GENRE_COLLECTOR  : 'Read across 10 genres to begin',
          ANNIVERSARY      : 'Complete your first year to begin',
          SOCIAL_BUTTERFLY : 'Attend 3 club events to begin',
          LIBRARIAN        : 'Add 5 books to the library to begin',
          YEARLY           : 'Annual awards — watch this space',
          SPECIAL          : 'Rare awards granted by the club',
          ONBOARDING       : 'Complete onboarding chapters to earn these',
        };
        return HINTS[category] || '';
      }

      /**
       * Builds the Genre Explorer section body, split into three visual zones:
       *
       *   Earned      — 4-column badge grid; each circle taps to the genre journey.
       *   In progress — compact rows with genre name, amber progress bar, X/Y count.
       *                 Only genres where the member has read ≥1 book but holds no badge.
       *   Discover    — genre name chips for genres with 0 books read, capped at 8
       *                 visible with a "+N more" overflow chip. Keeps aspiration alive
       *                 without drowning earned content.
       *
       * All progress bars use unified amber (var(--color-gamification)) regardless of category.
       *
       * @param {Object} geByGenre    - { [genre]: [badge...] } from buildBadgesByCategory_()
       * @param {Set}    earnedBadgeIds
       * @param {Object} genreCounts  - { [genre]: finishedBookCount }
       * @returns {string} HTML
       */
      function buildGenreExplorerSectionHtml_(geByGenre, earnedBadgeIds, genreCounts) {
        const accentColor = '#00897b';
        const thresholds  = BADGE_THRESHOLDS_FRONTEND.GENRE_EXPLORER;

        // Partition all canonical genres into three buckets
        const earnedGenres     = [];
        const inProgressGenres = [];
        const discoverGenres   = [];

        CANONICAL_GENRE_LIST.forEach(function(genre) {
          const badgesForGenre = (geByGenre && geByGenre[genre]) ? geByGenre[genre] : [];
          const count          = genreCounts[genre] || 0;

          // Resolve highest earned tier and next target tier
          let currentBadge = null, nextBadge = null;
          for (let i = badgesForGenre.length - 1; i >= 0; i--) {
            if (earnedBadgeIds.has(badgesForGenre[i].id)) {
              currentBadge = badgesForGenre[i];
              nextBadge    = badgesForGenre[i + 1] || null;
              break;
            }
          }
          if (!currentBadge && badgesForGenre.length) {
            for (let i = 0; i < badgesForGenre.length; i++) {
              const tierThresh = thresholds[(badgesForGenre[i].badgeTier || 1) - 1] || 0;
              if (count < tierThresh) { nextBadge = badgesForGenre[i]; break; }
            }
            if (!nextBadge) nextBadge = badgesForGenre[badgesForGenre.length - 1];
          }

          const maxReached    = !!(currentBadge && !nextBadge);
          const nextThreshold = nextBadge ? (thresholds[(nextBadge.badgeTier || 1) - 1] || 0) : 0;
          // Absolute progress % — matches what the journey card shows
          const pct = maxReached ? 100
            : (nextThreshold > 0 ? Math.min(100, Math.round((count / nextThreshold) * 100)) : 0);

          if (currentBadge) {
            earnedGenres.push({ genre, currentBadge, nextBadge, maxReached, count, nextThreshold, pct });
          } else if (count > 0 && badgesForGenre.length) {
            inProgressGenres.push({ genre, nextBadge, count, nextThreshold, pct });
          } else if (badgesForGenre.length) {
            discoverGenres.push({ genre });
          }
        });

        if (!earnedGenres.length && !inProgressGenres.length && !discoverGenres.length) {
          return '<p style="font-size:0.83rem;color:var(--text-faint);font-style:italic;">No genre badges available yet.</p>';
        }

        let html = '';

        // ── Earned — 4-column badge grid ──────────────────────────────────────
        if (earnedGenres.length) {
          html += `
            <div style="font-size:0.58rem;font-weight:700;color:var(--text-muted);
                        text-transform:uppercase;letter-spacing:0.5px;margin-bottom:8px;">
              Earned
            </div>
            <div style="display:grid;grid-template-columns:repeat(4,1fr);
                        gap:8px;margin-bottom:14px;">`;

          earnedGenres.forEach(function(g) {
            const imgSrc = (g.currentBadge.imgUrl || '').replace('sz=w400', 'sz=w80');
            const tierLabel = g.maxReached
              ? '&#10003; Max'
              : 'T' + (g.currentBadge.badgeTier || '');
            const imgHtml = imgSrc
              ? `<img src="${imgSrc}"
                     style="width:44px;height:44px;border-radius:50%;object-fit:cover;
                            border:2px solid ${accentColor};cursor:pointer;display:block;"
                     onclick="openBadgeJourneyView_('GENRE_EXPLORER','${escapeHtml(g.genre)}')"
                     onerror="this.style.display='none';this.nextElementSibling.style.display='flex';">
                 <div style="display:none;width:44px;height:44px;border-radius:50%;
                             background:#E1F5EE;border:2px solid ${accentColor};
                             align-items:center;justify-content:center;font-size:1.2rem;
                             cursor:pointer;"
                      onclick="openBadgeJourneyView_('GENRE_EXPLORER','${escapeHtml(g.genre)}')">
                   📗
                 </div>`
              : `<div style="width:44px;height:44px;border-radius:50%;background:#E1F5EE;
                             border:2px solid ${accentColor};display:flex;align-items:center;
                             justify-content:center;font-size:1.2rem;cursor:pointer;"
                      onclick="openBadgeJourneyView_('GENRE_EXPLORER','${escapeHtml(g.genre)}')">
                   📗
                 </div>`;

            html += `
              <div style="display:flex;flex-direction:column;align-items:center;gap:3px;">
                ${imgHtml}
                <div style="font-size:0.56rem;color:var(--text-strong);font-weight:500;
                            text-align:center;line-height:1.2;">
                  ${escapeHtml(g.genre)}
                </div>
                <div style="font-size:0.52rem;color:${accentColor};font-weight:700;">
                  ${tierLabel}
                </div>
              </div>`;
          });

          html += `</div>`;
        }

        // ── In progress — compact amber-bar rows ──────────────────────────────
        if (inProgressGenres.length) {
          html += `
            <div style="font-size:0.58rem;font-weight:700;color:var(--text-muted);
                        text-transform:uppercase;letter-spacing:0.5px;margin-bottom:7px;">
              In progress
            </div>
            <div style="display:flex;flex-direction:column;gap:5px;margin-bottom:12px;">`;

          inProgressGenres.forEach(function(g) {
            html += `
              <div style="display:flex;align-items:center;gap:8px;cursor:pointer;"
                   onclick="openBadgeJourneyView_('GENRE_EXPLORER','${escapeHtml(g.genre)}')">
                <div style="width:64px;font-size:0.72rem;color:var(--text-strong);
                            font-weight:500;flex-shrink:0;white-space:nowrap;
                            overflow:hidden;text-overflow:ellipsis;">
                  ${escapeHtml(g.genre)}
                </div>
                <div style="flex:1;height:5px;background:var(--border-soft);
                            border-radius:3px;overflow:hidden;">
                  <div style="width:${g.pct}%;height:100%;background:var(--color-gamification);
                              border-radius:3px;"></div>
                </div>
                <div style="font-size:0.58rem;color:#BA7517;font-weight:500;
                            white-space:nowrap;flex-shrink:0;min-width:40px;text-align:right;">
                  ${g.count} / ${g.nextThreshold}
                </div>
              </div>`;
          });

          html += `</div>`;
        }

        // ── Discover — genre chips (aspiration without overwhelm) ─────────────
        // Cap visible chips at 8; remaining count shown as a neutral overflow chip.
        if (discoverGenres.length) {
          const MAX_VISIBLE  = 8;
          const visibleChips = discoverGenres.slice(0, MAX_VISIBLE);
          const overflowCount = discoverGenres.length - MAX_VISIBLE;

          html += `
            <div style="font-size:0.58rem;font-weight:700;color:var(--text-muted);
                        text-transform:uppercase;letter-spacing:0.5px;margin-bottom:7px;">
              Discover more
            </div>
            <div style="display:flex;flex-wrap:wrap;gap:6px;">`;

          visibleChips.forEach(function(g) {
            html += `
              <div style="font-size:0.65rem;color:var(--text-muted);
                          background:var(--surface-alt);border:1px solid var(--border-soft);
                          border-radius:20px;padding:3px 10px;cursor:pointer;"
                   onclick="openBadgeJourneyView_('GENRE_EXPLORER','${escapeHtml(g.genre)}')">
                ${escapeHtml(g.genre)}
              </div>`;
          });

          if (overflowCount > 0) {
            html += `
              <div style="font-size:0.65rem;color:var(--text-faint);
                          background:var(--surface-alt);border:1px solid var(--border-soft);
                          border-radius:20px;padding:3px 10px;">
                +${overflowCount} more
              </div>`;
          }

          html += `</div>`;
        }

        return html || '<p style="font-size:0.83rem;color:var(--text-faint);font-style:italic;">No genre tags on finished books yet.</p>';
      }

      /**
       * Builds the Annual Awards section body, grouped by year (newest first).
       *
       * Current year — full treatment:
       *   - "Earned" sub-section: 56px circles, gold border, caption + AP below
       *   - "Up for Grabs" sub-section: dimmed 56px circles, dashed border, caption only
       *   - Year header: season pill (X / Y earned) + AP earned right-aligned
       *
       * Past years — compact treatment:
       *   - Earned badges only (season is closed, nothing to chase)
       *   - Year header: earned count pill + total AP earned right-aligned
       *   - Years where the member earned nothing are skipped entirely
       *
       * @param {Object[]} yearlyBadges  - All YEARLY category badges from BadgeDB
       * @param {Set}      earnedBadgeIds
       * @returns {string} HTML
       */
      function buildYearlySectionHtml_(yearlyBadges, earnedBadgeIds) {
        if (!yearlyBadges || !yearlyBadges.length) {
          return '<p style="font-size:0.83rem;color:var(--text-faint);font-style:italic;">No annual award badges defined yet.</p>';
        }

        const currentYear = new Date().getFullYear().toString();

        // Group badges by year extracted from badgeMeta (format: "YYYY|TYPE_CODE")
        const byYear = {};
        yearlyBadges.forEach(function(badge) {
          const year = (badge.badgeMeta || '').split('|')[0] || 'Unknown';
          if (!byYear[year]) byYear[year] = [];
          byYear[year].push(badge);
        });

        const years = Object.keys(byYear).sort().reverse();
        let html = '';

        years.forEach(function(year) {
          const isCurrentYear = year === currentYear;
          const badges        = byYear[year];
          const earnedBadges  = badges.filter(function(b) { return earnedBadgeIds.has(b.id); });
          const earnedCount   = earnedBadges.length;

          // Past years with nothing earned are skipped entirely
          if (!isCurrentYear && !earnedCount) return;

          // Total AP earned this year — badgePoints is on the badge definition
          const yearAp = earnedBadges.reduce(function(sum, b) {
            return sum + (b.badgePoints || 0);
          }, 0);
          const yearApDisplay = yearAp > 0 ? yearAp.toLocaleString() + ' AP' : '';

          // ── Year header ────────────────────────────────────────────────
          const pillLabel = isCurrentYear
            ? earnedCount + ' / ' + badges.length + ' earned'
            : earnedCount + ' earned';

          html += `
            <div style="margin-bottom:${isCurrentYear ? '16' : '14'}px;">
              <div style="display:flex;align-items:center;justify-content:space-between;
                          margin-bottom:10px;">
                <div style="display:flex;align-items:center;gap:7px;">
                  <span style="font-size:0.78rem;font-weight:700;color:var(--text-strong);">
                    ${year} Season
                  </span>
                  <span style="font-size:0.58rem;font-weight:700;background:#fffde7;
                               color:#8a6d00;border:1px solid #f1c40f;border-radius:20px;
                               padding:2px 8px;">
                    ${pillLabel}
                  </span>
                </div>
                ${yearApDisplay
                  ? `<span style="font-size:0.6rem;color:#BA7517;font-weight:700;">
                       ${yearApDisplay}
                     </span>`
                  : ''}
              </div>`;

          // ── Earned badges ──────────────────────────────────────────────
          if (earnedCount) {
            if (isCurrentYear) {
              html += `
                <div style="font-size:0.57rem;font-weight:700;color:var(--text-muted);
                            text-transform:uppercase;letter-spacing:0.4px;margin-bottom:7px;">
                  Earned
                </div>`;
            }

            html += `<div style="display:flex;flex-wrap:wrap;gap:10px;
                                  ${isCurrentYear ? 'margin-bottom:12px;' : ''}">`;

            earnedBadges.forEach(function(badge) {
              const imgSrc  = badge.imgUrl ? badge.imgUrl.replace('sz=w400', 'sz=w100') : '';
              const imgHtml = imgSrc
                ? `<img src="${imgSrc}"
                       style="width:56px;height:56px;border-radius:50%;object-fit:cover;
                              border:2px solid #f1c40f;display:block;"
                       onclick="openBadgeDetailSheet('${badge.id}')"
                       onerror="this.style.display='none';this.nextElementSibling.style.display='flex';">
                   <div style="display:none;width:56px;height:56px;border-radius:50%;
                               background:#fffde7;border:2px solid #f1c40f;
                               align-items:center;justify-content:center;font-size:1.5rem;
                               cursor:pointer;"
                        onclick="openBadgeDetailSheet('${badge.id}')">🏆</div>`
                : `<div style="width:56px;height:56px;border-radius:50%;background:#fffde7;
                               border:2px solid #f1c40f;display:flex;align-items:center;
                               justify-content:center;font-size:1.5rem;cursor:pointer;"
                        onclick="openBadgeDetailSheet('${badge.id}')">🏆</div>`;

              const apLabel = (isCurrentYear && badge.badgePoints)
                ? `<div style="font-size:0.52rem;color:#8a6d00;font-weight:700;">
                     ${badge.badgePoints.toLocaleString()} AP
                   </div>`
                : '';

              html += `
                <div style="display:flex;flex-direction:column;align-items:center;
                            gap:3px;cursor:pointer;width:60px;text-align:center;"
                     onclick="openBadgeDetailSheet('${badge.id}')">
                  ${imgHtml}
                  <div style="font-size:0.58rem;color:var(--text-strong);font-weight:500;
                              line-height:1.2;max-width:58px;display:-webkit-box;
                              -webkit-line-clamp:2;-webkit-box-orient:vertical;
                              overflow:hidden;">
                    ${escapeHtml(badge.caption)}
                  </div>
                  ${apLabel}
                </div>`;
            });

            html += `</div>`;
          }

          // ── Up for Grabs (current year unearned only) ──────────────────
          if (isCurrentYear) {
            const unearnedBadges = badges.filter(function(b) {
              return !earnedBadgeIds.has(b.id);
            });

            if (unearnedBadges.length) {
              html += `
                <div style="font-size:0.57rem;font-weight:700;color:var(--text-muted);
                            text-transform:uppercase;letter-spacing:0.4px;margin-bottom:7px;">
                  Up for Grabs
                </div>
                <div style="display:flex;flex-wrap:wrap;gap:10px;">`;

              unearnedBadges.forEach(function(badge) {
                const imgSrc  = badge.imgUrl ? badge.imgUrl.replace('sz=w400', 'sz=w100') : '';
                const imgHtml = imgSrc
                  ? `<img src="${imgSrc}"
                         style="width:56px;height:56px;border-radius:50%;object-fit:cover;
                                border:2px dashed var(--border-soft);display:block;opacity:0.45;"
                         onerror="this.style.display='none';this.nextElementSibling.style.display='flex';">
                     <div style="display:none;width:56px;height:56px;border-radius:50%;
                                 background:var(--surface-alt);
                                 border:2px dashed var(--border-soft);
                                 align-items:center;justify-content:center;
                                 font-size:1.5rem;opacity:0.45;">🏆</div>`
                  : `<div style="width:56px;height:56px;border-radius:50%;
                                 background:var(--surface-alt);
                                 border:2px dashed var(--border-soft);display:flex;
                                 align-items:center;justify-content:center;
                                 font-size:1.5rem;opacity:0.45;">🏆</div>`;

                html += `
                  <div style="display:flex;flex-direction:column;align-items:center;
                              gap:3px;width:60px;text-align:center;cursor:pointer;"
                       onclick="openBadgeDetailSheet('${badge.id}')">
                    ${imgHtml}
                    <div style="font-size:0.58rem;color:var(--text-faint);line-height:1.2;
                                max-width:58px;display:-webkit-box;-webkit-line-clamp:2;
                                -webkit-box-orient:vertical;overflow:hidden;">
                      ${escapeHtml(badge.caption)}
                    </div>
                  </div>`;
              });

              html += `</div>`;
            }
          }

          html += `</div>`; // close year block
        });

        return html || '<p style="font-size:0.83rem;color:var(--text-faint);font-style:italic;">No annual awards earned yet.</p>';
      }

      /**
       * Builds the Special Badges section — earned only, no teasers for unearned.
       *
       * @param {Object[]} specialBadges  - All SPECIAL category badges
       * @param {Set}      earnedBadgeIds
       * @returns {string} HTML
       */
      function buildSpecialSectionHtml_(specialBadges, earnedBadgeIds) {
        if (!specialBadges) return '';
        const earned = specialBadges.filter(b => earnedBadgeIds.has(b.id));
        if (!earned.length) {
          return '<p style="font-size:0.83rem;color:var(--text-faint);font-style:italic;">No special badges yet — these are rare!</p>';
        }
        return `<div style="display:flex;flex-wrap:wrap;gap:14px;">` +
          earned.map(function(badge) {
            const imgSrc = badge.imgUrl ? badge.imgUrl.replace('sz=w400', 'sz=w100') : '';
            const imgHtml = imgSrc
              ? `<img src="${imgSrc}"
                    style="width:60px;height:60px;border-radius:50%;object-fit:cover;
                           border:2px solid var(--arka-accent);margin-bottom:4px;display:block;"
                    onerror="this.style.display='none';this.nextElementSibling.style.display='flex';">
                 <div style="display:none;width:60px;height:60px;border-radius:50%;background:#f0e8f5;
                     border:2px solid var(--arka-accent);align-items:center;justify-content:center;font-size:1.6rem;">⭐</div>`
              : `<div style="width:60px;height:60px;border-radius:50%;background:#f0e8f5;border:2px solid var(--arka-accent);
                     display:flex;align-items:center;justify-content:center;font-size:1.6rem;">⭐</div>`;
            return `
              <div style="display:flex;flex-direction:column;align-items:center;gap:4px;
                          cursor:pointer;width:74px;"
                   onclick="openBadgeDetailSheet('${badge.id}')">
                ${imgHtml}
                <div style="font-size:0.72rem;color:var(--text-strong);text-align:center;line-height:1.2;
                            max-width:72px;display:-webkit-box;-webkit-line-clamp:2;
                            -webkit-box-orient:vertical;overflow:hidden;">
                  ${escapeHtml(badge.caption)}
                </div>
              </div>`;
          }).join('') + '</div>';
      }


      /**
       * Builds the "Closest to unlock" horizontal scroll strip.
       *
       * Ranks in-progress replacing-series badges by estimated calendar days to
       * unlock at the member's current reading pace (daysToUnlock), matching the
       * ranking logic in MasterEngine's generateMemberCoachInsights_().
       *
       * Pace signals (badgePaceAvgPagesPerDay, badgePaceAvgBooksPerDay) are read
       * from coachData.statSnapshot where MasterEngine exports them nightly.
       *
       * Only categories where the member has ≥1 earned badge AND a next tier
       * exists are included — maxed-out and unstarted series are excluded.
       *
       * @param {Object} badgesByCat  - Output of buildBadgesByCategory_()
       * @param {Set}    earnedBadgeIds
       * @param {Object} progress     - Output of computeMyBadgeProgress_()
       * @returns {string} HTML — the strip wrapper div, or '' if no candidates
       */
      function buildUpNextStrip_(badgesByCat, earnedBadgeIds, progress) {
        const STRIP_MAX = 3; // Maximum cards shown in strip before scroll

        // ── Pace signals from last nightly MasterEngine run ───────────────────
        // meCoachInsightsCache is the global CoachInsights payload (MemberDB Col S)
        // populated in Wave 1. Both fields are 0 for members with no page logs yet.
        const statSnap           = (meCoachInsightsCache && meCoachInsightsCache.statSnapshot) || {};
        const paceAvgPagesPerDay = statSnap.badgePaceAvgPagesPerDay || 0;
        const paceAvgBooksPerDay = statSnap.badgePaceAvgBooksPerDay || 0;

        /**
         * _badgeDaysToUnlock_()
         * Estimates calendar days to earn the next badge in a given category,
         * given the member's current pace and the raw unit gap remaining.
         *
         * Matches the formula used in MasterEngine's _nbCheckCategory_() and the
         * FAT_READ / GENRE_EXPLORER candidate builders for consistency.
         *
         * @param {string} category     - Badge category key
         * @param {number} gap          - Raw units remaining to threshold
         * @param {number} threshold    - The absolute threshold value for this tier
         * @returns {number} Estimated days to unlock; 99999 when pace is unknown
         */
        function _badgeDaysToUnlock_(category, gap, threshold) {
          switch (category) {
            case 'PAGE_MILESTONE':
              return paceAvgPagesPerDay > 0 ? Math.round(gap / paceAvgPagesPerDay) : 99999;
            case 'BOOK_MILESTONE':
              return paceAvgBooksPerDay > 0 ? Math.round(gap / paceAvgBooksPerDay) : 99999;
            case 'STREAK_MILESTONE':
              return gap * 7; // each gap unit is one calendar week that must elapse
            case 'PLOGGER':
              return gap * 7; // each unique week = 7 calendar days minimum
            case 'ANNIVERSARY':
              return Math.round(gap * 365.25); // gap is in years; convert to days
            case 'FAT_READ':
              // Time to read one book of `threshold` pages — not gap / pace
              return paceAvgPagesPerDay > 0 ? Math.round(threshold / paceAvgPagesPerDay) : 99999;
            default:
              return paceAvgBooksPerDay > 0 ? Math.round(gap / paceAvgBooksPerDay) : 99999;
          }
        }

        /**
         * _badgeEstimatedTimeLabel_()
         * Converts daysToUnlock to a human-readable time label shown on the card.
         *
         * @param {number} days
         * @returns {string} e.g. "~2 weeks" or "" when unknown
         */
        function _badgeEstimatedTimeLabel_(days) {
          if (!days || days >= 99999) return '';
          if (days <= 7)   return '~this week';
          if (days <= 14)  return '~2 weeks';
          if (days <= 21)  return '~3 weeks';
          if (days <= 30)  return '~1 month';
          if (days <= 60)  return '~2 months';
          if (days <= 90)  return '~3 months';
          if (days <= 120) return '~4 months';
          if (days <= 150) return '~5 months';
          if (days <= 180) return '~6 months';
          if (days <= 270) return '~9 months';
          if (days <= 365) return '~1 year';
          if (days <= 545) return '~1.5 years';
          if (days <= 730) return '~2 years';
          return '~' + Math.round(days / 365) + ' years';
        }

        const candidates = [];

        BADGE_CATEGORY_DISPLAY.forEach(function(conf) {
          const { category, label, icon, accent } = conf;

          // Only replacing-series categories with a measurable metric
          if (!conf.metricKey ||
              ['GENRE_EXPLORER','YEARLY','SPECIAL','ONBOARDING'].includes(category)) return;

          const series = badgesByCat[category] || [];
          if (!series.length) return;

          // Resolve the highest earned tier and the next tier to chase
          let currentBadge = null, nextBadge = null;
          for (let i = series.length - 1; i >= 0; i--) {
            if (earnedBadgeIds.has(series[i].id)) {
              currentBadge = series[i];
              nextBadge    = series[i + 1] || null;
              break;
            }
          }
          // Must have earned at least one tier AND have a next tier to chase
          if (!currentBadge || !nextBadge) return;

          const thresholds    = BADGE_THRESHOLDS_FRONTEND[category] || [];
          const nextTierIdx   = (nextBadge.badgeTier || 1) - 1;
          const nextThreshold = thresholds[nextTierIdx] || 0;
          if (!nextThreshold) return;

          const rawMetric = progress[conf.metricKey] || 0;
          // STREAK_MILESTONE displays currentStreak (resets on break), not bestStreak
          const barMetric = (category === 'STREAK_MILESTONE')
            ? (progress.currentStreak || 0)
            : rawMetric;

          const remaining      = Math.max(0, nextThreshold - barMetric);
          const pct            = Math.min(100, Math.round((barMetric / nextThreshold) * 100));
          const daysToUnlock   = _badgeDaysToUnlock_(category, remaining, nextThreshold);
          const estimatedLabel = _badgeEstimatedTimeLabel_(daysToUnlock);
          const apOnUnlock     = nextBadge.badgePoints || 0;

          candidates.push({
            category, label, icon, accent, conf,
            pct, remaining, nextThreshold, barMetric,
            apOnUnlock, daysToUnlock, estimatedLabel
          });
        });

        // Filter to badges achievable within MAX_STRIP_DAYS_TO_UNLOCK.
        // Matches the spirit of MasterEngine's NB_MAX_DAYS_TO_UNLOCK gate so
        // the strip never surfaces badges that are years away.
        // Time-bound categories (streak/plogger) can legitimately exceed the
        // page/book gates — 180 days gives them fair headroom while still
        // excluding multi-year targets.
        const MAX_STRIP_DAYS_TO_UNLOCK = 180;
        const filteredCandidates = candidates.filter(function(c) {
          return c.daysToUnlock <= MAX_STRIP_DAYS_TO_UNLOCK;
        });

        // Fall back to unfiltered top-3 if no candidate clears the gate —
        // this prevents an empty strip for members who are far from every badge.
        const rankedCandidates = filteredCandidates.length > 0
          ? filteredCandidates : candidates;

        if (!rankedCandidates.length) return '';

        // Sort ascending by daysToUnlock — the badge achievable soonest at current
        // pace appears first, matching MasterEngine's ranking logic exactly.
        // Ties broken by pct descending (higher progress is secondary signal).
        rankedCandidates.sort(function(a, b) {
          if (a.daysToUnlock !== b.daysToUnlock) return a.daysToUnlock - b.daysToUnlock;
          return b.pct - a.pct;
        });

        let cardsHtml = '';

        rankedCandidates.slice(0, STRIP_MAX).forEach(function(c) {
          const unitLabel  = c.conf.unit || '';
          const metricText = c.barMetric.toLocaleString()
            + ' / ' + c.nextThreshold.toLocaleString()
            + (unitLabel ? ' ' + unitLabel : '');
          const remainText = c.remaining.toLocaleString()
            + (unitLabel ? ' ' + unitLabel : '') + ' away';
          // Compact AP display: 3000 → 3K, 1500 → 1.5K, 600 → 600
          const apDisplay  = c.apOnUnlock >= 1000
            ? (c.apOnUnlock % 1000 === 0
                ? (c.apOnUnlock / 1000) + 'K'
                : (c.apOnUnlock / 1000).toFixed(1) + 'K')
            : c.apOnUnlock.toLocaleString();

          cardsHtml += `
            <div style="flex-shrink:0;width:140px;border:1px solid var(--border-soft);
                        border-radius:10px;background:white;overflow:hidden;cursor:pointer;"
                 onclick="openBadgeJourneyView_('${c.category}')">
              <div style="height:3px;background:${c.accent};"></div>
              <div style="padding:10px;">
                <div style="display:flex;align-items:center;gap:6px;margin-bottom:7px;">
                  <span style="font-size:1.1rem;">${c.icon}</span>
                  <span style="font-size:0.7rem;font-weight:600;color:var(--text-strong);
                               line-height:1.2;">${c.label}</span>
                </div>
                <div style="margin-bottom:6px;">
                  <div style="display:flex;justify-content:space-between;align-items:baseline;
                              margin-bottom:3px;">
                    <span style="font-size:0.62rem;color:var(--text-muted);">${metricText}</span>
                    <span style="font-size:0.62rem;font-weight:700;color:${c.accent};
                                 white-space:nowrap;margin-left:4px;">${c.pct}%</span>
                  </div>
                  <div style="height:5px;background:var(--border-soft);border-radius:3px;
                              overflow:hidden;">
                    <div style="width:${c.pct}%;height:100%;background:var(--color-gamification);
                                border-radius:3px;"></div>
                  </div>
                </div>
                <div style="display:flex;align-items:center;justify-content:space-between;">
                  <span style="font-size:0.6rem;color:var(--text-muted);">
                    ${c.estimatedLabel || remainText}
                  </span>
                  ${c.apOnUnlock ? `
                    <span style="font-size:0.58rem;font-weight:700;color:#BA7517;
                                 background:#FAEEDA;border-radius:8px;padding:2px 5px;
                                 white-space:nowrap;margin-left:4px;">
                      ${apDisplay} AP
                    </span>` : ''}
                </div>
              </div>
            </div>`;
        });

        return `
          <div style="margin-bottom:14px;">
            <div style="font-size:0.6rem;font-weight:700;color:var(--text-muted);
                        text-transform:uppercase;letter-spacing:0.6px;margin-bottom:8px;">
              &#9889; Closest to unlock
            </div>
            <div style="display:flex;gap:8px;overflow-x:auto;padding-bottom:4px;
                        -webkit-overflow-scrolling:touch;scrollbar-width:none;">
              ${cardsHtml}
            </div>
          </div>`;
      }


      /**
       * Renders the full Badge Collection view.
       *
       * Populates three separate DOM targets:
       *   #badgesHeroStats   — three-stat strip (badge count, max'd series, AP total)
       *   #badgesPersonaPill — archetype pill; empty/hidden for Forming profiles
       *   #badgesGalleryContent — full-card rows for earned categories (in
       *                           BADGE_CATEGORY_DISPLAY order), then compact rows
       *                           for unstarted categories, then admin panel
       *
       * Called by switchTab('badges'), applyWave3(), and applyWave3b().
       */
      function renderBadgeGallery() {
        const container = document.getElementById('badgesGalleryContent');
        if (!container) return;

        if (!isWave3Loaded) {
          container.innerHTML = `<p style="text-align:center;color:var(--text-muted);
            font-style:italic;padding:40px 0;">Loading badges&hellip;</p>`;
          return;
        }

        const isAdmin        = ADMIN_MEMBER_IDS.includes(currentUser);
        const earnedAwards   = memberBadgeIndex.get(currentUser) || [];
        const earnedBadgeIds = new Set(earnedAwards.map(function(a) { return a.badgeId; }));
        const progress       = computeMyBadgeProgress_();
        const badgesByCat    = buildBadgesByCategory_();

        // ── Hero stats ────────────────────────────────────────────────────────
        // Max'd: replacing-series categories where the user holds the top-tier badge
        let maxedCount = 0;
        BADGE_CATEGORY_DISPLAY.forEach(function(conf) {
          if (['GENRE_EXPLORER','YEARLY','SPECIAL','ONBOARDING'].includes(conf.category)) return;
          const series = badgesByCat[conf.category] || [];
          if (series.length && earnedBadgeIds.has(series[series.length - 1].id)) maxedCount++;
        });

        // Total AP across all earned badges — badgePoints is on the badge definition,
        // not the award record, so we look it up via badgesMap for each award.
        const totalAp = earnedAwards.reduce(function(sum, a) {
          const def = badgesMap.get(a.badgeId);
          return sum + (def ? (def.badgePoints || 0) : 0);
        }, 0);
        const apDisplay = totalAp >= 10000
          ? (totalAp / 1000).toFixed(1) + 'K'
          : totalAp.toLocaleString();

        const statsEl = document.getElementById('badgesHeroStats');
        if (statsEl) {
          statsEl.innerHTML = `
            <div style="text-align:center;">
              <div style="font-size:0.95rem;font-weight:700;color:#C0DD97;">
                ${earnedAwards.length}
              </div>
              <div style="font-size:0.62rem;color:rgba(255,255,255,0.5);margin-top:2px;">
                Badges earned
              </div>
            </div>
            <div style="text-align:center;border-left:1px solid rgba(255,255,255,0.15);
                        border-right:1px solid rgba(255,255,255,0.15);padding:0 14px;">
              <div style="font-size:0.95rem;font-weight:700;color:var(--color-gamification);">${maxedCount}</div>
              <div style="font-size:0.62rem;color:rgba(255,255,255,0.5);margin-top:2px;">
                Series max'd
              </div>
            </div>
            <div style="text-align:center;">
              <div style="font-size:0.95rem;font-weight:700;color:#C0DD97;">${apDisplay}</div>
              <div style="font-size:0.62rem;color:rgba(255,255,255,0.5);margin-top:2px;">
                AP earned
              </div>
            </div>`;
        }

        // Persona pill — archetypeName is null for Forming profiles (not enough data yet)
        const pillEl = document.getElementById('badgesPersonaPill');
        if (pillEl) {
          const profile = personaProfileMap.get(currentUser);
          if (profile && profile.archetypeName) {
            pillEl.innerHTML = `
              <div style="display:inline-flex;align-items:center;gap:5px;background:white;
                          border:1px solid rgba(59,109,17,0.25);border-radius:99px;
                          padding:4px 12px 4px 8px;">
                <span style="font-size:0.85rem;line-height:1;">
                  ${escapeHtml(profile.archetypeEmoji || '📖')}
                </span>
                <span style="font-size:0.65rem;font-weight:700;color:#27500A;letter-spacing:0.3px;">
                  ${escapeHtml(profile.archetypeName)}
                </span>
              </div>`;
          } else {
            pillEl.innerHTML = '';
          }
        }

        // ── Category section cards ──────────────────────────────────────────────
        // "Closest to unlock" strip sits above the full section cards — top 3 in-progress
        // series sorted by progress %, giving the member an immediate motivational nudge.
        const upNextHtml = buildUpNextStrip_(badgesByCat, earnedBadgeIds, progress);

        let html = upNextHtml + `
          <div style="font-size:0.6rem;font-weight:700;color:var(--text-muted);
                      text-transform:uppercase;letter-spacing:0.6px;margin-bottom:10px;">
            Your journeys
          </div>`;

        const unstartedRows = []; // Collected then rendered as compact rows at the bottom

        BADGE_CATEGORY_DISPLAY.forEach(function(conf) {
          const { category, label, icon, accent } = conf;

          // SPECIAL and ONBOARDING: skip entirely when no badges exist in the database
          if ((category === 'SPECIAL' || category === 'ONBOARDING')
              && !(badgesByCat[category] || []).length) return;

          // Count earned badges in this category
          let catEarned = 0;
          if (category === 'GENRE_EXPLORER') {
            const geMap = badgesByCat['GENRE_EXPLORER'] || {};
            Object.values(geMap).forEach(function(arr) {
              arr.forEach(function(b) { if (earnedBadgeIds.has(b.id)) catEarned++; });
            });
          } else {
            (badgesByCat[category] || []).forEach(function(b) {
              if (earnedBadgeIds.has(b.id)) catEarned++;
            });
          }

          if (catEarned === 0) {
            // YEARLY and ONBOARDING always render their full section cards even with
            // 0 earned — YEARLY shows the "Up for Grabs" sub-section so anticipation
            // builds before any award is won; ONBOARDING shows the full chapter
            // journey so new members can see what's ahead from day one.
            // All other categories collapse into a compact "Not yet started" row.
            if (category !== 'YEARLY' && category !== 'ONBOARDING') {
              // Carry the first badge ID so non-journey unstarted rows can open a
              // detail sheet instead of showing a dead chevron.
              const rawSeries    = badgesByCat[category];
              const seriesArr    = Array.isArray(rawSeries) ? rawSeries : [];
              const firstBadgeId = seriesArr.length ? seriesArr[0].id : null;
              unstartedRows.push({ label, icon, category, firstBadgeId });
              return; // exit forEach for this category — no card to render
            }
            // YEARLY and ONBOARDING: fall through to card builders below
          }

          // ── Build full earned card ────────────────────────────────────────
          if (category === 'GENRE_EXPLORER') {
            html += buildGenreExplorerCardHtml_(
              badgesByCat['GENRE_EXPLORER'] || {}, earnedBadgeIds,
              progress.genreCounts, catEarned
            );
          } else if (category === 'YEARLY') {
            html += buildNamedSectionCardHtml_(
              label, icon, accent,
              buildYearlySectionHtml_(badgesByCat['YEARLY'] || [], earnedBadgeIds)
            );
          } else if (category === 'SPECIAL') {
            html += buildNamedSectionCardHtml_(
              label, icon, accent,
              buildSpecialSectionHtml_(badgesByCat['SPECIAL'] || [], earnedBadgeIds)
            );
          } else if (category === 'ONBOARDING') {
            // ONBOARDING is non-tiered — displayed identically to SPECIAL badges
            // (earned-only badge grid; no progress bar or journey band)
            html += buildNamedSectionCardHtml_(
              label, icon, accent,
              buildSpecialSectionHtml_(badgesByCat['ONBOARDING'] || [], earnedBadgeIds)
            );
          } else {
            html += buildReplacingSeriesHtml_(
              category, badgesByCat[category] || [], earnedBadgeIds, progress, accent
            );
          }
        });

        // ── Unstarted compact rows ─────────────────────────────────────────────
        if (unstartedRows.length) {
          html += `
            <div style="font-size:0.6rem;font-weight:700;color:var(--text-muted);
                        text-transform:uppercase;letter-spacing:0.6px;margin:8px 0 8px;">
              Not yet started
            </div>`;

          const JOURNEY_SUPPORTED = ['PAGE_MILESTONE','BOOK_MILESTONE','STREAK_MILESTONE',
            'PLOGGER','REVIEW_MILESTONE','FAT_READ','GENRE_COLLECTOR',
            'ANNIVERSARY','SOCIAL_BUTTERFLY','LIBRARIAN'];

          unstartedRows.forEach(function(row) {
            const hint         = buildUnstartedHint_(row.category);
            const hasJourney   = JOURNEY_SUPPORTED.includes(row.category);
            const hasFirstBadge = !!row.firstBadgeId;

            // Resolve click action and right-side icon for each row type:
            //   Journey-supported  → chevron  → opens journey view
            //   Has first badge    → info circle → opens first badge detail sheet
            //   Neither (e.g. passive YEARLY watch-this-space) → no icon, not tappable
            const clickAction = hasJourney
              ? `onclick="openBadgeJourneyView_('${row.category}')"`
              : (hasFirstBadge
                  ? `onclick="openBadgeDetailSheet('${row.firstBadgeId}')"`
                  : '');

            const isClickable = hasJourney || hasFirstBadge;

            const rightIconHtml = hasJourney
              ? `<i class="ti ti-chevron-right"
                    style="font-size:15px;color:var(--text-faint);flex-shrink:0;"></i>`
              : (hasFirstBadge
                  ? `<i class="fa-solid fa-circle-info"
                        style="font-size:14px;color:var(--text-faint);flex-shrink:0;"></i>`
                  : '');

            html += `
              <div style="border:1px solid var(--border-soft);border-radius:10px;
                          margin-bottom:7px;background:white;
                          ${isClickable ? 'cursor:pointer;' : ''}"
                   ${clickAction}>
                <div style="display:flex;align-items:center;justify-content:space-between;
                            padding:10px 12px;">
                  <div style="display:flex;align-items:center;gap:9px;">
                    <span style="font-size:1rem;">${row.icon}</span>
                    <div>
                      <div style="font-size:0.82rem;color:var(--text-muted);font-weight:500;">
                        ${row.label}
                      </div>
                      ${hint
                        ? `<div style="font-size:0.6rem;color:var(--text-faint);margin-top:1px;">
                             ${hint}
                           </div>`
                        : ''}
                    </div>
                  </div>
                  ${rightIconHtml}
                </div>
              </div>`;
          });
        }

        // ── Admin panel (admin-only, always at the bottom) ─────────────────────
        if (isAdmin) html += buildAdminBadgePanelHtml();

        container.innerHTML = html;
      }


      // ─── Badge Journey Overlay (Variant A — Linear Series) ────────────────────────

      /**
       * Opens the full-screen Badge Journey overlay for a given linear-series category.
       *
       * The journey renders a snake-shaped SVG bezier path from Tier 1 to Tier N with:
       *   - Earned nodes: real badge image (HTML <img>) rendered on top of the SVG canvas,
       *     clickable via openBadgeDetailSheet(). Pulse ring kept in SVG for "you are here".
       *   - In-progress node: amber dashed SVG circle with tier number (no image).
       *   - Locked nodes: gray dashed SVG circle with "?" (no image).
       *   - Purple solid path for earned tiers.
       *   - Amber solid fill (de Casteljau at progress fraction) for the in-progress segment.
       *   - Amber dashed path for the remaining gap to the next node.
       *   - Gray path for all locked future tiers.
       *   - Locked tier cards show only "A surprise" to preserve discovery.
       *   - Auto-scrolls to center the highest earned node in the viewport on open.
       *
       * Layout constants at the top control all geometry — tune here, not in the
       * rendering logic below.
       *
       * @param {string} categoryKey - Badge category key, e.g. 'PAGE_MILESTONE'
       */
      function openBadgeJourneyView_(categoryKey, genreFilter) {

        // ── Layout & style constants ──────────────────────────────────────
        const JRNY_SVG_WIDTH      = 340;       // full phone width — no horizontal padding
        const JRNY_NODE_LEFT_X    = 74;        // x of left-side nodes — pushed toward left edge
        const JRNY_NODE_RIGHT_X   = 266;       // x of right-side nodes — pushed toward right edge (340 - 74)
        const JRNY_NODE_RADIUS    = 40;        // px — earned / in-progress circle radius (~2.1× original)
        const JRNY_LOCKED_RADIUS  = 34;        // px — locked circle radius (slightly smaller than earned)
        const JRNY_Y_START        = 75;        // y coordinate of the first (top) node
        const JRNY_Y_STEP         = 118;       // vertical distance between consecutive nodes (expanded for larger circles)
        const JRNY_CARD_INSET     = 24;        // px from screen edge to card outer edge (higher = more toward centre)
        const JRNY_PATH_STROKE    = 5;         // SVG stroke-width for the main snake path
        const JRNY_PURPLE         = 'var(--arka-accent)'; // Arka Purple — earned path colour
        const JRNY_PURPLE_DARK    = 'var(--arka-accent-hover)'; // earned image border colour
        const JRNY_AMBER_SOLID    = '#BA7517'; // in-progress filled path portion
        const JRNY_AMBER_DASH     = 'var(--color-gamification)'; // in-progress remaining dashed gap
        const JRNY_GRAY_PATH      = '#D3D1C7'; // locked path background

        // Image diameter matches node circle diameter exactly so badge fills the node
        const JRNY_BADGE_IMG_SIZE = JRNY_NODE_RADIUS * 2; // 38 px

        // ── Gather data ──────────────────────────────────────────────────────
        const conf = BADGE_CATEGORY_DISPLAY.find(function(c) { return c.category === categoryKey; });
        if (!conf) return;

        const badgesByCat = buildBadgesByCategory_();
        const progress    = computeMyBadgeProgress_();

        // ── Genre Explorer sub-series handling ────────────────────────────
        // When genreFilter is supplied the journey renders a single genre's tier
        // progression. Data sourcing differs from standard categories but every
        // downstream rendering step (SVG path, cards, overlay) is identical.
        const isGenreSubJourney = (categoryKey === 'GENRE_EXPLORER' && !!genreFilter);

        const badgesInSeries = isGenreSubJourney
          ? ((badgesByCat['GENRE_EXPLORER'] || {})[genreFilter] || [])
              .slice()
              .sort(function(a, b) { return (a.badgeTier || 0) - (b.badgeTier || 0); })
          : (badgesByCat[categoryKey] || [])
              .slice()
              .sort(function(a, b) { return (a.badgeTier || 0) - (b.badgeTier || 0); });

        if (!badgesInSeries.length) return;

        const earnedAwards   = memberBadgeIndex.get(currentUser) || [];
        const earnedBadgeIds = new Set(earnedAwards.map(function(a) { return a.badgeId; }));
        const thresholds     = BADGE_THRESHOLDS_FRONTEND[categoryKey] || [];

        // Genre sub-journeys use the per-genre book count; standard categories
        // use the top-level metric field (e.g. pageCount, bookCount).
        const rawMetric = isGenreSubJourney
          ? (progress.genreCounts[genreFilter] || 0)
          : (conf.metricKey ? (progress[conf.metricKey] || 0) : 0);

        // STREAK_MILESTONE progress display uses currentStreak (live active streak)
        // so the bar and label reset to zero when a streak breaks. rawMetric
        // (bestStreak) is still used where earned-tier determination is needed.
        const barMetric = (categoryKey === 'STREAK_MILESTONE' && !isGenreSubJourney)
          ? (progress.currentStreak || 0)
          : rawMetric;

        const totalTiers = badgesInSeries.length;

        // Index of the highest earned tier; −1 means not started yet
        let highestEarnedIdx = -1;
        for (let i = badgesInSeries.length - 1; i >= 0; i--) {
          if (earnedBadgeIds.has(badgesInSeries[i].id)) {
            highestEarnedIdx = i;
            break;
          }
        }
        const nextIdx = highestEarnedIdx + 1; // in-progress tier index (may === totalTiers if maxed)

        // AP total earned within this category
        const categoryBadgeIds = new Set(badgesInSeries.map(function(b) { return b.id; }));
        // badgePoints lives on BadgeDB (badgesMap), not on the award record itself.
        const totalEarnedAp    = earnedAwards
          .filter(function(a) { return categoryBadgeIds.has(a.badgeId); })
          .reduce(function(sum, a) {
            const def = badgesMap.get(a.badgeId);
            return sum + (def ? (def.badgePoints || 0) : 0);
          }, 0);

        const earnedCount   = Math.max(0, highestEarnedIdx + 1);
        const metricLabel = isGenreSubJourney ? 'books' : (conf.unit || '');

        // ── Node position array ────────────────────────────────────────────
        // Even index → left side; odd index → right side.
        const svgHeight = JRNY_Y_START + (totalTiers - 1) * JRNY_Y_STEP + 80;
        const nodes = badgesInSeries.map(function(badge, idx) {
          const isLeft = (idx % 2 === 0);
          return {
            badge  : badge,
            idx    : idx,
            x      : isLeft ? JRNY_NODE_LEFT_X : JRNY_NODE_RIGHT_X,
            y      : JRNY_Y_START + idx * JRNY_Y_STEP,
            isLeft : isLeft
          };
        });

        // ── SVG path helpers ──────────────────────────────────────────────

        /**
         * Cubic bezier d-string for one snake segment between two consecutive nodes.
         * Both control points share the midpoint y, producing a gentle S-curve.
         * Nodes positioned at 130/210 (out of 340px) keep the curve shallow so
         * cards have ample room on the outer edges.
         */
        function buildBezierSegment_(fromNode, toNode) {
          const midY = (fromNode.y + toNode.y) / 2;
          return ' C' + fromNode.x + ',' + midY
            + ' ' + toNode.x + ',' + midY
            + ' ' + toNode.x + ',' + toNode.y;
        }

        /** Linear interpolation between two 2-D points. */
        function lerpPt_(a, b, t) {
          return { x: a.x + (b.x - a.x) * t, y: a.y + (b.y - a.y) * t };
        }

        /**
         * Splits a cubic bezier at parameter t (de Casteljau).
         * Returns { left, right } each as a 4-point array.
         * Used to draw exactly (progress %) of the in-progress path segment in amber.
         */
        function deCasteljauSubdivide_(P0, P1, P2, P3, t) {
          const P01   = lerpPt_(P0, P1, t);
          const P12   = lerpPt_(P1, P2, t);
          const P23   = lerpPt_(P2, P3, t);
          const P012  = lerpPt_(P01, P12, t);
          const P123  = lerpPt_(P12, P23, t);
          const P0123 = lerpPt_(P012, P123, t);
          return {
            left  : [P0, P01, P012, P0123],
            right : [P0123, P123, P23, P3]
          };
        }

        /** Formats a control-point coordinate to 1 decimal place for compact SVG output. */
        function fp_(n) { return n.toFixed(1); }

        /** Builds an SVG cubic bezier d-string from a 4-point array. */
        function ptsToCubicD_(pts) {
          return 'M' + fp_(pts[0].x) + ',' + fp_(pts[0].y)
            + ' C' + fp_(pts[1].x) + ',' + fp_(pts[1].y)
            + ' '  + fp_(pts[2].x) + ',' + fp_(pts[2].y)
            + ' '  + fp_(pts[3].x) + ',' + fp_(pts[3].y);
        }

        /**
         * Evaluates a cubic bezier B(t) at parameter t.
         * Used by arcLengthParam_() to build the cumulative arc-length table.
         *
         * @param   {Object} P0,P1,P2,P3 - Control points {x, y}
         * @param   {number} t           - Parametric value 0–1
         * @returns {Object} Point {x, y} on the curve
         */
        function evalCubicBezierPt_(P0, P1, P2, P3, t) {
          const mt = 1 - t;
          return {
            x: mt*mt*mt*P0.x + 3*mt*mt*t*P1.x + 3*mt*t*t*P2.x + t*t*t*P3.x,
            y: mt*mt*mt*P0.y + 3*mt*mt*t*P1.y + 3*mt*t*t*P2.y + t*t*t*P3.y
          };
        }

        /**
         * Converts an arc-length fraction (0–1) to the corresponding parametric t
         * for a cubic bezier. Uses a 32-sample cumulative arc-length table plus linear
         * interpolation between samples for sub-interval accuracy.
         *
         * This corrects the visual distortion on S-curve snake paths where the middle
         * of the curve traverses more pixels per unit-t than the endpoints, causing a
         * raw-t split to visually overshoot the intended progress percentage.
         *
         * @param   {Object} P0,P1,P2,P3 - Bezier control points
         * @param   {number} frac         - Target arc-length fraction (0–1)
         * @returns {number} Parametric t where arc_length(0→t) = frac × totalLength
         */
        function arcLengthParam_(P0, P1, P2, P3, frac) {
          if (frac <= 0) return 0;
          if (frac >= 1) return 1;
          const N = 32;
          const tSamples   = [0];
          const lenSamples = [0];
          let prev = P0, cumLen = 0;
          for (let i = 1; i <= N; i++) {
            const t  = i / N;
            const pt = evalCubicBezierPt_(P0, P1, P2, P3, t);
            const dx = pt.x - prev.x, dy = pt.y - prev.y;
            cumLen += Math.sqrt(dx * dx + dy * dy);
            tSamples.push(t);
            lenSamples.push(cumLen);
            prev = pt;
          }
          const targetLen = frac * cumLen; // cumLen is the total arc length
          for (let i = 1; i <= N; i++) {
            if (lenSamples[i] >= targetLen) {
              const span   = lenSamples[i] - lenSamples[i - 1];
              const interp = span > 0 ? (targetLen - lenSamples[i - 1]) / span : 0;
              return tSamples[i - 1] + interp / N; // linear interpolation within the interval
            }
          }
          return 1;
        }

        // ── Build path d-strings ──────────────────────────────────────────

        // Full background path in gray (all tiers)
        let fullPathD = 'M' + nodes[0].x + ',' + nodes[0].y;
        for (let s = 1; s < nodes.length; s++) {
          fullPathD += buildBezierSegment_(nodes[s - 1], nodes[s]);
        }

        // Purple earned path (node 0 → highestEarnedIdx)
        let earnedPathD = '';
        if (highestEarnedIdx >= 0) {
          earnedPathD = 'M' + nodes[0].x + ',' + nodes[0].y;
          for (let e = 1; e <= highestEarnedIdx; e++) {
            earnedPathD += buildBezierSegment_(nodes[e - 1], nodes[e]);
          }
        }

        // Amber partial fill and dashed remainder for the in-progress segment.
        // Three cases are handled explicitly so no tFrac boundary silently drops the visuals:
        //   tFrac <= 0  → no progress yet (user just earned previous tier, or metric below prevThresh);
        //                 render the full segment as dashed so the path to the next tier stays visible.
        //   tFrac (0,1) → partial: split via de Casteljau — solid fill up to progress, dashed remainder.
        //   tFrac >= 1  → metric already meets/exceeds next threshold (award may be pending);
        //                 fill the full segment in solid amber.
        let amberFillD = '', amberRemainD = '';
        if (highestEarnedIdx >= 0 && nextIdx < totalTiers) {
          const prevThresh   = thresholds[highestEarnedIdx] || 0;
          const nextThresh   = thresholds[nextIdx]          || 0;
          const segmentRange = nextThresh - prevThresh;
          const segmentRaw   = Math.max(0, barMetric - prevThresh);
          // Progress fraction within this specific segment only (clamped 0–1)
          const tFrac = segmentRange > 0
            ? Math.max(0, Math.min(1, segmentRaw / segmentRange))
            : 0;

          const fromN        = nodes[highestEarnedIdx];
          const toN          = nodes[nextIdx];
          const midY         = (fromN.y + toN.y) / 2;

          // Full-segment cubic bezier string — reused across all three tFrac cases
          const fullSegmentD = 'M' + fp_(fromN.x) + ',' + fp_(fromN.y)
            + ' C' + fp_(fromN.x) + ',' + fp_(midY)
            + ' '  + fp_(toN.x)   + ',' + fp_(midY)
            + ' '  + fp_(toN.x)   + ',' + fp_(toN.y);

          if (tFrac <= 0) {
            // No progress into this segment yet — show full remaining path as dashed
            amberRemainD = fullSegmentD;
          } else if (tFrac >= 1) {
            // Metric already exceeds the next threshold (badge award may be pending)
            // Fill the entire segment in solid amber rather than leaving a gray gap
            amberFillD = fullSegmentD;
          } else {
            // Partial progress — arc-length reparameterize before the de Casteljau split.
            // tFrac is the correct VISUAL fraction but bezier parametric-t ≠ arc-length
            // on S-curves, so passing tFrac directly overshoots visually. arcLengthParam_()
            // returns the parametric t whose arc-length matches tFrac exactly.
            const P0     = { x: fromN.x, y: fromN.y };
            const P1     = { x: fromN.x, y: midY    };
            const P2     = { x: toN.x,   y: midY    };
            const P3     = { x: toN.x,   y: toN.y   };
            const tParam = arcLengthParam_(P0, P1, P2, P3, tFrac);
            const split  = deCasteljauSubdivide_(P0, P1, P2, P3, tParam);
            amberFillD   = ptsToCubicD_(split.left);
            amberRemainD = ptsToCubicD_(split.right);
          }
        }

        // ── SVG string assembly ───────────────────────────────────────────
        // Earned nodes are rendered as HTML <img> elements layered on top of the SVG
        // (see badgeImgHtml below) so the SVG only draws paths + non-earned node circles.
        // The pulse ring for "you are here" is the sole SVG remnant for earned nodes.
        let svgPaths = ''
          // Gray background — full journey outline
          + '<path d="' + fullPathD + '" stroke="' + JRNY_GRAY_PATH + '"'
          + ' stroke-width="' + JRNY_PATH_STROKE + '" fill="none"'
          + ' stroke-linecap="round" stroke-linejoin="round"/>'
          // Purple earned section
          + (earnedPathD
            ? '<path d="' + earnedPathD + '" stroke="' + JRNY_PURPLE + '"'
              + ' stroke-width="' + JRNY_PATH_STROKE + '" fill="none"'
              + ' stroke-linecap="round" stroke-linejoin="round"/>'
            : '')
          // Amber progress fill (solid)
          + (amberFillD
            ? '<path d="' + amberFillD + '" stroke="' + JRNY_AMBER_SOLID + '"'
              + ' stroke-width="' + JRNY_PATH_STROKE + '" fill="none" stroke-linecap="round"/>'
            : '')
          // Amber remaining gap (dashed)
          + (amberRemainD
            ? '<path d="' + amberRemainD + '" stroke="' + JRNY_AMBER_DASH + '"'
              + ' stroke-width="3" fill="none" stroke-linecap="round"'
              + ' stroke-dasharray="5,4"/>'
            : '');

        // Non-earned SVG node circles (earned nodes are handled in badgeImgHtml)
        let svgNodes = '';
        nodes.forEach(function(node) {
          const nx        = node.x;
          const ny        = node.y;
          const ni        = node.idx;
          const isEarned  = (ni <= highestEarnedIdx);
          const isCurrent = (ni === highestEarnedIdx); // "you are here"
          const isNext    = (ni === nextIdx && nextIdx < totalTiers);

          if (isEarned) {
            // Only the animated pulse ring lives in SVG for earned nodes.
            // The actual badge image is rendered as an HTML element (see badgeImgHtml).
            if (isCurrent) {
              svgNodes += '<circle cx="' + nx + '" cy="' + ny + '" r="57"'
                + ' fill="none" stroke="' + JRNY_PURPLE + '"'
                + ' stroke-width="1.5" stroke-dasharray="4,3"'
                + ' class="journey-pulse-ring"/>';
            }

          } else if (isNext) {
            // Dashed amber ring with tier number — no badge image
            svgNodes += '<circle cx="' + nx + '" cy="' + ny + '" r="' + JRNY_NODE_RADIUS + '"'
              + ' fill="#FAEEDA" stroke="#BA7517" stroke-width="2" stroke-dasharray="5,3"/>';
            svgNodes += '<text x="' + nx + '" y="' + (ny + 7) + '"'
              + ' text-anchor="middle" font-size="18" fill="#BA7517"'
              + ' font-family="sans-serif" font-weight="bold">' + (ni + 1) + '</text>';

          } else {
            // Locked — extra outer ring on the final tier for visual distinction
            if (ni === totalTiers - 1) {
              svgNodes += '<circle cx="' + nx + '" cy="' + ny + '" r="49"'
                + ' fill="none" stroke="' + JRNY_GRAY_PATH + '"'
                + ' stroke-width="1" stroke-dasharray="3,4"/>';
            }
            svgNodes += '<circle cx="' + nx + '" cy="' + ny + '" r="' + JRNY_LOCKED_RADIUS + '"'
              + ' fill="#F1EFE8" stroke="#B4B2A9" stroke-width="1.5" stroke-dasharray="3,3"/>';
            svgNodes += '<text x="' + nx + '" y="' + (ny + 7) + '"'
              + ' text-anchor="middle" font-size="22" fill="#888780"'
              + ' font-family="sans-serif">?</text>';
          }
        });

        // ── Badge image elements for earned nodes ──────────────────────────
        // Absolutely positioned HTML <img> elements replace the SVG circle for each
        // earned tier. They sit in the .journey-canvas div at the same (x, y) as the
        // SVG node, offset by half the image size to centre them on the node point.
        // Each image opens openBadgeDetailSheet() on click. An emoji <div> is shown
        // as fallback when imgUrl is absent or the image fails to load.
        let badgeImgHtml = '';
        nodes.forEach(function(node) {
          const ni       = node.idx;
          const isEarned = (ni <= highestEarnedIdx);
          if (!isEarned) return; // orange and gray nodes stay as pure SVG

          const badge   = node.badge;
          const imgLeft = node.x - JRNY_NODE_RADIUS; // centre the image on node x
          const imgTop  = node.y - JRNY_NODE_RADIUS; // centre the image on node y
          const imgSrc  = badge.imgUrl
            ? badge.imgUrl.replace('sz=w400', 'sz=w200')  // w200 keeps quality on the larger 80px node
            : '';
          const borderCSS = '2px solid ' + JRNY_PURPLE_DARK;
          const baseCSS   = 'position:absolute;'
            + 'left:'   + imgLeft + 'px;'
            + 'top:'    + imgTop  + 'px;'
            + 'width:'  + JRNY_BADGE_IMG_SIZE + 'px;'
            + 'height:' + JRNY_BADGE_IMG_SIZE + 'px;'
            + 'border-radius:50%;'
            + 'border:' + borderCSS + ';'
            + 'cursor:pointer;'
            + 'background:#f0e8f5;';

          // Emoji fallback div — always present, hidden until image fails
          const fallbackDiv = '<div style="' + baseCSS
            + 'display:none;align-items:center;justify-content:center;font-size:16px;"'
            + ' onclick="openBadgeDetailSheet(\'' + badge.id + '\')">'
            + '🏅</div>';

          if (imgSrc) {
            badgeImgHtml += '<img src="' + imgSrc + '"'
              + ' style="' + baseCSS + 'object-fit:cover;"'
              + ' onclick="openBadgeDetailSheet(\'' + badge.id + '\')"'
              + ' onerror="this.style.display=\'none\';'
              + 'this.nextElementSibling.style.display=\'flex\';">'
              + fallbackDiv;
          } else {
            // No imgUrl: show emoji circle immediately
            badgeImgHtml += '<div style="' + baseCSS
              + 'display:flex;align-items:center;justify-content:center;font-size:16px;"'
              + ' onclick="openBadgeDetailSheet(\'' + badge.id + '\')">'
              + '🏅</div>';
          }
        });

        // ── Tier card HTML ────────────────────────────────────────────────

        /**
         * Formats a large threshold number as a compact label: 25000 → "25K", 1000000 → "1M".
         * Keeps threshold text short inside the narrow journey cards.
         * @param {number} n
         * @returns {string}
         */
        function fmtThreshold_(n) {
          if (n >= 1000000) return (n / 1000000) + 'M';
          if (n >= 1000)    return (n / 1000)    + 'K';
          return String(n);
        }

        let cardsHtml = '';
        nodes.forEach(function(node) {
          const badge     = node.badge;
          const ni        = node.idx;
          const y         = node.y;
          const isLeft    = node.isLeft;
          const isEarned  = (ni <= highestEarnedIdx);
          const isNext    = (ni === nextIdx && nextIdx < totalTiers);
          const isCurrent = (ni === highestEarnedIdx);
          const isLast    = (ni === totalTiers - 1);

          // Absolute position: left or right edge, vertically centred on the node
          // Badge and card are now on OPPOSITE sides of the canvas.
          // Badge left (even tier) → info card on right. Badge right (odd tier) → card on left.
          const cardPos = isLeft
            ? 'right:' + JRNY_CARD_INSET + 'px;top:' + y + 'px;'  // badge on left → card on right
            : 'left:'  + JRNY_CARD_INSET + 'px;top:' + y + 'px;'; // badge on right → card on left

          const cardClass = 'journey-card '
            + (isEarned ? 'jc-earned' : isNext ? 'jc-next' : 'jc-locked');
          const tierNum = badge.badgeTier || (ni + 1);
          let cardContent = '';

          if (isEarned) {
            const award     = earnedAwards.find(function(a) { return a.badgeId === badge.id; });
            const awardDate = award ? award.awardedDate : '';
            // badgePoints is on the badge definition, not the award record.
            const ap        = badge.badgePoints || 0;
            cardContent = '<div class="jc-tier-label jctl-earned">TIER ' + tierNum
                + (isCurrent ? ' \u00b7 NOW' : '') + '</div>'
              + '<div class="jc-name jcn-earned">' + escapeHtml(badge.caption) + '</div>'
              + (awardDate ? '<div class="jc-date">'  + awardDate              + '</div>' : '')
              + (ap        ? '<div class="jc-ap">'    + ap.toLocaleString() + ' \u2600\ufe0f</div>' : '');

          } else if (isNext) {
            // Immediately next tier is fully revealed — it is the concrete target.
            // All tiers beyond it stay as "A surprise".
            const nextThresh  = thresholds[ni] || 0;
            const prevThresh  = highestEarnedIdx >= 0 ? (thresholds[highestEarnedIdx] || 0) : 0;
            // Percentage is computed absolutely (barMetric vs nextThresh) so it
            // matches the "X / Y weeks" label already shown on the card.
            // Segment-relative math (used for the SVG amber path) is intentionally
            // not applied here — it produced wrong values when barMetric falls
            // below prevThresh (e.g. a broken streak rebuilding from 0).
            const pct = nextThresh > 0
              ? Math.min(100, Math.round((barMetric / nextThresh) * 100))
              : 0;
            const apOnUnlock  = badge.badgePoints || 0;
            cardContent = '<div class="jc-tier-label jctl-next">TIER ' + tierNum + ' \u00b7 NEXT</div>'
              + '<div class="jc-name jcn-next">' + escapeHtml(badge.caption) + '</div>'
              + '<div class="jc-progress-label">'
                + barMetric.toLocaleString() + ' / ' + nextThresh.toLocaleString()
                + (metricLabel ? ' ' + metricLabel : '') + '</div>'
              + '<div class="jc-prog-bar">'
                + '<div class="jc-prog-fill" style="width:' + pct + '%"></div></div>'
              + '<div class="jc-prog-pct">' + pct + '% \u00b7 '
                + apOnUnlock.toLocaleString() + ' \u2600\ufe0f on unlock</div>';

          } else {
            // Locked — vague by design to preserve discovery excitement
            cardContent = '<div class="jc-tier-label jctl-locked">TIER ' + tierNum
                + (isLast ? ' \u00b7 FINAL' : '') + '</div>'
              + '<div class="jc-name jcn-locked">A surprise</div>'
              + '<div class="jc-mystery">'
                + (isLast ? 'For the truly devoted' : 'Unlock the previous tier')
              + '</div>';
          }

          cardsHtml += '<div class="' + cardClass + '" style="' + cardPos + '">'
            + cardContent + '</div>';
        });

        // ── Assemble and inject overlay HTML ──────────────────────────────
        const overlayHtml = `
          <div class="journey-header">
            <button class="btn-back-circle btn-back-circle--dark" onclick="closeJourneyView_()" aria-label="Go back"><i class="fa-solid fa-chevron-left" style="font-size:11px;"></i></button>
            <div class="journey-title">${conf.icon}&nbsp;${isGenreSubJourney ? genreFilter : conf.label}</div>
            <div class="journey-subtitle">Your journey</div>
          </div>

          <div class="journey-summary-bar">
            <div>
              <div class="journey-stat-val">${earnedCount}</div>
              <div class="journey-stat-lbl">Earned</div>
            </div>
            <div class="journey-stat-divider"></div>
            <div>
              <div class="journey-stat-val">${totalTiers}</div>
              <div class="journey-stat-lbl">Total tiers</div>
            </div>
            <div class="journey-stat-divider"></div>
            <div>
              <div class="journey-stat-val" style="font-size:0.85rem;">${barMetric.toLocaleString()}</div>
              <div class="journey-stat-lbl">${metricLabel}</div>
            </div>
            <div class="journey-stat-divider"></div>
            <div>
              <div class="journey-stat-val" style="font-size:0.85rem;">${totalEarnedAp.toLocaleString()}&nbsp;&#x2600;&#xfe0f;</div>
              <div class="journey-stat-lbl">AP earned</div>
            </div>
          </div>

          <div class="journey-scroll-area" id="journeyScrollArea">
            <div class="journey-canvas"
                 style="width:${JRNY_SVG_WIDTH}px;height:${svgHeight}px;">
              <svg width="${JRNY_SVG_WIDTH}" height="${svgHeight}"
                   style="position:absolute;top:0;left:0;" overflow="visible">
                ${svgPaths}
                ${svgNodes}
              </svg>
              ${badgeImgHtml}
              ${cardsHtml}
            </div>
          </div>`;

        // Reuse existing overlay div to avoid accumulating DOM nodes across opens
        let overlay = document.getElementById('badgeJourneyOverlay');
        if (!overlay) {
          overlay = document.createElement('div');
          overlay.id = 'badgeJourneyOverlay';
          document.body.appendChild(overlay);
        }
        overlay.innerHTML = overlayHtml;
        overlay.classList.add('journey-open');

        // Auto-scroll to place the current earned node roughly in the viewport centre.
        // Guard: only scroll if past Tier 2 so short journeys don't feel over-scrolled.
        if (highestEarnedIdx > 1) {
          setTimeout(function() {
            const scrollArea = document.getElementById('journeyScrollArea');
            if (scrollArea) {
              const nodeAbsY  = JRNY_Y_START + highestEarnedIdx * JRNY_Y_STEP;
              const targetTop = nodeAbsY - (scrollArea.clientHeight / 2);
              scrollArea.scrollTop = Math.max(0, targetTop);
            }
          }, 80);
        }
      }


      /**
       * Hides the Badge Journey overlay.
       * Removes the .journey-open class; the overlay div is kept in the DOM
       * so it can be recycled by the next openBadgeJourneyView_() call.
       */
      function closeJourneyView_() {
        const overlay = document.getElementById('badgeJourneyOverlay');
        if (overlay) overlay.classList.remove('journey-open');
      }


      /**
       * Builds a single badge card for the gallery grid.
       * Earned cards are full-colour; unearned cards are dim with a dashed ring.
       *
       * @param   {Object}      badge     - Badge object from badgesMap
       * @param   {boolean}     isLocked  - True = unearned, render dim
       * @param   {Object|null} award     - Award record if earned, otherwise null
       * @returns {string} HTML string
       */
      function buildGalleryBadgeCardHtml(badge, isLocked, award) {
        const size        = 64;
        const opacity     = isLocked ? '0.38' : '1';
        const borderStyle = isLocked ? '3px dashed var(--neutral-mid)' : '3px solid var(--arka-accent)';
      
        // Swap Drive thumbnail sz parameter for gallery size
        const imgSrc = badge.imgUrl ? badge.imgUrl.replace('sz=w400', 'sz=w100') : '';
      
        const imgHtml = imgSrc
          ? `<img src="${imgSrc}"
                  style="width:${size}px; height:${size}px; border-radius:50%; object-fit:cover;
                        border:${borderStyle}; margin-bottom:8px; display:block;"
                  onerror="this.style.display='none'; this.nextElementSibling.style.display='flex';">
            <div style="display:none; width:${size}px; height:${size}px; border-radius:50%;
                        background:#f0e8f5; border:${borderStyle}; align-items:center;
                        justify-content:center; font-size:1.8rem; margin-bottom:8px;">🏅</div>`
          : `<div style="width:${size}px; height:${size}px; border-radius:50%; background:#f0e8f5;
                        border:${borderStyle}; display:flex; align-items:center;
                        justify-content:center; font-size:1.8rem; margin-bottom:8px;">🏅</div>`;
      
        const awardDateHtml = award
          ? `<div style="font-size:0.68rem; color:var(--color-warning); margin-top:2px;">${award.awardedDate}</div>`
          : '';
      
        return `
          <div style="display:flex; flex-direction:column; align-items:center; cursor:pointer;
                      opacity:${opacity}; width:90px; text-align:center;"
              onclick="openBadgeDetailSheet('${badge.id}')">
            ${imgHtml}
            <div style="font-size:0.82rem; font-weight:500; color:var(--text-strong); line-height:1.2;
                        display:-webkit-box; -webkit-line-clamp:2; -webkit-box-orient:vertical;
                        overflow:hidden; width:100%;">
              ${badge.caption}
            </div>
            ${awardDateHtml}
          </div>
        `;
      }

      /**
       * renderMeCoachCard()
       *
       * Renders the Arka Coach section in the Me tab from a pre-parsed
       * coachInsights object (MemberDB Col S, parsed by buildMembersList_).
       *
       * Renders three stacked sections:
       *   1. Insight chips  — behavioural observations (existing).
       *   2. Task cards     — actionable prompts (new). Max COACH_TASKS_MAX_DISPLAY.
       *   3. AI advice card — nightly Gemini narrative (existing, future pass).
       *
       * Task completion is event-driven: _doSubmitShelfUpdate() dispatches
       * 'arkaCoachTaskResolved' after any successful shelf save. The listener
       * registered here marks the matching task card green/checked immediately
       * and writes sessionStorage so the state survives same-session tab switches.
       *
       * Called once at Wave 1 load time — no re-render on tab switch.
       *
       * @param {Object|null} coachInsights - Parsed Col S JSON or null.
       */
      /**
       * Session cache of the last coachInsights payload passed to renderMeCoachCard().
       * Read by renderMeActionBand() to pull the top unresolved task for the band.
       * Null until Wave 1 loads the member record.
       */
      let meCoachInsightsCache = null;
      /** Scroll position saved when insights view opens; restored on back. */
      // _insightsFromScrollY removed — insightsView now uses navPush/navPop (System A).
      // Scroll restoration is handled by navPop; the variable is no longer needed.

      // ── ONBOARDING STATE ─────────────────────────────────────────────────────
      /** ID of the chapter row currently expanded in the onboarding card.
       *  '__none__' = all chapters collapsed (default start state).
       *  null would auto-open the first active chapter on first paint — intentionally avoided. */
      let _onboardOpenChapterId = '__none__';
      /** When true, the dismiss-warning overlay is rendered inside the card. Cleared on keep or confirm. */
      let _onboardShowDismissWarn = false;

      /**
       * computeOnboardingTaskStates()
       *
       * Pure function. Derives a Map<taskId, boolean> for every task in
       * ONBOARD_CHAPTERS using the best available data source per task.
       *
       * Detection source priority:
       *
       *   T01 (Join)      — always true for any authenticated member.
       *   T09 (Library)   — globalBooksDB.addedByRaw (Wave 3, all-time) with
       *                     activity log fallback.
       *   T10–T11, T14–T16 (shelf tasks) — globalShelvesDB (Wave 3, all-time)
       *                     with activity log fallback.
       *   T12 (linked read) — globalMyPageLogDB where bookId is populated
       *                     (Wave 3b, all-time personal) with activity log fallback.
       *   T13 (unlinked)  — globalMyPageLogDB where bookId is blank
       *                     (Wave 3b, all-time personal) with activity log fallback.
       *   All other auto  — globalActivityLogDB only (Wave 2, 2000-row window).
       *   Self-reported   — selfReportedSet from Col S onboarding.selfReported[].
       *
       * Safe to call at any wave: shelf/books/pageLog globals are empty arrays before
       * their wave loads, so the activity log fallback covers the Wave 2 render pass.
       * Wave 3 and 3b re-renders correct anything the fallback missed.
       *
       * @param  {string[]} selfReportedIds - Confirmed self-reported task IDs from Col S.
       * @returns {Map<string, boolean>}       taskId → true if done.
       */
      function computeOnboardingTaskStates(selfReportedIds) {
        var selfReportedSet = new Set(Array.isArray(selfReportedIds) ? selfReportedIds : []);

        // ── Activity log: pre-filter to current user once ────────────────────
        // Capped at 2000 rows newest-first. Sufficient for recent actions;
        // older actions are covered by the shelf / library / page-log fallbacks.
        var myActivityLog = globalActivityLogDB.filter(function(a) {
          return (a.activityMemberID || '') === currentUser;
        });

        // ── Shelf DB: current user's non-deleted records (Wave 3, all-time) ──
        var myNonDeletedShelves = globalShelvesDB.filter(function(s) {
          return s.memberId === currentUser && s.status !== 'Deleted';
        });
        var hasAnyShelf      = myNonDeletedShelves.length > 0;
        var hasReadingShelf  = myNonDeletedShelves.some(function(s) {
          return s.status === 'Reading' || s.status === 'Finished';
        });
        var hasFinishedShelf = myNonDeletedShelves.some(function(s) {
          return s.status === 'Finished';
        });
        var hasRatedShelf    = myNonDeletedShelves.some(function(s) {
          return Number(s.rating) > 0;
        });
        var hasReviewedShelf = myNonDeletedShelves.some(function(s) {
          return (s.review || '').trim().length > 0;
        });

        // ── Library DB: books this member added (Wave 3, all-time) ───────────
        var hasAddedLibraryBook = globalBooksDB.some(function(b) {
          return b.addedByRaw === currentUser;
        });

        // ── Page log DB: current user's all-time personal logs (Wave 3b) ─────
        var myPageLogs = globalMyPageLogDB.filter(function(l) {
          return l.memberId === currentUser;
        });
        var hasLinkedPageLog = myPageLogs.some(function(l) {
          return l.bookId && l.bookId.toString().indexOf('ARKA_BOOK_') === 0;
        });
        var hasUnlinkedPageLog = myPageLogs.some(function(l) {
          return !l.bookId || l.bookId.toString().trim() === '';
        });

        var taskStates = new Map();

        ONBOARD_CHAPTERS.forEach(function(chapter) {
          chapter.tasks.forEach(function(task) {
            var isDone = false;

            if (task.id === 'ONBOARD_T01') {
              // Always true — being logged in proves the member joined.
              isDone = true;

            } else if (task.type === 'self') {
              isDone = selfReportedSet.has(task.id);

            } else {
              // ── Auto tasks — richest available source per task ID ──────────
              switch (task.id) {

                case 'ONBOARD_T09': // Add a new book to the Library
                  isDone = hasAddedLibraryBook
                        || myActivityLog.some(function(a) {
                             return a.activityTypeID === 'ARKA_ACTTYP_BOOKADDED';
                           });
                  break;

                case 'ONBOARD_T10': // Add a book to To Read shelf
                  isDone = hasAnyShelf
                        || myActivityLog.some(function(a) {
                             return a.activityTypeID === 'ARKA_ACTTYP_BOOKTOREAD';
                           });
                  break;

                case 'ONBOARD_T11': // Start reading a book
                  isDone = hasReadingShelf
                        || myActivityLog.some(function(a) {
                             return a.activityTypeID === 'ARKA_ACTTYP_BOOKREADING';
                           });
                  break;

                case 'ONBOARD_T12': // Log reading in a book (linked session)
                  // globalMyPageLogDB is all-time personal data — no row cap.
                  // bookId populated with ARKA_BOOK_X = session was tied to a book.
                  isDone = hasLinkedPageLog
                        || myActivityLog.some(function(a) {
                             if (a.activityTypeID !== 'ARKA_ACTTYP_PAGEREAD') return false;
                             return (a.activityDesc || '').indexOf('unlinked') === -1;
                           });
                  break;

                case 'ONBOARD_T13': // Log reading without a book (unlinked session)
                  // bookId blank or absent = freeform / material session.
                  isDone = hasUnlinkedPageLog
                        || myActivityLog.some(function(a) {
                             if (a.activityTypeID !== 'ARKA_ACTTYP_PAGEREAD') return false;
                             return (a.activityDesc || '').indexOf('unlinked') !== -1;
                           });
                  break;

                case 'ONBOARD_T14': // Finish reading a book
                  isDone = hasFinishedShelf
                        || myActivityLog.some(function(a) {
                             return a.activityTypeID === 'ARKA_ACTTYP_BOOKREAD';
                           });
                  break;

                case 'ONBOARD_T15': // Rate a finished book
                  isDone = hasRatedShelf
                        || myActivityLog.some(function(a) {
                             return a.activityTypeID === 'ARKA_ACTTYP_BOOKRATING';
                           });
                  break;

                case 'ONBOARD_T16': // Write a review
                  isDone = hasReviewedShelf
                        || myActivityLog.some(function(a) {
                             return a.activityTypeID === 'ARKA_ACTTYP_BOOKREVIEW';
                           });
                  break;

                default:
                  // All remaining auto tasks — activity log only.
                  isDone = myActivityLog.some(function(a) {
                    return a.activityTypeID === task.activityTypeId;
                  });
              }
            }

            taskStates.set(task.id, isDone);
          });
        });

        return taskStates;
      }

      /**
       * getOnboardingChapterSummary()
       *
       * Wraps computeOnboardingTaskStates(). Reads selfReported IDs from
       * meCoachInsightsCache (available from Wave 1 onward). Returns the full
       * chapter structure enriched with per-task isDone booleans and per-chapter
       * aggregate counts, ready for the renderer to consume directly.
       *
       * Chapters unlock sequentially: a chapter's state is 'done', 'active', or
       * 'locked' based on whether the previous chapter is fully complete.
       *
       * @returns {Array<OnboardingChapterSummary>} One object per chapter:
       *   { id, title, badgeLabel, badgePts, tasks[], doneCount, totalCount,
       *     allDone, state: 'done'|'active'|'locked' }
       */
      function getOnboardingChapterSummary() {
        var selfReportedIds = (meCoachInsightsCache &&
                               meCoachInsightsCache.onboarding &&
                               Array.isArray(meCoachInsightsCache.onboarding.selfReported))
                              ? meCoachInsightsCache.onboarding.selfReported
                              : [];

        var taskStates            = computeOnboardingTaskStates(selfReportedIds);
        var previousChapterAllDone = true; // Chapter 1 is always unlocked

        return ONBOARD_CHAPTERS.map(function(chapter) {
          var tasks = chapter.tasks.map(function(task) {
            return {
              id           : task.id,
              label        : task.label,
              type         : task.type,
              helpArticleId: task.helpArticleId,
              isDone       : taskStates.get(task.id) || false
            };
          });

          var doneCount  = tasks.filter(function(t) { return t.isDone; }).length;
          var totalCount = tasks.length;
          var allDone    = doneCount === totalCount;
          var unlocked   = previousChapterAllDone;
          var state      = allDone ? 'done' : (unlocked ? 'active' : 'locked');

          previousChapterAllDone = allDone;

          return {
            id        : chapter.id,
            title     : chapter.title,
            badgeLabel: chapter.badgeLabel,
            badgePts  : chapter.badgePts,
            tasks     : tasks,
            doneCount : doneCount,
            totalCount: totalCount,
            allDone   : allDone,
            state     : state
          };
        });
      }

      /**
       * renderOnboardingCard()
       *
       * Renders the "Your Onboarding" journey card into #meOnboardingCard and
       * makes it visible. If the member has dismissed the card (onboarding.dismissed
       * === true in Col S), the container is hidden and the function returns early.
       *
       * Called twice per session:
       *   1. From applyWave1() — uses selfReported data only (ActivityLog not yet
       *      loaded). Auto tasks appear unchecked in this pass; corrected by Wave 2.
       *   2. From applyWave2() — full detection pass; all auto tasks resolved.
       *
       * Safe to call at any time — fully idempotent, re-renders from scratch.
       *
       * Reads:  meCoachInsightsCache, _onboardOpenChapterId, _onboardShowDismissWarn,
       *         ONBOARD_CHAPTERS, globalActivityLogDB, currentUser
       * Writes: #meOnboardingCard innerHTML + display style
       */
      function renderOnboardingCard() {
        var cardEl = document.getElementById('meOnboardingCard');
        if (!cardEl) return;

        // ── Guard: Wave 1 must have completed before this function is safe to run.
        // meCoachInsightsCache (and its dismissed flag) is only populated by
        // populateMePage(), which is called inside applyWave1(). If a later wave
        // (e.g. Wave 2 or Wave 3b) arrives before Wave 1 and calls this function,
        // the null cache would cause dismissed to read as undefined — showing the
        // card falsely for a dismissed member, producing a visible flicker before
        // Wave 1 corrects it. applyWave1() always calls renderOnboardingCard()
        // after populating the cache, so returning early here is safe.
        if (!isAppDataLoaded) return;

        // ── Guard: dismissed flag ────────────────────────────────────────────
        var onboardState = (meCoachInsightsCache && meCoachInsightsCache.onboarding &&
                            typeof meCoachInsightsCache.onboarding === 'object')
                           ? meCoachInsightsCache.onboarding : {};
        if (onboardState.dismissed === true) {
          cardEl.style.display = 'none';
          return;
        }

        // ── Icon map — UI concern kept out of the frozen ONBOARD_CHAPTERS spec ──
        var OB_CHAPTER_ICON = {
          'ONBOARD_CH1': 'fa-solid fa-rocket',
          'ONBOARD_CH2': 'fa-solid fa-book',
          'ONBOARD_CH3': 'fa-solid fa-book-open-reader',
          'ONBOARD_CH4': 'fa-solid fa-compass',
          'ONBOARD_CH5': 'fa-solid fa-users-rectangle'
        };

        // ── Compute chapter and task states ───────────────────────────────────
        var chapters     = getOnboardingChapterSummary();
        var totalTasks   = chapters.reduce(function(s, c) { return s + c.totalCount; }, 0);
        var doneTasks    = chapters.reduce(function(s, c) { return s + c.doneCount; }, 0);
        var doneChapters = chapters.filter(function(c) { return c.allDone; });
        var allComplete  = chapters.every(function(c) { return c.allDone; });
        var pct          = totalTasks > 0 ? Math.round((doneTasks / totalTasks) * 100) : 0;

        // Determine the default open chapter: respect _onboardOpenChapterId if it
        // still points at a valid active/done chapter; otherwise auto-open the
        // first active chapter so the member always lands somewhere actionable.
        var validOpenId = null;
        if (_onboardOpenChapterId && _onboardOpenChapterId !== '__none__') {
          // User previously opened a specific chapter — honour it if still valid.
          var matchesCurrent = chapters.some(function(c) { return c.id === _onboardOpenChapterId; });
          if (matchesCurrent) validOpenId = _onboardOpenChapterId;
        }
        // Auto-open the first active chapter only on initial render (null = never interacted).
        // '__none__' means the user explicitly collapsed — respect that and show all closed.
        if (!validOpenId && _onboardOpenChapterId === null) {
          var firstActive = chapters.find(function(c) { return c.state === 'active'; });
          validOpenId = firstActive ? firstActive.id : null;
        }

        var html = '';

        // ═══════════════════════════════════════════════════════════════════════
        // ALL-COMPLETE STATE
        // ═══════════════════════════════════════════════════════════════════════
        if (allComplete) {
          var totalPts = chapters.reduce(function(s, c) { return s + c.badgePts; }, 0);
          html += '<div class="ob-complete-banner">'
                +   '<i class="fa-solid fa-trophy" style="font-size:24px;color:var(--color-success);display:block;margin-bottom:6px;"></i>'
                +   '<div style="font-size:13px;font-weight:700;color:#085041;">Onboarding complete!</div>'
                +   '<div style="font-size:10px;color:#0F6E56;margin-top:2px;">'
                +     chapters.length + ' badges earned &middot; ' + totalPts + ' club points'
                +   '</div>'
                + '</div>'
                + '<div class="ob-complete-badges">';
          chapters.forEach(function(ch) {
            html += '<div class="ob-complete-badge-cell">'
                  +   '<div class="ob-complete-badge-icon">'
                  +     '<i class="' + (OB_CHAPTER_ICON[ch.id] || 'fa-solid fa-award') + '"></i>'
                  +   '</div>'
                  +   '<div style="font-size:8px;color:#3C3489;text-align:center;line-height:1.3;">'
                  +     escapeHtml(ch.title)
                  +   '</div>'
                  + '</div>';
          });
          html += '</div>'
                + '<div style="padding:8px;text-align:center;border-top:0.5px solid var(--border-soft);">'
                +   '<span style="font-size:10px;color:var(--text-muted);cursor:pointer;" '
                +         'onclick="_onboardDismissCompleted()">'
                +     'Dismiss &nbsp;<i class="fa-solid fa-xmark" style="font-size:10px;"></i>'
                +   '</span>'
                + '</div>';

        // ═══════════════════════════════════════════════════════════════════════
        // IN-PROGRESS STATE
        // ═══════════════════════════════════════════════════════════════════════
        } else {

          // ── Card header ────────────────────────────────────────────────────
          // Precompute subtitle — avoids operator precedence collision between + and ?: 
          // inside the html concatenation chain below. allComplete is false in this
          // else branch so the first clause is never needed here; kept explicit for clarity.
          var obSubtitle = doneChapters.length > 0
            ? (doneChapters.length + ' of 5 chapters done \u2014 keep going!')
            : 'Complete chapters to earn badges and club points';

          html += '<div class="ob-header">'
                +   '<div class="ob-header-left">'
                +     '<div class="ob-title-row">'
                +       '<i class="fa-solid fa-list-check" style="font-size:13px;color:rgba(255,255,255,0.9);"></i>'
                +       ' Your Onboarding'
                +       ' <span class="ob-q-btn" onclick="openHelpArticle(\'help-onboarding\')" '
                +              'title="What is this?">?</span>'
                +     '</div>'
                +     '<div style="font-size:0.68rem;color:rgba(255,255,255,0.65);margin-top:4px;font-weight:500;">'
                +       obSubtitle
                +     '</div>'
                +     '<div class="ob-prog-track">'
                +       '<div class="ob-prog-fill" style="width:' + pct + '%;"></div>'
                +     '</div>'
                +   '</div>'
                +   '<div class="ob-header-right">'
                +     '<span class="ob-count-label">' + doneTasks + ' / ' + totalTasks + '</span>'
                +     '<span class="ob-dismiss-btn" onclick="_onboardDismissClick()" '
                +           'title="Remove onboarding card">'
                +       '<i class="fa-solid fa-xmark"></i>'
                +     '</span>'
                +   '</div>'
                + '</div>';

          // ── Done chapters summary strip ────────────────────────────────────
          if (doneChapters.length > 0) {
            var earnedPts = doneChapters.reduce(function(s, c) { return s + c.badgePts; }, 0);
            html += '<div class="ob-done-strip">'
                  +   '<i class="fa-solid fa-circle-check" style="color:var(--color-success);font-size:12px;"></i>'
                  +   '<span class="ob-done-pill">'
                  +     '<i class="fa-solid fa-award" style="font-size:9px;"></i>'
                  +     ' ' + doneChapters.length
                  +     ' badge' + (doneChapters.length > 1 ? 's' : '') + ' earned'
                  +   '</span>'
                  +   '<span>'
                  +     doneChapters.length + ' chapter' + (doneChapters.length > 1 ? 's' : '') + ' complete'
                  +   '</span>'
                  + '</div>';
          }

          // ── Chapter rows ──────────────────────────────────────────────────
          var lockedCount = chapters.filter(function(c) { return c.state === 'locked'; }).length;
          var lockedRowRendered = false;

          chapters.forEach(function(ch) {
            var icon = OB_CHAPTER_ICON[ch.id] || 'fa-solid fa-book';
            var isOpen = (ch.id === validOpenId);

            // ── DONE chapter ───────────────────────────────────────────────
            if (ch.state === 'done') {
              html += '<div class="ob-chapter-row">'
                    +   '<div class="ob-chapter-hdr ob-chapter-hdr-done" '
                    +        'onclick="toggleOnboardingChapter(\'' + ch.id + '\')">'
                    +     '<div class="ob-chapter-left">'
                    +       '<div class="ob-chapter-ico ob-chapter-ico-done">'
                    +         '<i class="' + icon + '" style="color:var(--color-success);"></i>'
                    +       '</div>'
                    +       '<div>'
                    +         '<div class="ob-chapter-title-muted">' + escapeHtml(ch.title) + '</div>'
                    +         '<div class="ob-chapter-sub">'
                    +           ch.totalCount + '/' + ch.totalCount + ' done'
                    +         '</div>'
                    +       '</div>'
                    +     '</div>'
                    +     '<span class="ob-badge-earned-pill">'
                    +       '<i class="fa-solid fa-award" style="font-size:9px;"></i> Badge earned'
                    +     '</span>'
                    +   '</div>';

              // Expand done chapter if tapped (shows all tasks struck-through)
              if (isOpen) {
                html += '<div class="ob-task-list" onclick="event.stopPropagation();">';
                ch.tasks.forEach(function(t) {
                  html += '<div class="ob-task-row">'
                        +   '<div class="ob-task-check ob-task-check-done">'
                        +     '<i class="fa-solid fa-check"></i>'
                        +   '</div>'
                        +   '<div class="ob-task-body">'
                        +     '<div class="ob-task-label-done">' + escapeHtml(t.label) + '</div>'
                        +   '</div>'
                        + '</div>';
                });
                html += '</div>';
              }
              html += '</div>'; // .ob-chapter-row

            // ── ACTIVE chapter ─────────────────────────────────────────────
            } else if (ch.state === 'active') {
              var chevron = isOpen ? 'fa-chevron-up' : 'fa-chevron-down';
              html += '<div class="ob-chapter-row">'
                    +   '<div class="ob-chapter-hdr" '
                    +        'onclick="toggleOnboardingChapter(\'' + ch.id + '\')">'
                    +     '<div class="ob-chapter-left">'
                    +       '<div class="ob-chapter-ico ob-chapter-ico-active">'
                    +         '<i class="' + icon + '" style="color:var(--color-challenge);"></i>'
                    +       '</div>'
                    +       '<div>'
                    +         '<div class="ob-chapter-title">' + escapeHtml(ch.title) + '</div>'
                    +         '<div class="ob-chapter-sub">'
                    +           ch.doneCount + ' of ' + ch.totalCount + ' done'
                    +         '</div>'
                    +       '</div>'
                    +     '</div>'
                    +     '<i class="fa-solid ' + chevron + '" '
                    +        'style="font-size:11px;color:var(--text-muted);"></i>'
                    +   '</div>';

              if (isOpen) {
                html += '<div class="ob-task-list" onclick="event.stopPropagation();">';
                ch.tasks.forEach(function(t) {
                  if (t.isDone) {
                    // Completed task
                    html += '<div class="ob-task-row">'
                          +   '<div class="ob-task-check ob-task-check-done">'
                          +     '<i class="fa-solid fa-check"></i>'
                          +   '</div>'
                          +   '<div class="ob-task-body">'
                          +     '<div class="ob-task-label-done">' + escapeHtml(t.label) + '</div>'
                          +   '</div>'
                          + '</div>';
                  } else if (t.type === 'self') {
                    // Self-reported task — not done
                    html += '<div class="ob-task-row">'
                          +   '<div class="ob-task-check ob-task-check-self" '
                          +        'onclick="event.stopPropagation();confirmOnboardSelfTask(\'' + t.id + '\')" '
                          +        'title="Mark as done">'
                          +   '</div>'
                          +   '<div class="ob-task-body">'
                          +     '<div class="ob-task-label">' + escapeHtml(t.label) + '</div>'
                          +     '<span class="ob-task-help" '
                          +           'onclick="event.stopPropagation();openHelpArticle(\'' + t.helpArticleId + '\')">'
                          +       '<i class="fa-solid fa-book-open" style="font-size:9px;"></i>'
                          +       ' Read how to do this'
                          +     '</span>'
                          +     '<span class="ob-task-self-confirm" '
                          +           'onclick="event.stopPropagation();confirmOnboardSelfTask(\'' + t.id + '\')">'
                          +       '&#10003; Mark as done once you have done this'
                          +     '</span>'
                          +   '</div>'
                          + '</div>';
                  } else {
                    // Auto-detected task — not done yet
                    html += '<div class="ob-task-row">'
                          +   '<div class="ob-task-check ob-task-check-todo"></div>'
                          +   '<div class="ob-task-body">'
                          +     '<div class="ob-task-label">' + escapeHtml(t.label) + '</div>'
                          +     '<span class="ob-task-help" '
                          +           'onclick="event.stopPropagation();openHelpArticle(\'' + t.helpArticleId + '\')">'
                          +       '<i class="fa-solid fa-book-open" style="font-size:9px;"></i>'
                          +       ' Read how to do this'
                          +     '</span>'
                          +   '</div>'
                          + '</div>';
                  }
                });
                html += '</div>'; // .ob-task-list

                // Badge unlock preview
                html += '<div class="ob-badge-preview">'
                      +   '<div class="ob-badge-thumb-locked">'
                      +     '<i class="fa-solid fa-lock" style="font-size:11px;color:var(--text-muted);"></i>'
                      +   '</div>'
                      +   '<div>'
                      +     '<div style="font-size:10px;font-weight:600;color:#3C3489;">'
                      +       escapeHtml(ch.badgeLabel)
                      +     '</div>'
                      +     '<div style="font-size:9px;color:var(--color-challenge);margin-top:1px;">'
                      +       ch.badgePts + ' pts when complete'
                      +     '</div>'
                      +   '</div>'
                      + '</div>';
              }
              html += '</div>'; // .ob-chapter-row

            // ── LOCKED chapters — single aggregated row ────────────────────
            } else if (ch.state === 'locked' && !lockedRowRendered) {
              lockedRowRendered = true;
              html += '<div class="ob-chapter-row">'
                    +   '<div class="ob-chapter-hdr ob-chapter-hdr-locked">'
                    +     '<div class="ob-chapter-left">'
                    +       '<div class="ob-chapter-ico ob-chapter-ico-locked">'
                    +         '<i class="fa-solid fa-lock" style="font-size:12px;color:var(--text-muted);"></i>'
                    +       '</div>'
                    +       '<div>'
                    +         '<div class="ob-chapter-title-muted">'
                    +           lockedCount + ' more chapter' + (lockedCount > 1 ? 's' : '') + ' to go'
                    +         '</div>'
                    +         '<div class="ob-chapter-sub">Finish previous chapters to unlock</div>'
                    +       '</div>'
                    +     '</div>'
                    +   '</div>'
                    + '</div>';
            }
            // Subsequent locked chapters are intentionally skipped — only one
            // aggregated row is shown, controlled by the lockedRowRendered flag.
          });
        } // end in-progress state

        // ── Inject HTML and show container ────────────────────────────────────
        cardEl.innerHTML = html;
        cardEl.style.display = 'block';

        // ── Dismiss warning overlay (shown on top when flag is active) ─────────
        if (_onboardShowDismissWarn) {
          var warnHtml = '<div class="ob-warn-overlay" onclick="event.stopPropagation();">'
                       +   '<div class="ob-warn-sheet">'
                       +     '<div class="ob-warn-title">'
                       +       '<i class="fa-solid fa-triangle-exclamation" '
                       +          'style="color:#BA7517;font-size:12px;margin-right:4px;"></i>'
                       +       'Remove onboarding?'
                       +     '</div>'
                       +     '<div class="ob-warn-body">'
                       +       'Your checklist isn\'t complete yet. You can relaunch it anytime '
                       +       'from Help &mdash; search &ldquo;Onboarding&rdquo; or tap the '
                       +       '<strong>?</strong> icon on this card.'
                       +     '</div>'
                       +     '<div class="ob-warn-btns">'
                       +       '<div class="ob-warn-btn-keep" role="button" tabindex="0" data-action onclick="_onboardKeepIt()">Keep it</div>'
                       +       '<div class="ob-warn-btn-remove" role="button" tabindex="0" data-action onclick="confirmOnboardingDismiss()">Remove it</div>'
                       +     '</div>'
                       +   '</div>'
                       + '</div>';
          cardEl.insertAdjacentHTML('beforeend', warnHtml);
        }
      }

      // ── ONBOARDING INTERACTION HANDLERS ──────────────────────────────────────
      // All write operations are optimistic: local state is updated first,
      // renderOnboardingCard() re-runs immediately, and the Col S write is
      // fire-and-forget (same pattern as markCoachTaskComplete). If a write is
      // lost the member loses at most one checkbox tick — the nightly sync is
      // the backstop.

      /**
       * toggleOnboardingChapter()
       *
       * Expands the tapped chapter row. If the chapter is already open, collapses
       * it (null → renderer auto-selects the first active chapter next paint).
       * Done chapters expand to show their completed task list for review.
       * No server call — purely local UI state.
       *
       * @param {string} chapterId - ONBOARD_CHX identifier of the tapped row.
       */
      function toggleOnboardingChapter(chapterId) {
        // '__none__' is the explicit-collapse sentinel — distinct from null (initial state).
        // null → renderer auto-opens the first active chapter on first paint.
        // '__none__' → user tapped to collapse; renderer respects that and opens nothing.
        _onboardOpenChapterId = (_onboardOpenChapterId === chapterId) ? '__none__' : chapterId;
        renderOnboardingCard();
      }

      /**
       * confirmOnboardSelfTask()
       *
       * Marks a self-reported onboarding task as done. Updates
       * meCoachInsightsCache.onboarding.selfReported optimistically, fires
       * saveOnboardingProgress() fire-and-forget, and re-renders the card.
       *
       * Idempotent — tapping the same task a second time is a no-op.
       * If this tick completes the parent chapter, shows a toast informing the
       * member that the chapter badge will be awarded on the nightly sync.
       *
       * @param {string} taskId - ONBOARD_TXX to mark confirmed.
       */
      function confirmOnboardSelfTask(taskId) {
        if (!taskId || !currentUser) return;

        // Ensure the onboarding sub-object exists in the local cache.
        if (!meCoachInsightsCache) meCoachInsightsCache = {};
        if (!meCoachInsightsCache.onboarding ||
            typeof meCoachInsightsCache.onboarding !== 'object') {
          meCoachInsightsCache.onboarding = { dismissed: false, selfReported: [] };
        }

        var selfReported = Array.isArray(meCoachInsightsCache.onboarding.selfReported)
                           ? meCoachInsightsCache.onboarding.selfReported.slice()
                           : [];

        // Idempotent — do nothing if already confirmed.
        if (selfReported.indexOf(taskId) !== -1) return;

        selfReported.push(taskId);
        meCoachInsightsCache.onboarding.selfReported = selfReported;

        // Fire-and-forget Col S write. Re-render does not wait on this.
        try {
          google.script.run.saveOnboardingProgress(currentUser, { selfReported: selfReported });
        } catch (saveErr) {
          console.warn('confirmOnboardSelfTask: save call failed (non-fatal):', saveErr);
        }

        // Check if this tick just completed the chapter that owns this task.
        // getOnboardingChapterSummary() reads the freshly updated cache, so
        // allDone reflects the state *after* this confirmation.
        var updatedChapters = getOnboardingChapterSummary();
        ONBOARD_CHAPTERS.forEach(function(ch) {
          ch.tasks.forEach(function(t) {
            if (t.id !== taskId) return;
            var chSummary = updatedChapters.find(function(s) { return s.id === ch.id; });
            if (chSummary && chSummary.allDone) {
              showToast({ type: 'special', icon: 'fa-solid fa-medal', title: 'Chapter complete!', sub: '\u201c' + chSummary.badgeLabel + '\u201d badge will be awarded tonight.' });
            }
          });
        });

        renderOnboardingCard();
      }

      /**
       * _onboardDismissClick()
       *
       * Invoked by the × button in the card header (incomplete state only).
       * Sets the dismiss-warning flag so renderOnboardingCard() paints the
       * bottom-sheet overlay on the next call. No server write at this stage —
       * the member must confirm via confirmOnboardingDismiss().
       */
      function _onboardDismissClick() {
        _onboardShowDismissWarn = true;
        renderOnboardingCard();
      }

      /**
       * _onboardKeepIt()
       *
       * Invoked by the "Keep it" button inside the dismiss-warning overlay.
       * Clears the overlay flag and restores the normal card state.
       */
      function _onboardKeepIt() {
        _onboardShowDismissWarn = false;
        renderOnboardingCard();
      }

      /**
       * confirmOnboardingDismiss()
       *
       * Invoked by the "Remove it" button in the dismiss-warning overlay.
       * Sets dismissed=true in local cache and Col S, clears the warning flag,
       * and hides the card. Renders a guidance toast so the member knows
       * they can relaunch from Help.
       */
      function confirmOnboardingDismiss() {
        if (!currentUser) return;

        if (!meCoachInsightsCache) meCoachInsightsCache = {};
        if (!meCoachInsightsCache.onboarding ||
            typeof meCoachInsightsCache.onboarding !== 'object') {
          meCoachInsightsCache.onboarding = { dismissed: false, selfReported: [] };
        }

        meCoachInsightsCache.onboarding.dismissed = true;
        _onboardShowDismissWarn = false;

        try {
          google.script.run.saveOnboardingProgress(currentUser, { dismissed: true });
        } catch (saveErr) {
          console.warn('confirmOnboardingDismiss: save call failed (non-fatal):', saveErr);
        }

        // renderOnboardingCard() detects dismissed=true and hides #meOnboardingCard.
        renderOnboardingCard();
        showToast({ type: 'info', icon: 'fa-solid fa-circle-info', title: 'Checklist removed.', sub: 'Tap \u201cOnboarding\u201d in Help to relaunch it.' });
      }

      /**
       * _onboardDismissCompleted()
       *
       * Invoked by the dismiss button in the all-complete banner. No warning
       * overlay is shown because the member has finished everything — one-tap
       * dismiss with a celebratory toast.
       */
      function _onboardDismissCompleted() {
        if (!currentUser) return;

        if (!meCoachInsightsCache) meCoachInsightsCache = {};
        if (!meCoachInsightsCache.onboarding ||
            typeof meCoachInsightsCache.onboarding !== 'object') {
          meCoachInsightsCache.onboarding = { dismissed: false, selfReported: [] };
        }

        meCoachInsightsCache.onboarding.dismissed = true;

        try {
          google.script.run.saveOnboardingProgress(currentUser, { dismissed: true });
        } catch (saveErr) {
          console.warn('_onboardDismissCompleted: save call failed (non-fatal):', saveErr);
        }

        renderOnboardingCard();
        showToast({ type: 'special', icon: 'fa-solid fa-trophy', title: 'Onboarding complete!', sub: 'All badges will appear in your profile.' });
      }

      /**
       * relaunchOnboarding()
       *
       * Public function — exposed on window so a help-article inline button can
       * call it without a module reference. Clears the dismissed flag locally
       * and in Col S, resets expand/overlay state, switches to the Me tab, and
       * re-renders the card.
       *
       * The help article button format:
       *   <button onclick="relaunchOnboarding()">Show me the checklist</button>
       */
      function relaunchOnboarding() {
        if (!currentUser) return;

        if (!meCoachInsightsCache) meCoachInsightsCache = {};
        if (!meCoachInsightsCache.onboarding ||
            typeof meCoachInsightsCache.onboarding !== 'object') {
          meCoachInsightsCache.onboarding = { dismissed: false, selfReported: [] };
        }

        meCoachInsightsCache.onboarding.dismissed = false;
        _onboardOpenChapterId   = '__none__';   // Start collapsed; member opens chapters themselves
        _onboardShowDismissWarn = false;

        try {
          google.script.run.saveOnboardingProgress(currentUser, { dismissed: false });
        } catch (saveErr) {
          console.warn('relaunchOnboarding: save call failed (non-fatal):', saveErr);
        }

        // Switch to Me tab so the member sees the card immediately.
        switchTab('me');
        renderOnboardingCard();
      }

      // Expose globally so help-article inline <button onclick="..."> can reach it
      // without a module reference. Assigned after declaration to avoid hoisting
      // ambiguity — renderOnboardingCard() and switchTab() are already in scope.
      window.relaunchOnboarding = relaunchOnboarding;

      function renderMeCoachCard(coachInsights) {
        var cardEl     = document.getElementById('meCoachInsightCard');
        var chipsEl    = document.getElementById('meCoachInsightChips');
        var taskListEl = document.getElementById('meCoachTaskList');
        var aiCardEl   = document.getElementById('meCoachAiCard');
        var aiTextEl   = document.getElementById('meCoachAiText');
        var aiMetaEl   = document.getElementById('meCoachAiMeta');
        var newBadge   = document.getElementById('meCoachNewBadge');

        // Guard: hide the whole section if no insight data is available yet.
        // New members and those not yet through a nightly sync fall here.
        if (!cardEl || !chipsEl) return;
        // Cache before the guard so renderMeActionBand() always has fresh data,
        // even when the coach card itself is hidden (e.g. first-sync members).
        if (coachInsights) meCoachInsightsCache = coachInsights;

        if (!coachInsights || !coachInsights.insights || coachInsights.insights.length === 0) {
          cardEl.style.display = 'none';
          renderMeActionBand();
          return;
        }

        // ── Theme palette — tint + accent + dot colour ───────────────────────
        // Mirrors the computeBookInsight_ palette for visual consistency.
        var COACH_THEME_PALETTE = {
          amber  : { bg: '#fff8ee', accent: 'var(--color-gamification)', dot: 'var(--color-gamification)', label: '#854f0b'  },
          teal   : { bg: '#edfaf4', accent: 'var(--color-success)', dot: 'var(--color-success)', label: '#0f6e56'  },
          purple : { bg: '#f5f0ff', accent: 'var(--arka-accent)', dot: 'var(--arka-accent)', label: '#3c3489'  },
          blue   : { bg: '#eef6fd', accent: '#378add', dot: '#378add', label: '#185fa5'  },
          neutral: { bg: 'var(--surface-alt)', accent: 'var(--neutral-mid)', dot: 'var(--neutral-mid)', label: '#5f5e5a'  }
        };

        // ── Task type config — icon background, icon class, CTA colour ───────
        // Centralised so adding a new taskType only requires one entry here.
        var COACH_TASK_CONFIG = {
          // Shelf tasks — CTA opens openShelfModal()
          RATE_BOOK:           { iconBg: '#f5f0ff', iconColor: '#3c3489', iconClass: 'fa-star',          ctaBg: '#f5f0ff', ctaColor: '#3c3489', ctaBorder: 'var(--arka-accent)' },
          WRITE_REVIEW:        { iconBg: '#fff8ee', iconColor: '#854f0b', iconClass: 'fa-comment-dots',  ctaBg: '#fff8ee', ctaColor: '#854f0b', ctaBorder: 'var(--color-gamification)' },
          SHELF_STALE_READING: { iconBg: '#edfaf4', iconColor: '#0f6e56', iconClass: 'fa-book-open',     ctaBg: '#edfaf4', ctaColor: '#0f6e56', ctaBorder: 'var(--color-success)' },
          // Book metadata tasks — CTA opens openBookDetailView()
          BOOK_MISSING_PAGES:  { iconBg: '#fff3e0', iconColor: '#854f0b', iconClass: 'fa-hashtag',       ctaBg: '#fff3e0', ctaColor: '#854f0b', ctaBorder: 'var(--color-gamification)' },
          BOOK_MISSING_GENRE:  { iconBg: '#f0f4ff', iconColor: '#185fa5', iconClass: 'fa-tag',           ctaBg: '#f0f4ff', ctaColor: '#185fa5', ctaBorder: '#378add' },
          BOOK_MISSING_COVER:  { iconBg: '#f9f0ff', iconColor: '#6d3fa0', iconClass: 'fa-image',         ctaBg: '#f9f0ff', ctaColor: '#6d3fa0', ctaBorder: '#9b59b6' },
          // Momentum tasks — CTA opens the progress log modal
          STREAK_AT_RISK:      { iconBg: '#fff0f0', iconColor: '#c0392b', iconClass: 'fa-fire',          ctaBg: '#fff0f0', ctaColor: '#c0392b', ctaBorder: 'var(--color-danger)' },
          FIRST_LOG_THIS_WEEK: { iconBg: '#edfaf4', iconColor: '#0f6e56', iconClass: 'fa-book-open',     ctaBg: '#edfaf4', ctaColor: '#0f6e56', ctaBorder: 'var(--color-success)' },
          // Hygiene — To Read stale, CTA opens openShelfModal()
          TO_READ_STALE:       { iconBg: '#edfaf4', iconColor: '#0f6e56', iconClass: 'fa-bookmark',      ctaBg: '#edfaf4', ctaColor: '#0f6e56', ctaBorder: 'var(--color-success)' },
          // Social — CTA opens the challenges tab
          JOIN_CHALLENGE:      { iconBg: '#fff8ee', iconColor: '#854f0b', iconClass: 'fa-trophy',        ctaBg: '#fff8ee', ctaColor: '#854f0b', ctaBorder: 'var(--color-gamification)' },
          // Nudge to link pages to a book after repeated unlinked sessions
          UNLINKED_HABIT:      { iconBg: '#f0f4ff', iconColor: '#185fa5', iconClass: 'fa-book-medical',  ctaBg: '#f0f4ff', ctaColor: '#185fa5', ctaBorder: '#378add' }
        };

        // ── Maximum task cards shown (matches MasterEngine's COACH_TASKS_MAX_COUNT) ──
        var COACH_TASKS_MAX_DISPLAY = 3;

        // ── 1. Render insight chips ──────────────────────────────────────────
        chipsEl.innerHTML = coachInsights.insights.map(function(insight) {
          var palette = COACH_THEME_PALETTE[insight.theme] || COACH_THEME_PALETTE.neutral;
          return (
            '<div style="display:flex; align-items:flex-start; gap:9px;' +
            ' background:white; border:0.5px solid var(--border-soft);' +
            ' border-radius:10px; padding:10px 12px;">' +
              '<div style="width:8px; height:8px; border-radius:50%;' +
              ' background:' + palette.dot + '; flex-shrink:0; margin-top:4px;"></div>' +
              '<div>' +
                '<div style="font-size:12px; font-weight:700; color:var(--text-strong); margin-bottom:2px;">' +
                  insight.icon + '&nbsp; ' + insight.label +
                '</div>' +
                '<div style="font-size:11px; color:var(--text-muted); line-height:1.4;">' + insight.sub + '</div>' +
              '</div>' +
            '</div>'
          );
        }).join('');

        // ── 2. Render task cards ─────────────────────────────────────────────
        var tasks = Array.isArray(coachInsights.tasks) ? coachInsights.tasks : [];
        tasks = tasks.slice(0, COACH_TASKS_MAX_DISPLAY);

        // ── 3. AI advice card ────────────────────────────────────────────────
        // Shown only once MasterEngine starts writing aiAdvice into the JSON.
        if (coachInsights.aiAdvice && aiCardEl && aiTextEl && aiMetaEl) {
          aiTextEl.innerText = coachInsights.aiAdvice;
          aiMetaEl.innerText = 'Generated ' + (coachInsights.generatedAt || 'last night') + ' · refreshes nightly';
          aiCardEl.style.display = 'block';
        }

        // ── NEW badge — show once per day on first visit ─────────────────────
        if (newBadge && coachInsights.generatedAt) {
          var seenKey = 'coachSeen_' + coachInsights.generatedAt;
          if (!sessionStorage.getItem(seenKey)) {
            newBadge.style.display = 'inline';
            sessionStorage.setItem(seenKey, '1');
          }
        }

        // ── arkaCoachTaskResolved event listener ─────────────────────────────
        // Fired by _doSubmitShelfUpdate() after any successful shelf save.
        // Matches the event's shelfId against rendered task cards by
        // data-task-shelf-id attribute, then conditionally marks the card done
        // based on what actually changed (rating > 0, review non-empty, or
        // status change for stale-reading tasks).
        // The listener is re-registered on each call (guarded by a module-scoped
        // flag) so there is never a duplicate listener accumulation.
        if (!window._arkaCoachTaskListenerAttached) {
          window._arkaCoachTaskListenerAttached = true;
          document.addEventListener('arkaCoachTaskResolved', function(evt) {
            var d = evt.detail || {};

            // Resolve tasks directly from the cache — task DOM cards no longer
            // exist in Coach, so we can't iterate them. Same resolution rules apply.
            if (meCoachInsightsCache && Array.isArray(meCoachInsightsCache.tasks)) {
              meCoachInsightsCache.tasks.forEach(function(task) {
                var taskType = task.taskType;
                var taskId   = task.taskId;

                if (sessionStorage.getItem('arkaCoachTaskDone_' + taskId)) return;

                var isMomentum = (taskType === 'STREAK_AT_RISK' || taskType === 'FIRST_LOG_THIS_WEEK');
                if (!isMomentum && task.targetEntityId !== d.shelfId) return;

                var resolved = false;
                if (taskType === 'RATE_BOOK'           && Number(d.rating) > 0)               resolved = true;
                if (taskType === 'WRITE_REVIEW'        && d.review && d.review.trim() !== '')  resolved = true;
                if (taskType === 'SHELF_STALE_READING')                                        resolved = true;
                if (taskType === 'TO_READ_STALE')                                              resolved = true;
                if (isMomentum && d.pagesLogged > 0)                                           resolved = true;

                if (resolved) {
                  sessionStorage.setItem('arkaCoachTaskDone_' + taskId, '1');
                  try { google.script.run.markCoachTaskComplete(currentUser, taskId); } catch(e) {}
                }
              });
            }

            renderMeActionBand();
          });
        }

        // Reveal the whole section now that content is ready
        cardEl.style.display = 'block';

        renderMeActionBand();
      }

      /**
       * Returns true when a coach task has been resolved via the activity log
       * rather than via the arkaCoachTaskResolved event.
       * Covers BOOK_MISSING_* (resolved by any BOOKUPDATE on the target book)
       * and JOIN_CHALLENGE (resolved by any CHALLENGE_ENROLL by this member).
       * Mirrors the activity-log filter block inside renderMeCoachCard().
       * @param {Object} task - A task object from coachInsights.tasks.
       * @returns {boolean}
       */
      function isTaskResolvedByActivity_(task) {
        var ACTIVITY_RESOLVED = {
          BOOK_MISSING_PAGES: true,
          BOOK_MISSING_GENRE: true,
          BOOK_MISSING_COVER: true,
          JOIN_CHALLENGE    : true
        };
        if (!ACTIVITY_RESOLVED[task.taskType]) return false;

        if (task.taskType === 'JOIN_CHALLENGE') {
          return globalActivityLogDB.some(function(act) {
            return act.activityTypeID   === 'ARKA_ACTTYP_CHALLENGE_ENROLL'
                && act.activityMemberID === currentUser;
          });
        }

        var TWENTY_FOUR_HOURS_MS = 24 * 60 * 60 * 1000;
        var activityCutoffMs     = Date.now() - TWENTY_FOUR_HOURS_MS;
        return globalActivityLogDB.some(function(act) {
          if (act.activityTypeID   !== 'ARKA_ACTTYP_BOOKUPDATE') return false;
          if (act.activityMemberID !== currentUser)               return false;
          if (act.activityDesc     !== task.targetEntityId)       return false;
          var actMs = parseGoogleDate(act.activityDate).getTime();
          return !isNaN(actMs) && actMs >= activityCutoffMs;
        });
      }
      
      /**
       * Renders the three-tile Action Band above the Reading Journey section.
       *
       * Tile 1 — Log reading: always shown; opens openLogReadingSheet().
       * Tile 2 — Continue reading: most-recently-logged currently-reading book;
       *          omitted when the member has no active Reading shelf.
       * Tile 3 — Suggested task: first unresolved task from meCoachInsightsCache;
       *          omitted when no tasks are pending or coach data is unavailable.
       *
       * Called by renderMeCoachCard() (Wave 1 + task-resolved events) and by the
       * submitLogReading success re-render blocks.
       *
       * Reads: meCoachInsightsCache, globalMyPageLogDB, globalShelvesDB,
       *        booksMap, shelvesMap, currentUser, parseGoogleDate(), getBookColor(),
       *        escapeHtml().
       */
      /**
       * renderMeActionBand()
       *
       * Renders the three action tiles above the coach section on the Me tab:
       *   1. Log Reading  — always shown; primary accent tile.
       *   2. Continue Reading — shown when the member has at least one Reading-shelf
       *      book; pre-selects the most-recently-logged book in the log modal.
       *   3. Suggested Task — shown when meCoachInsightsCache contains an unresolved
       *      task that has not been session-dismissed.
       *
       * A11Y CONTRACT (enforced here; apply to every new interactive tile):
       *   Every clickable outer <div> MUST carry:
       *     role="button"  — exposes it as a button to assistive technology.
       *     tabindex="0"   — places it in the natural Tab order.
       *     data-action    — opts it into initKeyboardActivationBridge_() so
       *                      Enter/Space fire the existing onclick without
       *                      rewriting any action logic.
       *
       * CODING RULE: No new interactive <div> in this function (or anywhere in the
       * app) without all three attributes above. The delegated handler is already
       * wired at window.onload; adding the attributes is the entire migration cost.
       */
      function renderMeActionBand() {
        var bandEl = document.getElementById('meActionBand');
        if (!bandEl) return;

        var html = '';

        // ── Tile 1: Log reading — primary accent tile, always rendered ────────────
        html +=
          '<div onclick="openLogReadingSheet()" '
          + 'role="button" tabindex="0" data-action '
          + 'style="display:flex;align-items:center;gap:11px;background:var(--arka-accent);'
          + 'border-radius:12px;padding:13px 14px;margin-bottom:9px;cursor:pointer;">'
          + '<div style="width:38px;height:38px;border-radius:9px;background:rgba(255,255,255,0.18);'
          + 'display:flex;align-items:center;justify-content:center;flex-shrink:0;">'
          + '<i class="fa-solid fa-pencil" style="font-size:17px;color:#fff;"></i>'
          + '</div>'
          + '<div style="flex:1;min-width:0;">'
          + '<div style="font-size:15px;font-weight:700;color:#fff;line-height:1.2;">Log reading</div>'
          + '<div style="font-size:11px;color:rgba(255,255,255,0.82);margin-top:2px;">Pages, or against a book</div>'
          + '</div>'
          + '<i class="fa-solid fa-chevron-right" style="font-size:16px;color:rgba(255,255,255,0.7);flex-shrink:0;"></i>'
          + '</div>';

        // ── Tile 2: Continue reading — most-recently-logged Reading-shelf book ─────
        // Build per-book last-read ms from the personal all-time page-log store.
        var lastReadByBook = {};
        globalMyPageLogDB.forEach(function(l) {
          if (l.memberId !== currentUser) return;
          if (!l.bookId || l.bookId.indexOf('ARKA_BOOK_') !== 0) return;
          var d = parseGoogleDate(l.timestamp);
          if (!d || isNaN(d.getTime())) return;
          var ms = d.getTime();
          if (!lastReadByBook[l.bookId] || ms > lastReadByBook[l.bookId]) {
            lastReadByBook[l.bookId] = ms;
          }
        });

        var topReading = null;
        globalShelvesDB.forEach(function(s) {
          if (s.memberId !== currentUser || s.status !== 'Reading') return;
          var book = booksMap.get(s.bookId);
          if (!book) return;
          var ms = lastReadByBook[s.bookId] || 0;
          if (!topReading || ms > topReading.lastReadMs) {
            topReading = { book: book, shelf: s, lastReadMs: ms };
          }
        });

        if (topReading) {
          var crBook    = topReading.book;
          var crShelf   = topReading.shelf;
          var crTotal   = Number(crBook.pages)       || 0;
          var crCurrent = Number(crShelf.pagesRead)  || 0;
          var crPct     = crTotal > 0 ? Math.min(100, Math.round((crCurrent / crTotal) * 100)) : 0;
          var crColor   = getBookColor(crBook.title);
          var crInitial = escapeHtml(crBook.title.charAt(0));
          var crOnclick = "openLogReadingSheet({bookId:'" + crBook.id + "',shelfId:'" + crShelf.shelfId + "'})";

          var crCoverHtml = crBook.coverImageURL
            ? '<img src="' + crBook.coverImageURL + '" '
              + 'style="width:34px;height:46px;object-fit:cover;border-radius:5px;flex-shrink:0;" '
              + 'onerror="this.style.display=\'none\';this.nextElementSibling.style.display=\'flex\';">'
              + '<div style="display:none;width:34px;height:46px;border-radius:5px;background:' + crColor + ';'
              + 'align-items:center;justify-content:center;flex-shrink:0;">'
              + '<span style="color:#fff;font-size:0.9rem;font-weight:700;">' + crInitial + '</span></div>'
            : '<div style="width:34px;height:46px;border-radius:5px;background:' + crColor + ';'
              + 'display:flex;align-items:center;justify-content:center;flex-shrink:0;">'
              + '<span style="color:#fff;font-size:0.9rem;font-weight:700;">' + crInitial + '</span></div>';

          var crDaysAgo = topReading.lastReadMs > 0
            ? Math.round((Date.now() - topReading.lastReadMs) / 86400000) : -1;
          var crLastLbl = crDaysAgo < 0  ? 'not started yet'
            : crDaysAgo === 0            ? 'today'
            : crDaysAgo === 1            ? 'yesterday'
            : crDaysAgo < 7             ? crDaysAgo + ' days ago'
            : 'over a week ago';

          html +=
            '<div onclick="' + crOnclick + '" '
            + 'role="button" tabindex="0" data-action '
            + 'style="display:flex;align-items:center;gap:11px;background:#fff;'
            + 'border:0.5px solid var(--border-soft);border-radius:12px;'
            + 'padding:11px 12px;margin-bottom:9px;cursor:pointer;">'
            + '<div style="flex-shrink:0;">' + crCoverHtml + '</div>'
            + '<div style="flex:1;min-width:0;">'
            + '<div style="font-size:10px;color:var(--text-muted);margin-bottom:1px;">Continue reading</div>'
            + '<div style="font-size:13px;font-weight:700;color:var(--text-strong);'
            + 'white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + escapeHtml(crBook.title) + '</div>'
            + '<div style="height:5px;background:var(--border-soft);border-radius:3px;'
            + 'margin:5px 0 3px;overflow:hidden;">'
            + '<div style="height:100%;width:' + crPct + '%;background:var(--color-success);border-radius:3px;"></div>'
            + '</div>'
            + '<div style="font-size:10px;color:var(--text-muted);">'
            + 'p.' + crCurrent + (crTotal > 0 ? ' of ' + crTotal : '') + ' · last read ' + crLastLbl
            + '</div>'
            + '</div>'
            + '<i class="fa-solid fa-chevron-right" '
            + 'style="font-size:15px;color:var(--border-soft);flex-shrink:0;"></i>'
            + '</div>';
        }

        // ── Tile 3: Suggested task — top unresolved coach task ────────────────────
        // Mirrors COACH_TASK_CONFIG from renderMeCoachCard() — kept local until a
        // future cleanup hoists it to module scope.
        var BAND_TASK_CONFIG = {
          RATE_BOOK           : { iconBg: '#f5f0ff', iconColor: '#3c3489', iconClass: 'fa-star'         },
          WRITE_REVIEW        : { iconBg: '#fff8ee', iconColor: '#854f0b', iconClass: 'fa-comment-dots' },
          SHELF_STALE_READING : { iconBg: '#edfaf4', iconColor: '#0f6e56', iconClass: 'fa-book-open'    },
          BOOK_MISSING_PAGES  : { iconBg: '#fff3e0', iconColor: '#854f0b', iconClass: 'fa-hashtag'      },
          BOOK_MISSING_GENRE  : { iconBg: '#f0f4ff', iconColor: '#185fa5', iconClass: 'fa-tag'          },
          BOOK_MISSING_COVER  : { iconBg: '#f9f0ff', iconColor: '#6d3fa0', iconClass: 'fa-image'        },
          STREAK_AT_RISK      : { iconBg: '#fff0f0', iconColor: '#c0392b', iconClass: 'fa-fire'         },
          FIRST_LOG_THIS_WEEK : { iconBg: '#edfaf4', iconColor: '#0f6e56', iconClass: 'fa-book-open'    },
          TO_READ_STALE       : { iconBg: '#edfaf4', iconColor: '#0f6e56', iconClass: 'fa-bookmark'     },
          JOIN_CHALLENGE      : { iconBg: '#fff8ee', iconColor: '#854f0b', iconClass: 'fa-trophy'       }
        };

        if (meCoachInsightsCache && Array.isArray(meCoachInsightsCache.tasks)) {
          // Apply the same session-done filter as renderMeCoachCard so the band
          // and the coach section are always in agreement on task state.
          var topTask = null;
          for (var ti = 0; ti < meCoachInsightsCache.tasks.length; ti++) {
            var t = meCoachInsightsCache.tasks[ti];
            if (!sessionStorage.getItem('arkaCoachTaskDone_' + t.taskId)
                && !isTaskResolvedByActivity_(t)) {
              topTask = t;
              break;
            }
          }

          if (topTask) {
            var cfg = BAND_TASK_CONFIG[topTask.taskType] || BAND_TASK_CONFIG.RATE_BOOK;

            // CTA routing: targetEntityType is the primary branch; taskType overrides
            // for shelf tasks where the correct UX differs from the edit-mode default:
            //   SHELF_STALE_READING → log reading sheet   (page-log intent, not shelf edit)
            //   TO_READ_STALE       → shelf modal std mode (start-reading intent; tiles unlocked)
            //   RATE_BOOK / WRITE_REVIEW → shelf modal edit mode (correct — already Finished)
            var taskOnClick;
            if (topTask.targetEntityType === 'book') {
              taskOnClick = "openBookDetailView('" + topTask.auxiliaryBookId + "','me')";
            } else if (topTask.targetEntityType === 'pagelog') {
              taskOnClick = "openLogReadingSheet({bookId:'" + topTask.auxiliaryBookId + "',shelfId:'" + topTask.targetEntityId + "'})";
            } else if (topTask.targetEntityType === 'challenge') {
              taskOnClick = "openChallengesView()";
            } else if (topTask.targetEntityType === 'library') {
              // Routes to the Library tab so the member can find or add a book.
              taskOnClick = "switchTab('library')";
            } else if (topTask.taskType === 'SHELF_STALE_READING') {
              // Stale-reading: prompt for a page log, not a shelf record edit.
              // openLogReadingSheet routes through logReadingProgress (backend CASE 2
              // is not triggered here — progress log is a separate path). PageLogDB
              // is written. arkaCoachTaskResolved fires on save and resolves the task
              // via the shelfId match (task.targetEntityId === d.shelfId).
              taskOnClick = "openLogReadingSheet({bookId:'" + topTask.auxiliaryBookId + "',shelfId:'" + topTask.targetEntityId + "'})";
            } else if (topTask.taskType === 'TO_READ_STALE') {
              // To-Read-stale: start this book. Standard mode unlocks tiles so the
              // member can transition to Reading (or Finished if read offline).
              // CASE 2 handles the To Read → Reading/Finished progression correctly.
              taskOnClick = "openShelfModal('" + topTask.auxiliaryBookId + "','false')";
            } else {
              // Default: RATE_BOOK, WRITE_REVIEW and any future shelf tasks that
              // target already-Finished records. Edit mode (CASE 1) is correct here.
              taskOnClick = "openShelfModal('" + topTask.auxiliaryBookId + "','true','" + topTask.targetEntityId + "')";
            }

            html +=
              '<div onclick="' + taskOnClick + '" '
              + 'role="button" tabindex="0" data-action '
              + 'style="display:flex;align-items:center;gap:11px;background:#fff;'
              + 'border:0.5px solid var(--border-soft);border-radius:12px;'
              + 'padding:10px 12px;cursor:pointer;">'
              + '<div style="width:30px;height:30px;border-radius:8px;background:' + cfg.iconBg + ';'
              + 'display:flex;align-items:center;justify-content:center;flex-shrink:0;">'
              + '<i class="fa-solid ' + cfg.iconClass + '" '
              + 'style="font-size:14px;color:' + cfg.iconColor + ';"></i>'
              + '</div>'
              + '<div style="flex:1;min-width:0;">'
              + '<div style="font-size:10px;color:var(--text-muted);margin-bottom:1px;">Suggested task</div>'
              + '<div style="font-size:13px;font-weight:700;color:var(--text-strong);'
              + 'white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">'
              + escapeHtml(topTask.title) + '</div>'
              + '</div>'
              + '<i class="fa-solid fa-chevron-right" '
              + 'style="font-size:15px;color:var(--border-soft);flex-shrink:0;"></i>'
              + '</div>';
          }
        }

        bandEl.innerHTML = html;
      }

      /**
       * markCoachTaskDone_()
       *
       * Visually marks a coach task card as completed: green background, teal border,
       * white checkmark icon, hidden CTA button. Persists to sessionStorage so
       * the done state survives same-session tab switches (Me tab re-renders the
       * card from coachInsights JSON which still contains the task until the next
       * nightly MasterEngine sync clears it).
       *
       * @param {HTMLElement} cardEl - The task card div (has data-task-id attribute).
       * @param {string}      taskId - Unique task ID for the sessionStorage key.
       */
      function markCoachTaskDone_(cardEl, taskId) {
        if (!cardEl) return;

        // Background + border → completion green
        cardEl.style.background   = '#edfaf4';
        cardEl.style.borderColor  = 'var(--color-success)';

        // Icon wrapper → solid teal with white checkmark
        var iconWrap = cardEl.querySelector('.coach-task-icon');
        if (iconWrap) {
          iconWrap.style.background = 'var(--color-success)';
          iconWrap.innerHTML = '<i class="fa-solid fa-check" style="color:white; font-size:13px;"></i>';
        }

        // CTA button → hidden (action is already done)
        var ctaBtn = cardEl.querySelector('button');
        if (ctaBtn) ctaBtn.style.display = 'none';

        // Persist within session — renderMeCoachCard() reads this on next Me tab visit
        if (taskId) sessionStorage.setItem('arkaCoachTaskDone_' + taskId, '1');

        // Silent background write (Option A): remove the task from MemberDB Col S
        // so it doesn't reappear before the nightly sync. Fire-and-forget — no
        // success handler, no spinner, no blocking. The nightly sync is the backstop
        // if this write fails. sessionStorage above covers the same session instantly.
        if (taskId && typeof currentUser !== 'undefined' && currentUser) {
          try {
            google.script.run.markCoachTaskComplete(currentUser, taskId);
          } catch (silentErr) {
            // Non-fatal — sessionStorage + nightly sync still cover it.
            console.warn('markCoachTaskComplete dispatch failed (non-fatal):', silentErr);
          }
        }
      }


      // ─── Badge Strip (Profile Pages) ─────────────────────────────────────────────
      
      /**
       * Renders the badge strip for a member in a given container.
       *
       * @param {string}  memberId    - Member ID whose badges to display
       * @param {string}  containerId - DOM container to write into
       * @param {boolean} showSeeAll  - When true, renders the "See all →" header link (Me tab)
       * @param {boolean} isExpanded  - When true, skips the STRIP_VISIBLE cap and shows all badges
       */
      function renderBadgeStrip(memberId, containerId, showSeeAll = false, isExpanded = false) {
        const container = document.getElementById(containerId);
        if (!container || !isAppDataLoaded) return;

        // getEffectiveStripBadges_ applies the replacing filter and sorts by category order
        const effectiveBadges = getEffectiveStripBadges_(memberId);
        const totalEarned     = (memberBadgeIndex.get(memberId) || []).length; // raw count for pill
        const STRIP_VISIBLE   = 8; // Max circles shown before the "+N more" expand button

        if (!effectiveBadges.length) {
          // Empty state — only render the container label so layout doesn't collapse
          if (showSeeAll && totalEarned === 0) {
            container.innerHTML = '';
            return;
          }
        }

        // ── Build earned circles (replacing-filtered) ────────────────────────
        // isExpanded bypasses the STRIP_VISIBLE cap so all badges render inline
        let earnedHtml = '';
        const visibleBadges = isExpanded
          ? effectiveBadges
          : effectiveBadges.slice(0, STRIP_VISIBLE);

        visibleBadges.forEach(function(entry) {
          earnedHtml += buildBadgeCircleHtml(entry.badge, false, 48);
        });

        // Overflow button — tapping expands the strip inline (no navigation away)
        const overflowCount = effectiveBadges.length - STRIP_VISIBLE;
        if (!isExpanded && overflowCount > 0) {
          // Encode arguments so the inline onclick can reconstruct the call correctly
          const escapedMemberId   = memberId.replace(/'/g, "\\'");
          const escapedContainerId = containerId.replace(/'/g, "\\'");
          earnedHtml += `
            <div style="display:flex;flex-direction:column;align-items:center;gap:4px;cursor:pointer;"
                 onclick="expandBadgeStrip('${escapedMemberId}', '${escapedContainerId}', ${showSeeAll})">
              <div style="width:48px;height:48px;border-radius:50%;background:var(--border-soft);
                          border:2px solid var(--neutral-mid);display:flex;align-items:center;
                          justify-content:center;font-size:0.88rem;font-weight:500;color:var(--text-muted);">
                +${overflowCount}
              </div>
              <div style="font-size:0.58rem;color:var(--text-faint);">more</div>
            </div>`;
        }

        const earnedCountLabel = totalEarned > 0
          ? `<span style="font-size:0.68rem;color:var(--text-faint);font-weight:normal;margin-left:4px;">
               ${totalEarned} earned
             </span>`
          : '';

        container.innerHTML = `
          <div style="margin-top:8px;">
            ${showSeeAll
              ? `<div style="display:flex;justify-content:space-between;align-items:center;
                             margin-bottom:12px;">
                  <div style="display:flex;align-items:baseline;gap:8px;">
                    <span style="font-size:0.68rem;font-weight:700;color:var(--text-muted);
                                 text-transform:uppercase;letter-spacing:0.5px;">Badges</span>
                    ${earnedCountLabel}
                  </div>
                  <div role="button" tabindex="0" data-action onclick="openBadgeGallery()"
                       style="font-size:0.78rem;color:var(--arka-accent);font-weight:500;cursor:pointer;
                              background:#f5f0ff;padding:4px 10px;border-radius:12px;">
                    See all →
                  </div>
                </div>`
              : `<div style="margin-bottom:12px;">
                  <span style="font-size:0.68rem;font-weight:700;color:var(--text-muted);
                               text-transform:uppercase;letter-spacing:0.5px;">Badges</span>
                  ${earnedCountLabel}
                </div>`
            }
            <div style="display:flex;flex-wrap:wrap;gap:12px;">
              ${earnedHtml || '<p style="font-size:0.85rem;color:var(--text-faint);font-style:italic;margin:0;">No badges yet.</p>'}
            </div>
          </div>`;
      }
      
      
      /**
       * Expands a badge strip to show all earned badges in the same container,
       * replacing the "+N more" overflow button with the full badge grid.
       * Called by the overflow button rendered inside renderBadgeStrip().
       *
       * @param {string}  memberId    - Member ID whose badges to display
       * @param {string}  containerId - DOM container that holds the strip
       * @param {boolean} showSeeAll  - Passed through to preserve header state (Me tab)
       */
      function expandBadgeStrip(memberId, containerId, showSeeAll) {
        renderBadgeStrip(memberId, containerId, showSeeAll, true /* isExpanded */);
      }


      /**
       * Builds a single circular badge avatar for the compact profile strip.
       *
       * @param   {Object}  badge    - Badge object from badgesMap
       * @param   {boolean} isLocked - True = dim, dashed border
       * @param   {number}  sizePx   - Circle diameter in pixels (48 for earned, 40 for locked)
       * @returns {string} HTML string
       */
      function buildBadgeCircleHtml(badge, isLocked, sizePx) {
        const opacity     = isLocked ? '0.35' : '1';
        const borderStyle = isLocked ? `2px dashed var(--neutral-mid)` : `2px solid var(--arka-accent)`;
      
        // Request an appropriately small thumbnail so the strip stays fast
        const imgSrc = badge.imgUrl ? badge.imgUrl.replace('sz=w400', 'sz=w80') : '';
      
        const imgHtml = imgSrc
          ? `<img src="${imgSrc}"
                  style="width:${sizePx}px; height:${sizePx}px; border-radius:50%;
                        object-fit:cover; border:${borderStyle}; display:block;"
                  onerror="this.style.display='none'; this.nextElementSibling.style.display='flex';">
            <div style="display:none; width:${sizePx}px; height:${sizePx}px; border-radius:50%;
                        background:#f0e8f5; border:${borderStyle}; align-items:center;
                        justify-content:center; font-size:${Math.floor(sizePx * 0.38)}px;">🏅</div>`
          : `<div style="width:${sizePx}px; height:${sizePx}px; border-radius:50%;
                        background:#f0e8f5; border:${borderStyle}; display:flex; align-items:center;
                        justify-content:center; font-size:${Math.floor(sizePx * 0.38)}px;">🏅</div>`;
      
        return `
          <div style="display:flex; flex-direction:column; align-items:center; gap:4px;
                      cursor:pointer; opacity:${opacity};"
              onclick="openBadgeDetailSheet('${badge.id}')">
            ${imgHtml}
            <div style="font-size:0.58rem; color:#34495e; text-align:center;
                        max-width:${sizePx + 8}px; line-height:1.2;
                        display:-webkit-box; -webkit-line-clamp:2;
                        -webkit-box-orient:vertical; overflow:hidden;">
              ${badge.caption}
            </div>
          </div>
        `;
      }
      
      
      // ─── Badge Detail Bottom Sheet ────────────────────────────────────────────────
      
      /**
       * Opens the badge detail bottom sheet for a specific badge.
       * Shows the badge image, description, who holds it, and when
       * the current user earned it (if they did).
       *
       * @param {string} badgeId - ARKA_BADGE_X to display
       */
      function openBadgeDetailSheet(badgeId) {
        const badge = badgesMap.get(badgeId);
        if (!badge) return;
      
        // All active holders of this badge
        const allHolderAwards = globalBadgeAwardsDB.filter(
          a => a.badgeId === badgeId && a.status === 'Active'
        );
        const holderCount = allHolderAwards.length;
      
        // Did the current user earn this badge?
        const myAward = allHolderAwards.find(a => a.memberId === currentUser);
      
        // "Awarded by · date" line — only shown to the recipient
        let awardedByHtml = '';
        if (myAward) {
          const isAutoAwarded = myAward.awardedBy === 'MasterEngine';
          const awarderName   = isAutoAwarded
            ? 'Auto-awarded by system'
            : ((membersMap.get(myAward.awardedBy) || {}).displayName || 'Club Admin');
          awardedByHtml = `
            <div style="font-size:0.78rem; color:var(--color-warning); font-weight:500; margin:4px 0 8px;">
              ${escapeHtml(awarderName)} · ${myAward.awardedDate}
            </div>
          `;
        }
      
        // Badge image — request a slightly larger size for the detail view
        const imgSrc = badge.imgUrl ? badge.imgUrl.replace('sz=w400', 'sz=w120') : '';
        const imgHtml = imgSrc
          ? `<img src="${imgSrc}"
                  id="badgeDetailImg"
                  style="width:72px; height:72px; border-radius:50%; object-fit:cover;
                        border:3px solid var(--arka-accent); flex-shrink:0; cursor:zoom-in;
                        transition:all 0.25s ease;"
                  onclick="toggleBadgeImageZoom(this, '${badge.imgUrl.replace('sz=w400', 'sz=w300')}')"
                  onerror="this.style.display='none'; this.nextElementSibling.style.display='flex';">
            <div style="display:none; width:72px; height:72px; border-radius:50%;
                        background:#f0e8f5; border:3px solid var(--arka-accent); align-items:center;
                        justify-content:center; font-size:2.2rem; flex-shrink:0;">🏅</div>`
          : `<div style="width:72px; height:72px; border-radius:50%; background:#f0e8f5;
                        border:3px solid var(--arka-accent); display:flex; align-items:center;
                        justify-content:center; font-size:2.2rem; flex-shrink:0;">🏅</div>`;
      
        // Compact holder avatar strip (max 6 shown)
        let holdersHtml = '';
        if (holderCount > 0) {
          const holderAvatarsHtml = allHolderAwards.slice(0, 6).map(a => {
            const m = membersMap.get(a.memberId);
            if (!m) return '';
            const initLetter = m.displayName ? m.displayName.charAt(0).toUpperCase() : '?';
            const avatarStyle = `width:32px; height:32px; border-radius:50%; border:2px solid white;
                                margin-right:-6px; cursor:pointer; flex-shrink:0;`;
            return m.imageURL
              ? `<img src="${m.imageURL}" style="${avatarStyle} object-fit:cover;"
                      onclick="closeBadgeDetailSheet(); showMemberProfile('${m.id}')"
                      title="${m.displayName}">`
              : `<div style="${avatarStyle} background:var(--border-soft); display:flex; align-items:center;
                              justify-content:center; font-size:0.72rem; font-weight:500; color:var(--text-muted);"
                      onclick="closeBadgeDetailSheet(); showMemberProfile('${m.id}')"
                      title="${m.displayName}">
                  ${initLetter}
                </div>`;
          }).join('');
      
          holdersHtml = `
            <div style="background:var(--surface-alt); border-radius:8px; padding:10px 12px; margin-top:16px;">
              <div style="font-size:0.68rem; color:var(--text-muted); font-weight:500; text-transform:uppercase;
                          letter-spacing:0.5px; margin-bottom:8px;">
                Held by ${holderCount} member${holderCount !== 1 ? 's' : ''}
              </div>
              <div style="display:flex; align-items:center; padding-left:6px; flex-wrap:wrap; gap:2px;">
                ${holderAvatarsHtml}
                ${holderCount > 6
                  ? `<div style="font-size:0.72rem; color:var(--text-muted); margin-left:14px;">
                      +${holderCount - 6} more
                    </div>`
                  : ''}
              </div>
            </div>
          `;
        }
      
        const drawer = document.getElementById('badgeDetailDrawer');
        drawer.innerHTML = `
          <div style="width:36px; height:4px; background:var(--border-soft); border-radius:2px;
                      margin:0 auto 16px;"></div>
          <div style="display:flex; gap:14px; align-items:flex-start;">
            ${imgHtml}
            <div style="flex:1; min-width:0;">
              <div style="font-size:1.05rem; font-weight:bold; color:var(--text-strong); margin-bottom:2px;">
                ${badge.caption}
              </div>
              ${awardedByHtml}
              <div style="font-size:0.88rem; color:#34495e; line-height:1.5;">
                ${badge.description}
              </div>
            </div>
          </div>
          ${holdersHtml}
        `;
      
        document.getElementById('badgeDetailModal').style.display = 'block';
        setTimeout(() => drawer.classList.add('open'), 10);
      }
      
      
      /**
       * Closes the badge detail bottom sheet with the standard slide-down animation.
       */
      function closeBadgeDetailSheet() {
        const drawer = document.getElementById('badgeDetailDrawer');
        if (drawer) drawer.classList.remove('open');
        setTimeout(() => {
          const modal = document.getElementById('badgeDetailModal');
          if (modal) modal.style.display = 'none';
        }, 300);
      }

      /**
       * Toggles the badge image between small circle (72px) and enlarged square (200px).
       * Swaps to a higher-res thumbnail URL when expanding so the image stays crisp.
       * Clicking again collapses it back to the original size and shape.
       *
       * @param {HTMLElement} imgEl   - The clicked image element
       * @param {string}      largeUrl - Higher-res thumbnail URL for the expanded state
       */
      function toggleBadgeImageZoom(imgEl, largeUrl) {
        const isExpanded = imgEl.dataset.expanded === 'true';

        if (isExpanded) {
          // Collapse back to circle
          imgEl.src                  = imgEl.dataset.smallUrl;
          imgEl.style.width          = '72px';
          imgEl.style.height         = '72px';
          imgEl.style.borderRadius   = '50%';
          imgEl.style.cursor         = 'zoom-in';
          imgEl.dataset.expanded     = 'false';
        } else {
          // Store the small URL so we can restore it on collapse
          imgEl.dataset.smallUrl     = imgEl.src;
          imgEl.src                  = largeUrl;
          imgEl.style.width          = '200px';
          imgEl.style.height         = '200px';
          imgEl.style.borderRadius   = '12px';
          imgEl.style.cursor         = 'zoom-out';
          imgEl.dataset.expanded     = 'true';
        }
      }

      // ══════════════════════════════════════════════════════════════════════
      // READING PERSONALITY — rendering functions
      // ══════════════════════════════════════════════════════════════════════

      /**
       * renderMeTabPersonaInset()
       *
       * Populates the #meTabPersonaInset tinted block in the Me tab identity card
       * with the current user's reading archetype emoji, name, and tagline.
       *
       * Called from: applyWave2() once personaProfileMap is built.
       *              Re-call after any persona-shift event to keep the strip current.
       *
       * Reads:  personaProfileMap, currentUser
       * Writes: #meTabPersonaInset (innerHTML + display), #meTabPersonalityChipLabel
       *
       * Graceful fallback: if the profile is Forming (no archetypeName), the inset
       * stays hidden and the chip label becomes "Discover my personality ›" to act
       * as a discovery nudge per Audit UX §1 Suggestion 2.
       */
      function renderMeTabPersonaInset() {
        var insetEl    = document.getElementById('meTabPersonaInset');
        var chipLabel  = document.getElementById('meTabPersonalityChipLabel');
        if (!insetEl) return;

        var myProfile = personaProfileMap ? personaProfileMap.get(currentUser) : null;

        // ── Forming profile — no resolved archetype yet ───────────────────────
        if (!myProfile || !myProfile.archetypeName) {
          insetEl.style.display = 'none';
          if (chipLabel) chipLabel.innerText = 'Discover my personality ›';
          return;
        }

        // ── Resolved archetype — build the inset content ──────────────────────
        var safeEmoji   = escapeHtml(myProfile.archetypeEmoji   || '📖');
        var safeName    = escapeHtml(myProfile.archetypeName);
        var safeTagline = myProfile.archetypeTagline
                          ? escapeHtml(myProfile.archetypeTagline)
                          : '';

        insetEl.innerHTML =
            '<div style="display:flex; align-items:center; gap:10px;">'
          +   '<span style="font-size:22px; flex-shrink:0; line-height:1;">' + safeEmoji + '</span>'
          +   '<div>'
          +     '<div style="font-size:13px; font-weight:600; color:#26215C; line-height:1.2;">'
          +       safeName
          +     '</div>'
          +     (safeTagline
                  ? '<div style="font-size:12px; color:var(--arka-accent); font-style:italic; margin-top:2px;">'
                      + '\u201C' + safeTagline + '\u201D'
                    + '</div>'
                  : '')
          +   '</div>'
          + '</div>';

        insetEl.style.display = 'block';
        if (chipLabel) chipLabel.innerText = 'My personality ›';
      }


      /**
       * renderPersonaStrip()
       *
       * Renders the compact Reading Personality card into a profile container.
       * Shows on both own profile (#mePersonaContainer) and other members'
       * profiles (#otherPersonaContainer). Tapping opens the full panel.
       * Called from applyWave3() for own profile, and from openOtherMemberProfile()
       * for others' profiles (same call site as renderBadgeStrip).
       *
       * @param {string} memberId    - ARKA_MEMBER_X whose persona to show
       * @param {string} containerId - DOM id to render into
       */
      function renderPersonaStrip(memberId, containerId) {
        const container = document.getElementById(containerId);
        if (!container) return;

        const profile    = personaProfileMap.get(memberId);
        // Derive the parent section wrapper ID from the container ID so the
        // header divider hides together with the content — no orphaned headings.
        const sectionEl  = document.getElementById(containerId.replace('Container', 'Section'));

        // Helper: hides both container and section header cleanly.
        function hidePersonaSection_() {
          container.innerHTML = '';
          if (sectionEl) sectionEl.style.display = 'none';
        }
        // Helper: ensures the section is visible before rendering into it.
        function showPersonaSection_() {
          if (sectionEl) sectionEl.style.display = '';
        }

        // No PersonaPass row yet — member may be new or inactive. Hide entirely.
        if (!profile) { hidePersonaSection_(); return; }

        // Suppressed + not own profile → hide section completely, no message.
        // Own profile always shows regardless of status (member can always
        // see their own personality — the toggle only affects others' view).
        if (profile.status === 'Suppressed' && memberId !== currentUser) {
          hidePersonaSection_();
          return;
        }

        // Content is available — ensure the section wrapper is visible.
        showPersonaSection_();

        // Parse resolved (non-gated) verdicts for trait chips.
        let resolvedVerdicts = [];
        try {
          const allVerdicts = JSON.parse(profile.axisVerdicts || '[]');
          resolvedVerdicts  = allVerdicts.filter(function(v) { return !v.gated; });
        } catch (e) { /* malformed JSON — chips stay empty */ }

        // ── Forming state — no archetype resolved yet ─────────────────────
        if (!profile.archetypeName) {
          container.innerHTML = `
            <div style="background:#f5f0ff; border:1px dashed #d8cce4; border-radius:12px;
                        padding:12px 14px; cursor:pointer;"
                 onclick="openPersonalityView('${memberId}', '${containerId}')">
              <div style="font-size:0.8rem; color:var(--arka-accent-hover); font-style:italic;">
                📖 Reading Personality is forming…
              </div>
              <div style="font-size:0.72rem; color:var(--text-faint); margin-top:3px;">
                Keep logging to reveal your type.
              </div>
            </div>`;
          return;
        }

        // ── Parse rarity for the "X of Y" line ────────────────────────────
        let archetypeShareLine = '';
        try {
          const rarity = JSON.parse(profile.raritySummary || '{}');
          if (rarity.archetypeShare) {
            archetypeShareLine = 'Only <b style="color:#f1c40f;">' + rarity.archetypeShare +
                                 '</b> members share this type';
          }
        } catch (e) { /* rarity display is non-critical */ }

        // ── Trait chips (max 4 to keep strip compact) ──────────────────────
        const chipHtml = resolvedVerdicts.slice(0, 4).map(function(v) {
          return `<span class="persona-chip">${v.side}</span>`;
        }).join('');

        // Resolve display name for the compact card header — own profile shows
        // nothing (redundant), other members' cards show their name clearly so
        // the card is distinguishable even when two members share an archetype.
        const cardMemberRec  = membersMap ? membersMap.get(memberId) : null;
        const cardMemberName = (memberId !== currentUser && cardMemberRec)
          ? (cardMemberRec.displayName || cardMemberRec.name || '')
          : '';

        container.innerHTML = `
          <div class="persona-compact-card"
               onclick="openPersonalityView('${memberId}', '${containerId}')">
            <!-- Archetype name + rarity row -->
            <div style="display:flex; align-items:flex-start; gap:10px; margin-bottom:10px;">
              <span style="font-size:2rem; line-height:1;">${profile.archetypeEmoji || '📖'}</span>
              <div style="flex:1;">
                ${cardMemberName
                  ? `<div style="font-size:0.65rem; letter-spacing:1.5px; text-transform:uppercase;
                                 color:#cdbfe0; margin-bottom:3px;">${cardMemberName}</div>`
                  : ''}
                <div style="font-family:'Cinzel',serif; font-weight:700; font-size:1.02rem;
                            color:#fff; letter-spacing:0.3px; line-height:1.2;">
                  ${profile.archetypeName}
                </div>
                ${archetypeShareLine
                  ? `<div style="font-size:0.69rem; color:#cdbfe0; margin-top:2px;">${archetypeShareLine}</div>`
                  : ''}
              </div>
            </div>
            <!-- Trait chips -->
            <div style="display:flex; flex-wrap:wrap; gap:0; margin-bottom:8px;">
              ${chipHtml}
            </div>
            <!-- See full — own row, right-aligned -->
            <div style="text-align:right;">
              <span style="font-size:0.72rem; color:#cdbfe0; letter-spacing:0.3px;">
                See full profile →
              </span>
            </div>
          </div>`;
      }


      /**
       * openPersonalityView()
       *
       * Hides the originating profile view, shows #personalityView, and renders
       * the full personality panel for the given member. The back button restores
       * the originating view.
       *
       * @param {string} memberId       - ARKA_MEMBER_X whose full panel to render
       * @param {string} sourceContainerId - container id that was tapped; used to
       *                                    infer which profile view to return to
       */
      function openPersonalityView(memberId, sourceContainerId) {
        // This entry point uses manual DOM toggling (System B), not navStack (System A).
        _personalityViaNavStack = false;
        // Capture scroll position so closePersonalityView() (System B path) can restore it.
        _personalityFromScrollY = window.scrollY || window.pageYOffset || 0;
        // Determine the return target by inspecting which profile view is currently
        // visible, rather than inferring from sourceContainerId alone. mePersonaContainer
        // lives inside myProfileView, so the container-ID heuristic incorrectly set
        // personaViewReturnTarget to 'meView' when the user tapped the persona card
        // from their profile card. Checking DOM visibility is the ground truth.
        var myProfileViewEl = document.getElementById('myProfileView');
        var isMyProfileVisible = (myProfileViewEl && myProfileViewEl.style.display !== 'none');

        personaViewReturnTarget = (sourceContainerId === 'otherPersonaContainer')
          ? 'otherMemberProfileView'
          : isMyProfileVisible
            ? 'myProfileView'
            : 'meView';

        // Hide the originating profile view.
        const returnEl = document.getElementById(personaViewReturnTarget);
        if (returnEl) returnEl.style.display = 'none';

        // Show the personality view.
        const pvEl = document.getElementById('personalityView');
        if (pvEl) pvEl.style.display = 'block';

        // Scroll to top.
        window.scrollTo(0, 0);

        // Render the full panel.
        renderPersonalityView(memberId);
      }


      /**
       * closePersonalityView()
       *
       * Returns to whichever view opened the personality panel, restoring scroll.
       * Branches on _personalityViaNavStack:
       *
       *   System A (openMyPersonality) — navPop restores the exact origin view
       *   (Me tab, home, or wherever the drawer was open) and its scroll position.
       *   The flag is reset to false so a subsequent System B open does not
       *   accidentally trigger the navPop branch.
       *
       *   System B (openPersonalityView) — manually re-shows the origin DOM element
       *   (myProfileView, otherMemberProfileView, or meView) and restores the scroll
       *   position captured at open time.
       */
      function closePersonalityView() {
        var pvEl = document.getElementById('personalityView');
        if (pvEl) pvEl.style.display = 'none';

        if (_personalityViaNavStack) {
          // System A path — opened via openMyPersonality() which called navPush().
          // Consume that stack entry and restore the real origin view + scroll.
          _personalityViaNavStack = false;
          navPop(function(entry) {
            switchTab(entry.viewName || 'me');
          });
        } else {
          // System B path — opened via openPersonalityView() (manual DOM toggle).
          // Re-show the origin element and restore the scroll captured at open time.
          var returnEl = document.getElementById(personaViewReturnTarget);
          if (returnEl) returnEl.style.display = 'block';
          setTimeout(function() {
            window.scrollTo(0, _personalityFromScrollY);
          }, 0);
        }
      }


      /**
       * renderPersonalityView()
       *
       * Renders the full Reading Personality panel into #personalityViewContent.
       * Layout: Hero archetype → About intro → Spectrum axes (each with axis
       * description + member note + track) → Insights → Blind Spot →
       * How You've Changed (evolution from PERSONAUPDATE activity rows).
       *
       * @param {string} memberId - ARKA_MEMBER_X to render for
       */
      function renderPersonalityView(memberId) {
        const content = document.getElementById('personalityViewContent');
        if (!content) return;

        const profile     = personaProfileMap.get(memberId);
        const isOwnProfile = memberId === currentUser;
        const memberRec   = membersMap ? membersMap.get(memberId) : null;
        const memberName  = memberRec ? (memberRec.displayName || memberRec.name || 'This reader') : 'This reader';

        // ── Forming state ────────────────────────────────────────────────────
        if (!profile || !profile.archetypeName) {
          content.innerHTML = `
            <div style="text-align:center; padding:48px 24px 40px;">
              <div style="font-size:3rem; margin-bottom:14px; opacity:.7;">📖</div>
              <div style="font-family:var(--font-display); font-weight:700; font-size:1.05rem;
                          color:var(--text-strong); margin-bottom:8px;">
                ${isOwnProfile ? 'Your Reading Personality is forming' : memberName + '\'s personality is forming'}
              </div>
              <div style="font-size:0.82rem; color:var(--text-muted); max-width:280px; margin:0 auto;
                          line-height:1.55;">
                The engine needs a little more reading data to name your type.
                Keep logging — your axes will reveal themselves one by one.
              </div>
            </div>`;
          return;
        }

        // ── Parse JSON payloads ────────────────────────────────────────────
        let verdicts = [], insights = [], blindSpot = null, rarity = {};
        try { verdicts  = JSON.parse(profile.axisVerdicts  || '[]'); } catch(e) {}
        try { insights  = JSON.parse(profile.insights      || '[]'); } catch(e) {}
        try { if (profile.blindSpot) blindSpot = JSON.parse(profile.blindSpot); } catch(e) {}
        try { rarity    = JSON.parse(profile.raritySummary || '{}'); } catch(e) {}

        const resolvedVerdicts = verdicts.filter(function(v) { return !v.gated; });
        const formingCount     = verdicts.filter(function(v) { return v.gated; }).length;

        // ── Rarity / social proof ─────────────────────────────────────────
        const rarityLine = rarity.archetypeShare
          ? 'Only <b style="color:#f1c40f;">' + rarity.archetypeShare +
            '</b> members share this type'
          : '';

        // ── Hero trait chips ──────────────────────────────────────────────
        const heroChips = resolvedVerdicts.slice(0, 5).map(function(v) {
          return `<span class="persona-chip">${v.side}</span>`;
        }).join('');

        // ── Axis descriptions — what each axis measures ───────────────────
        const AXIS_META = {
          Rhythm   : { icon: '🕐', desc: 'The time of day you most often read.' },
          Appetite : { icon: '📄', desc: 'How much you typically read in a single sitting.' },
          Cadence  : { icon: '📅', desc: 'Whether your reading is evenly paced or comes in waves.' },
          Era      : { icon: '🗓️', desc: 'The era of books you tend to gravitate toward.' },
          Scale    : { icon: '📏', desc: 'The length of books you choose and finish.' },
          Breadth  : { icon: '🗺️', desc: 'How wide or narrow your reading spans across genres.' }
        };

        // ── Pole label pairs for the slider ───────────────────────────────
        const POLE_LABELS = {
          Rhythm   : ['🌅 Early Bird',       'Night Owl 🌙'],
          Appetite : ['🍪 The Nibbler',      'The Devourer 📚'],
          Cadence  : ['🌊 The Binger',       'The Metronome ⏱️'],
          Era      : ['✨ Trendsetter',      'Time Traveler 🏛️'],
          Scale    : ['📄 Novella Lover',    'Doorstop Lover 📕'],
          Breadth  : ['🎯 Devoted Specialist','Genre Nomad 🌍']
        };

        // ── Axis rows ─────────────────────────────────────────────────────
        const axisRows = verdicts.map(function(v) {
          const meta  = AXIS_META[v.axis]  || { icon: '◉', desc: '' };
          const poles = POLE_LABELS[v.axis] || ['◀', '▶'];

          if (v.gated) {
            const progressMatch = (v.note || '').match(/(\d+) of (\d+)/);
            const pct = progressMatch
              ? Math.round((parseInt(progressMatch[1]) / parseInt(progressMatch[2])) * 100) + '%'
              : '40%';
            return `
              <div style="background:#fcfaff; border:1px dashed #d8cce4; border-radius:14px;
                          padding:14px 16px; margin-bottom:10px;">
                <div style="display:flex; align-items:center; gap:8px; margin-bottom:4px;">
                  <span style="font-size:1rem;">${meta.icon}</span>
                  <span style="font-size:0.64rem; letter-spacing:1.5px; text-transform:uppercase;
                               color:var(--text-faint);">${v.axis}</span>
                  <span style="margin-left:auto; font-size:0.7rem; color:var(--arka-accent);
                               font-style:italic;">Still forming…</span>
                </div>
                <div style="font-size:0.72rem; color:var(--text-faint); margin-bottom:8px;">
                  ${meta.desc}
                </div>
                <div style="height:6px; border-radius:6px; background:#eef0f3; overflow:hidden; margin-bottom:7px;">
                  <div style="height:100%; width:${pct}; border-radius:6px;
                              background:repeating-linear-gradient(45deg,#e8def0,#e8def0 5px,
                              #f0e8f5 5px,#f0e8f5 10px);"></div>
                </div>
                <div style="font-size:0.7rem; color:var(--arka-accent);">${v.note || ''}</div>
              </div>`;
          }

          // Resolved axis
          const isRight    = (v.position || 50) >= 50;
          const leftStyle  = isRight ? 'color:var(--text-faint);' : 'color:var(--text-strong);font-weight:700;';
          const rightStyle = isRight ? 'color:var(--text-strong);font-weight:700;' : 'color:var(--text-faint);';
          const trackClass = isRight ? 'persona-track' : 'persona-track persona-track-left';
          const markerId   = 'psm-' + v.axis.toLowerCase().replace(/[^a-z]/g, '');

          return `
            <div style="background:#fff; border:1px solid #ede8f5; border-radius:14px;
                        padding:14px 16px; margin-bottom:10px;
                        box-shadow:0 1px 4px rgba(83,74,183,.05);">
              <!-- Axis label + verdict -->
              <div style="display:flex; align-items:center; gap:8px; margin-bottom:3px;">
                <span style="font-size:1rem;">${meta.icon}</span>
                <span style="font-size:0.64rem; letter-spacing:1.5px; text-transform:uppercase;
                             color:var(--text-faint);">${v.axis}</span>
                <span style="margin-left:auto; font-family:var(--font-display); font-weight:700;
                             font-size:0.85rem; color:var(--color-challenge);">${v.side}</span>
              </div>
              <!-- Axis description — what it measures -->
              <div style="font-size:0.72rem; color:var(--text-faint); margin-bottom:10px;
                          padding-left:26px;">
                ${meta.desc}
              </div>
              <!-- Pole labels -->
              <div style="display:flex; justify-content:space-between; font-size:0.68rem;
                          margin-bottom:6px;">
                <span style="${leftStyle}">${poles[0]}</span>
                <span style="${rightStyle}">${poles[1]}</span>
              </div>
              <!-- Track + marker -->
              <div class="${trackClass}">
                <span class="persona-marker" id="${markerId}" style="left:50%;"></span>
              </div>
              <!-- Member-specific note -->
              <div style="font-size:0.72rem; color:var(--text-muted); margin-top:10px; line-height:1.5;
                          padding:8px 10px; background:#faf8fc; border-radius:8px;
                          border-left:3px solid #e8def0;">
                ${v.note || ''}
              </div>
            </div>`;
        }).join('');

        // ── Insight cards ──────────────────────────────────────────────────
        const accentColors = { gold: 'var(--color-gamification)', purple: 'var(--color-challenge)', green: 'var(--color-success)' };
        const insightCards = insights.map(function(ins) {
          const borderColor = accentColors[ins.accent] || 'var(--arka-accent)';
          return `
            <div style="display:flex; gap:13px; align-items:flex-start; background:#fff;
                        border:1px solid #ede8f5; border-left:4px solid ${borderColor};
                        border-radius:12px; padding:13px 15px; margin-bottom:9px;
                        box-shadow:0 1px 4px rgba(83,74,183,.04);">
              <span style="font-size:1.4rem; line-height:1.2; flex-shrink:0;">${ins.glyph || '📌'}</span>
              <div>
                <div style="font-family:var(--font-display); font-weight:700; font-size:1.08rem;
                            color:var(--text-strong); line-height:1.2; margin-bottom:4px;">
                  ${ins.stat || ''}
                </div>
                <div style="font-size:0.74rem; color:var(--text-muted); line-height:1.5;">
                  ${ins.caption || ''}
                </div>
              </div>
            </div>`;
        }).join('');

        // ── Blind spot card ────────────────────────────────────────────────
        const blindSpotHtml = (blindSpot && isOwnProfile) ? `
          <div style="background:linear-gradient(135deg,#2c2440,#3a2f52); color:#efe7f7;
                      border-radius:14px; padding:18px 20px; margin-bottom:20px;
                      position:relative; overflow:hidden;">
            <div style="position:absolute;right:14px;top:10px;font-size:2.5rem;
                        color:rgba(255,255,255,.06);">✦</div>
            <div style="font-size:0.62rem; letter-spacing:2.5px; text-transform:uppercase;
                        color:#c9b9dd; margin-bottom:7px;">
              ${blindSpot.eyebrow || 'YOUR BLIND SPOT'}
            </div>
            <div style="font-size:0.92rem; line-height:1.6;">${blindSpot.text || ''}</div>
          </div>` : '';

        // ── Evolution timeline ─────────────────────────────────────────────
        const personaShifts = (globalActivityLogDB || [])
          .filter(function(a) {
            return a.activityTypeID   === 'ARKA_ACTTYP_PERSONAUPDATE' &&
                   a.activityMemberID === memberId;
          })
          .sort(function(a, b) { return new Date(a.activityDate) - new Date(b.activityDate); })
          .slice(-8);

        let evolutionHtml = '';
        if (personaShifts.length > 0) {
          const evoRows = personaShifts.map(function(shift, idx) {
            const isLast   = idx === personaShifts.length - 1;
            const dotStyle = isLast
              ? 'background:#fff;border:3px solid var(--arka-accent);box-shadow:0 0 0 4px #f0e8f5;'
              : 'background:#fff;border:3px solid #e0d8ec;';
            const lineEl = !isLast
              ? `<div style="position:absolute;left:7px;top:20px;bottom:-8px;
                             width:2px;background:#ede8f5;"></div>` : '';
            const desc   = shift.activityDesc || '';
            const axisM  = desc.match(/Axis:\s*([^|]+)\|/);
            const shiftM = desc.match(/\|\s*([^|→]+)\s*→\s*([^|]+)\|/);
            const axisLabel = axisM  ? axisM[1].trim()  : '';
            const fromLabel = shiftM ? shiftM[1].trim() : '';
            const toLabel   = shiftM ? shiftM[2].trim() : '';
            let dateLabel = '';
            try {
              // activityDate format: "dd-MM-yyyy HH:mm:ss +ZZZZ"
              // new Date() mis-parses this, so split manually.
              const parts = (shift.activityDate || '').split(/[\s\-:+]/);
              const d = new Date(Number(parts[2]), Number(parts[1]) - 1, Number(parts[0]));
              if (!isNaN(d)) dateLabel = d.toLocaleDateString('en-GB', { month:'short', year:'numeric' });
            } catch(e) {}
            return `
              <div style="display:flex;align-items:flex-start;gap:10px;
                          position:relative;padding:4px 0 10px;">
                ${lineEl}
                <div style="width:16px;height:16px;border-radius:50%;
                            flex-shrink:0;margin-top:2px;${dotStyle}"></div>
                <div style="min-width:58px;font-size:0.67rem;color:var(--text-faint);padding-top:1px;">
                  ${dateLabel}
                </div>
                <div style="font-size:0.82rem;color:var(--text-strong);line-height:1.4;">
                  ${axisLabel
                    ? `<span style="color:var(--text-faint);font-size:0.72rem;">${axisLabel}:</span>
                       <span style="text-decoration:line-through;color:#c8b8d8;
                                    font-size:0.8rem;margin:0 5px;">${fromLabel}</span>→
                       <span style="font-family:var(--font-display);font-weight:700;
                                    color:var(--color-challenge);margin-left:5px;">${toLabel}</span>`
                    : `<span style="color:var(--text-faint);">${desc}</span>`}
                </div>
              </div>`;
          }).join('');

          evolutionHtml = `
            <div style="margin-bottom:20px;">
              <div style="font-family:var(--font-display);font-weight:600;font-size:1rem;
                          color:var(--text-strong);margin-bottom:3px;">How You've Changed</div>
              <div style="font-size:0.74rem;color:var(--text-faint);margin-bottom:12px;">
                Your personality isn't fixed — it evolves as you read more.
              </div>
              <div style="background:#fff;border:1px solid #ede8f5;border-radius:14px;
                          padding:14px 16px;box-shadow:0 1px 4px rgba(83,74,183,.05);">
                ${evoRows}
              </div>
            </div>`;
        }

        // ── Forming axes note ─────────────────────────────────────────────
        const formingNote = formingCount > 0 ? `
          <div style="background:#faf5ff;border:1px solid #e8def0;border-radius:12px;
                      padding:12px 15px;margin-bottom:20px;display:flex;gap:10px;
                      align-items:flex-start;">
            <span style="font-size:1.1rem;flex-shrink:0;">🔓</span>
            <div style="font-size:0.76rem;color:var(--arka-accent-hover);line-height:1.5;">
              <b style="color:var(--color-challenge);">${formingCount} ${formingCount === 1 ? 'axis is' : 'axes are'} still forming.</b>
              Keep logging pages to reveal ${formingCount === 1 ? 'it' : 'them'} — each one adds
              a new dimension to your personality.
            </div>
          </div>` : '';

        // ── Help link ─────────────────────────────────────────────────────
        const helpLink = `
          <div style="text-align:center;margin-bottom:24px;">
            <span onclick="openHelpArticle('help-reading-personality')"
                  style="font-size:0.74rem;color:var(--arka-accent);cursor:pointer;
                         display:inline-flex;align-items:center;gap:5px;
                         padding:6px 14px;border-radius:20px;
                         background:#f5f0ff;border:1px solid #e8def0;">
              <i class="fa-solid fa-circle-question" style="font-size:0.72rem;"></i>
              How is this computed? See the full guide
            </span>
          </div>`;

        // ── Assemble full panel ────────────────────────────────────────────
        content.innerHTML = `
          <!-- ── Hero ── -->
          <div style="position:relative;overflow:hidden;border-radius:18px;color:#fff;
                      text-align:center;padding:38px 22px 32px;margin-bottom:20px;
                      background:radial-gradient(120% 80% at 50% -10%,
                        rgba(169,132,186,.55) 0%,rgba(83,74,183,0) 60%),
                        linear-gradient(160deg,#3a3050 0%,#241d36 55%,#1a1626 100%);">
            <div style="position:relative;z-index:1;font-size:0.62rem;letter-spacing:3px;
                        text-transform:uppercase;color:#cdbfe0;margin-bottom:12px;">
              ${isOwnProfile ? 'YOUR READING TYPE' : (memberName.toUpperCase() + '\'S READING TYPE')}
            </div>
            <div style="position:relative;z-index:1;font-size:2.4rem;line-height:1;
                        margin-bottom:9px;filter:drop-shadow(0 4px 12px rgba(0,0,0,.4));">
              ${profile.archetypeEmoji || '📖'}
            </div>
            <div style="position:relative;z-index:1;font-family:var(--font-display);font-weight:700;
                        font-size:1.75rem;letter-spacing:.4px;margin:0 0 10px;
                        background:linear-gradient(90deg,#fff,#e3d4f0);
                        -webkit-background-clip:text;background-clip:text;color:transparent;">
              ${profile.archetypeName}
            </div>
            ${profile.archetypeTagline
              ? `<div style="position:relative;z-index:1;font-size:0.87rem;color:#d9cfe8;
                             max-width:310px;margin:0 auto 16px;font-style:italic;
                             line-height:1.5;">"${profile.archetypeTagline}"</div>`
              : ''}
            <div style="position:relative;z-index:1;display:flex;flex-wrap:wrap;
                        justify-content:center;gap:6px;margin-bottom:${rarityLine ? '12px' : '0'};">
              ${heroChips}
            </div>
            ${rarityLine
              ? `<div style="position:relative;z-index:1;font-size:0.72rem;color:#cdbfe0;
                             margin-top:2px;">${rarityLine}</div>`
              : ''}
          </div>

          <!-- ── About intro ── -->
          <div style="background:#f9f5ff;border-radius:12px;padding:13px 16px;
                      margin-bottom:20px;border-left:4px solid var(--arka-accent);">
            <div style="font-size:0.78rem;color:var(--color-challenge);font-weight:600;margin-bottom:4px;">
              About this profile
            </div>
            <div style="font-size:0.76rem;color:var(--text-muted);line-height:1.6;">
              Reading Personality is computed nightly from ${isOwnProfile ? 'your' : memberName + '\'s'}
              page logs and finished books — no surveys, no self-reporting. Each axis reflects a
              genuine pattern in the data. Axes marked "forming" need a little more reading history
              before they can resolve.
            </div>
          </div>

          <!-- ── Spectrum ── -->
          ${verdicts.length ? `
            <div style="margin-bottom:6px;">
              <div style="font-family:var(--font-display);font-weight:600;font-size:1rem;
                          color:var(--text-strong);margin-bottom:3px;">Reading Spectrum</div>
              <div style="font-size:0.74rem;color:var(--text-faint);margin-bottom:14px;">
                Where ${isOwnProfile ? 'you sit' : memberName + ' sits'} on each axis.
                The highlighted side is the dominant trait.
              </div>
              ${axisRows}
            </div>` : ''}

          <!-- ── Forming axes note ── -->
          ${formingNote}

          <!-- ── Insights ── -->
          ${insights.length ? `
            <div style="margin-bottom:20px;">
              <div style="font-family:var(--font-display);font-weight:600;font-size:1rem;
                          color:var(--text-strong);margin-bottom:3px;">
                ${isOwnProfile ? 'Things You Didn\'t Know' : 'Reading Snapshot'}
              </div>
              <div style="font-size:0.74rem;color:var(--text-faint);margin-bottom:12px;">
                ${isOwnProfile
                  ? 'Patterns hiding in your own reading history.'
                  : 'Standout facts from ' + memberName + '\'s reading history.'}
              </div>
              ${insightCards}
            </div>` : ''}

          <!-- ── Blind spot ── -->
          ${blindSpotHtml}

          <!-- ── Evolution ── -->
          ${evolutionHtml}

          <!-- ── Help link ── -->
          ${helpLink}

          <!-- ── Footer ── -->
          <div style="font-size:0.64rem;color:#d0c8dc;text-align:center;padding-bottom:24px;">
            Last updated ${profile.computedDate || '—'} · ${profile.engineVersion || ''}
          </div>`;

        // ── Animate sliders into position after paint ──────────────────────
        setTimeout(function() {
          verdicts.forEach(function(v) {
            if (v.gated) return;
            const markerId = 'psm-' + v.axis.toLowerCase().replace(/[^a-z]/g, '');
            const marker   = document.getElementById(markerId);
            if (marker) marker.style.left = (v.position || 50) + '%';
          });
        }, 150);
      }

      /**
       * initPersonaVisibilityToggle_()
       *
       * Seeds the Reading Personality privacy toggle in Edit Profile from the
       * current in-memory personaProfileMap entry for the logged-in user.
       * Defaults to ON (visible) if no row exists yet so new members don't
       * accidentally start hidden.
       * @private
       */
      function initPersonaVisibilityToggle_() {
        const profile    = personaProfileMap.get(currentUser);
        const isVisible  = !profile || profile.status !== 'Suppressed';
        const toggleEl   = document.getElementById('personaVisibilityToggle');
        const helpTextEl = document.getElementById('personaVisibilityHelp');
        if (toggleEl) toggleEl.checked = isVisible;
        if (helpTextEl) {
          helpTextEl.textContent = isVisible
            ? 'Visible — other members can see your Reading Type on your profile.'
            : 'Hidden — only you can see your Reading Personality.';
        }
      }

      /**
       * handlePersonaVisibilityToggle()
       *
       * Fired immediately when the user flips the privacy toggle in Edit Profile.
       * Updates PersonaProfileDB Col L (Active / Suppressed) via the server,
       * then syncs the in-memory personaProfileMap and re-renders the compact
       * strip so the change is reflected without a page reload.
       *
       * @param {boolean} isVisible - true = Active (show), false = Suppressed (hide)
       */
      function handlePersonaVisibilityToggle(isVisible) {
        const helpTextEl = document.getElementById('personaVisibilityHelp');
        if (helpTextEl) helpTextEl.textContent = 'Saving…';

        google.script.run
          .withSuccessHandler(function(res) {
            if (res && res.status === 'success') {
              // Sync in-memory map so strip + full panel instantly reflect the change.
              const profile = personaProfileMap.get(currentUser);
              if (profile) {
                profile.status = isVisible ? 'Active' : 'Suppressed';
                personaProfileMap.set(currentUser, profile);
              }
              if (helpTextEl) {
                helpTextEl.textContent = isVisible
                  ? 'Visible — other members can see your Reading Type on your profile.'
                  : 'Hidden — only you can see your Reading Personality.';
              }
              // Re-render own strip (own profile always shows regardless of status).
              renderPersonaStrip(currentUser, 'mePersonaContainer');
              // Surface persona archetype on the Me tab identity card (Audit Critical Path #1).
              renderMeTabPersonaInset();
              showToast({ type: 'info', icon: 'fa-solid fa-eye' + (isVisible ? '' : '-slash'), title: isVisible ? 'Reading Personality is now visible.' : 'Reading Personality is now hidden.' });
            } else {
              // Roll back the toggle visually on failure.
              const toggleEl = document.getElementById('personaVisibilityToggle');
              if (toggleEl) toggleEl.checked = !isVisible;
              if (helpTextEl) helpTextEl.textContent = 'Could not save — please try again.';
              showToast({ type: 'error', title: 'Could not update visibility. Please try again.' });
            }
          })
          .withFailureHandler(function(err) {
            const toggleEl = document.getElementById('personaVisibilityToggle');
            if (toggleEl) toggleEl.checked = !isVisible;
            if (helpTextEl) helpTextEl.textContent = 'Could not save — please try again.';
            showToast({ type: 'error', title: 'Could not update visibility. Please try again.' });
          })
          .updatePersonaVisibility(isVisible);
      }

      /**
       * initEmailOptOutToggle_()
       *
       * Seeds the email notification toggle in Edit Profile from the current
       * member's emailOptOut value in globalMembersDB (Wave 1 data).
       * Defaults to ON (wants emails) when the field is absent — preserves
       * opt-in for all members who pre-date the Col U addition.
       * @private
       */
      function initEmailOptOutToggle_() {
        const member     = globalMembersDB.find(function(m) { return m.id === currentUser; });
        // emailOptOut=true → member doesn't want emails → toggle should be OFF
        // emailOptOut=false/undefined → member wants emails → toggle should be ON
        const wantsEmails = !member || !member.emailOptOut;
        const toggleEl    = document.getElementById('emailOptOutToggle');
        const helpTextEl  = document.getElementById('emailOptOutHelp');
        if (toggleEl) toggleEl.checked = wantsEmails;
        if (helpTextEl) {
          helpTextEl.textContent = wantsEmails
            ? 'On — we\'ll send reading nudges and streak reminders.'
            : 'Off — no emails from Arka. You can re-enable anytime.';
        }
      }

      /**
       * handleEmailOptOutToggle()
       *
       * Fired immediately when the member flips the email notifications toggle.
       * Writes the preference to MemberDB Col U via updateEmailOptOut() and
       * syncs the in-memory globalMembersDB so the toggle state is consistent
       * if the member cancels and re-opens Edit Profile in the same session.
       * Rolls the toggle back visually on failure.
       *
       * @param {boolean} wantsEmails - true = toggle ON (wants emails)
       *                               false = toggle OFF (opted out)
       */
      function handleEmailOptOutToggle(wantsEmails) {
        const helpTextEl = document.getElementById('emailOptOutHelp');
        if (helpTextEl) helpTextEl.textContent = 'Saving…';

        google.script.run
          .withSuccessHandler(function(res) {
            if (res && res.status === 'success') {
              // Sync in-memory globalMembersDB so initEmailOptOutToggle_() is
              // accurate if the member cancels and re-opens Edit Profile.
              const member = globalMembersDB.find(function(m) { return m.id === currentUser; });
              if (member) member.emailOptOut = res.emailOptOut;

              if (helpTextEl) {
                helpTextEl.textContent = wantsEmails
                  ? 'On — we\'ll send reading nudges and streak reminders.'
                  : 'Off — no emails from Arka. You can re-enable anytime.';
              }
              showToast({
                type : wantsEmails ? 'success' : 'info',
                icon : 'fa-solid fa-bell' + (wantsEmails ? '' : '-slash'),
                title: wantsEmails
                  ? 'Email notifications enabled.'
                  : 'Email notifications turned off.'
              });
            } else {
              // Roll back the toggle and show error
              const toggleEl = document.getElementById('emailOptOutToggle');
              if (toggleEl) toggleEl.checked = !wantsEmails;
              if (helpTextEl) helpTextEl.textContent = 'Could not save — please try again.';
              showToast({ type: 'error', title: 'Could not update email preference. Please try again.' });
            }
          })
          .withFailureHandler(function(err) {
            const toggleEl = document.getElementById('emailOptOutToggle');
            if (toggleEl) toggleEl.checked = !wantsEmails;
            if (helpTextEl) helpTextEl.textContent = 'Could not save — please try again.';
            showToast({ type: 'error', title: 'Could not update email preference. Please try again.' });
          })
          .updateEmailOptOut(wantsEmails);
      }

      
      
